window.ASBAB_NUZUL_CACHE["48"] = {"asbab_nuzul":{"1":[{"ar":"عَنْ عَبْدِ اللهِ بْنِ مَسْعُودٍ رضي الله عنه قَالَ: لَمَّا انْصَرَفْنَا مِنْ غَزْوَةِ الْحُدَيْبِيَةِ، قَالَ رَسُولُ اللهِ ﷺ: « مَنْ يَحْرُسُنَا اللَّيْلَةَ »؟ قَالَ عَبْدُ اللهِ: فَقُلْتُ: أَنَا. حَتَّى عَادَ مِرَاراً، قُلْتُ: أَنَا يَا رَسُولَ اللهِ. قَالَ: « فَأَنْتَ إِذَاً »، قَالَ: فَحَرَسْتُهُمْ، حَتَّى إِذَا كَانَ وَجْهُ الصُّبْحِ، أَدْرَكَنِي قَوْلُ رَسُولِ اللهِ ﷺ: « إِنَّكَ تَنَامُ »، فَنِمْتُ، فَمَا أَيْقَظَنَا إِلَّا حَرُّ الشَّمْسِ فِي ظُهُورِنَا، فَقَامَ رَسُولُ اللهِ ﷺ، وَصَنَعَ كَمَا كَانَ يَصْنَعُ مِنْ الْوُضُوءِ، وَرَكْعَتَيْ الْفَجْرِ ثُمَّ صَلَّى بِنَا الصُّبْحَ، فَلَمَّا انْصَرَفَ، قَالَ: « إِنَّ اللهَ عز و جل، لَوْ أَرَادَ أَنْ لَا تَنَامُوا لَمْ تَنَامُوا، وَلَكِنْ أَرَادَ أَنْ تَكُونُوا لِمَنْ بَعْدَكُمْ، فَهَكَذَا لِمَنْ نَامَ أَوْ نَسِيَ ».\n\nقَالَ: ثُمَّ إِنَّ نَاقَةَ رَسُولِ اللهِ ﷺ وَإِبِلَ الْقَوْمِ تَفَرَّقَتْ، فَخَرَجَ النَّاسُ فِي طَلَبِهَا، فَجَاءُوا بِإِبْلِهِمْ، إِلَّا نَاقَةَ رَسُولِ اللهِ ﷺ، فَقَالَ عَبْدُ اللهِ: قَالَ لِي رَسُولُ اللهِ ﷺ: « خُذْ هَهُنَا »، فَأَخَذْتُ حَيْثُ قَالَ لِي، فَوَجَدْتُ زِمَامَهَا قَدْ الْتَوَى عَلَى شَجَرَةٍ، مَا كَانَتْ لِتَحُلَّهَا إِلَّا يَدٌ، قَالَ: فَجِئْتُ بِهَا النَّبِيَّ ﷺ، فَقُلْتُ: يَا رَسُولَ اللهِ، وَالَّذِي بَعَثَكَ بِالْحَقِّ نَبِيًّا لَقَدْ وَجَدْتُ زِمَامَهَا مُلْتَوِياً عَلَى شَجَرَةٍ مَا كَانَتْ لِتَحُلَّهَا إِلَّا يَدٌ، قَالَ: وَنَزَلَتْ عَلَى رَسُولِ اللهِ ﷺ، سُورَةُ الْفَتْحِ: { إِنَّا فَتَحْنَا لَكَ فَتْحًا مُّبِينًا ﴿١﴾ }. واللفظ لأحمد.","id":""}],"24":[{"ar":"عَنْ أَنَسٍ رضي الله عنه أَنَّ ثَمَانِينَ رَجُلًا مِنْ أَهْلِ مَكَّةَ، هَبَطُوا عَلَى رَسُولِ اللهِ ﷺ وَأَصْحَابِهِ مِنْ جَبَلِ التَّنْعِيمِ، عِنْدَ صَلَاةِ الْفَجْرِ، فَأَخَذَهُمْ رَسُولُ اللهِ ﷺ سِلْماً، فَعَفَا عَنْهُمْ، وَنَزَلَ الْقُرْآنُ: { وَهُوَ ٱلَّذِى كَفَّ أَيْدِيَهُمْ عَنكُمْ وَأَيْدِيَكُمْ عَنْهُم بِبَطْنِ مَكَّةَ مِنۢ بَعْدِ أَنْ أَظْفَرَكُمْ عَلَيْهِمْ ۚ }. واللفظ لأحمد.","id":""}]},"mapping_ayat":{"48:1":[{"p":"Bukhari","n":3681,"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ عُمَرُ يُدْخِلُنِي مَعَ أَشْيَاخِ بَدْرٍ فَقَالَ بَعْضُهُمْ لِمَ تُدْخِلُ هَذَا الْفَتَى مَعَنَا وَلَنَا أَبْنَاءٌ مِثْلُهُ فَقَالَ إِنَّهُ مِمَّنْ قَدْ عَلِمْتُمْ قَالَ فَدَعَاهُمْ ذَاتَ يَوْمٍ وَدَعَانِي مَعَهُمْ قَالَ وَمَا رُئِيتُهُ دَعَانِي يَوْمَئِذٍ إِلَّا لِيُرِيَهُمْ مِنِّي فَقَالَ مَا تَقُولُونَ فِي{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ وَرَأَيْتَ النَّاسَ يَدْخُلُونَ فِي دِينِ اللَّهِ أَفْوَاجًا }حَتَّى خَتَمَ السُّورَةَ فَقَالَ بَعْضُهُمْ أُمِرْنَا أَنْ نَحْمَدَ اللَّهَ وَنَسْتَغْفِرَهُ إِذَا نُصِرْنَا وَفُتِحَ عَلَيْنَا وَقَالَ بَعْضُهُمْ لَا نَدْرِي أَوْ لَمْ يَقُلْ بَعْضُهُمْ شَيْئًا فَقَالَ لِي يَا ابْنَ عَبَّاسٍ أَكَذَاكَ تَقُولُ قُلْتُ لَا قَالَ فَمَا تَقُولُ قُلْتُ هُوَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ اللَّهُ لَهُ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَتْحُ مَكَّةَ فَذَاكَ عَلَامَةُ أَجَلِكَ{ فَسَبِّحْ بِحَمْدِ رَبِّكَ وَاسْتَغْفِرْهُ إِنَّهُ كَانَ تَوَّابًا }قَالَ عُمَرُ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","trj":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Said bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma, Umar Pernah mengajakku dalam sebuah majlis orang dewasa, sehingga sebagian sahabat bertanya \"Mengapa si anak kecil ini kau ikut sertakan, kami juga punya anak-anak kecil seperti dia?\" Umar menjawab; \"Kalian maklum, anak ini punya \"kualitas\" tersendiri.\" Kata Ibnu Umar, maka suatu hari Umar mengundang mereka dan mengajakku bersama mereka. Seingatku, Umar tidak mengajakku saat itu selain untuk mempertontonkan kepada mereka kualitas keilmuanku. Lantas Umar bertanyal; \"Bagaimana komentar kalian tentang ayat \"Seandainya pertolongan Allah dan kemenangan datang (1) dan kau lihat manusia masuk agama Allah dengan berbondong-bondong (2) -hingga ahkir surat (QS. Alfath 1-3). Sebagian sahabat berkomentar; \"Tentang ayat ini, setahu kami, kita diperintahkan agar memuji Allah dan meminta ampunan kepada-Nya, tepatnya ketika kita diberi pertolongan dan diberi kemenangan.\" Sebagian lagi berkomentar; \"kalau kami nggak tahu.\" Atau bahkan tidak berkomentar sama sekali. Lantas Umar bertanya kepadaku; \"Wahai Ibnu Abbas, beginikah kamu berkomentar mengenai ayat tadi?\"TIDAK\" Jawabku.\"Lalu komentarmu? Tanya Umar. Ibnu Abbas menjawab; \"Surat tersebut adalah pertanda wafat Rasulullah shallallahu 'alaihi wasallam sudah dekat, Allah memberitahunya dengan ayatnya: \"Jika telah datang pertolongan Allah dan kemenangan', itu berarti penaklukan Makkah dan itulah tanda ajalmu (Muhammad), karenanya \"Bertasbihlah dengan memuji Tuhanmu dan mohonlah ampunan, sesungguhnya Dia Maha Menerima taubat. Kata Umar, \"Aku tidak tahu penafsiran ayat tersebut selain seperti yang kamu (Ibnu Abbas) ketahui.\""},{"p":"Bukhari","n":3790,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يُدْنِي ابْنَ عَبَّاسٍ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ إِنَّ لَنَا أَبْنَاءً مِثْلَهُ فَقَالَ إِنَّهُ مِنْ حَيْثُ تَعْلَمُ فَسَأَلَ عُمَرُ ابْنَ عَبَّاسٍ عَنْ هَذِهِ الْآيَةِ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَقَالَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ إِيَّاهُ فَقَالَ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","trj":"Telah menceritakan kepada kami [Muhammad bin Ar'arah] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; Umar bin Khaththab radliallahu 'anhu pernah mendekatiku. Maka Abdurrahman bin Auf berkata kepadanya; Sesungguhnya kita juga punya anak-anak sepertinya. Umar menjawab; kamu sendirikan tahu siapakah Ibnu Abbas. Lalu Umar bertanya kepada Ibnu Abbas tentang ayat; \"Apabila pertolongan dan kemenangan Allah telah datang.(QS. Alfath 1-5) \" Ibnu Abbas menjawab; \"Ajal Rasulullah shallallahu 'alaihi wasallam telah memberitahukan kepada beliau bahwa dia telah datang kepadanya.\" Umar berkata; 'Aku tidak tahu tentang ayat itu kecuali apa yang kamu ketahui.'"},{"p":"Darimi","n":45,"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا يَزِيدُ بْنُ أَبِي حَكِيمٍ حَدَّثَنِي الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ إِنَّ اللَّهَ فَضَّلَ مُحَمَّدًا عَلَى الْأَنْبِيَاءِ وَعَلَى أَهْلِ السَّمَاءِ فَقَالُوا يَا ابْنَ عَبَّاسٍ بِمَ فَضَّلَهُ عَلَى أَهْلِ السَّمَاءِ قَالَ إِنَّ اللَّهَ قَالَ لِأَهْلِ السَّمَاءِ { وَمَنْ يَقُلْ مِنْهُمْ إِنِّي إِلَهٌ مِنْ دُونِهِ فَذَلِكَ نَجْزِيهِ جَهَنَّمَ كَذَلِكَ نَجْزِي الظَّالِمِينَ } الْآيَةَ وَقَالَ اللَّهُ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا لِيَغْفِرَ لَكَ اللَّهُ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ } قَالُوا فَمَا فَضْلُهُ عَلَى الْأَنْبِيَاءِ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ { وَمَا أَرْسَلْنَا مِنْ رَسُولٍ إِلَّا بِلِسَانِ قَوْمِهِ لِيُبَيِّنَ لَهُمْ } الْآيَةَ وَقَالَ اللَّهُ عَزَّ وَجَلَّ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { وَمَا أَرْسَلْنَاكَ إِلَّا كَافَّةً لِلنَّاسِ } فَأَرْسَلَهُ إِلَى الْجِنِّ وَالْإِنْسِ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Yazid bin Abu Hakim] telah menceritakan kepadaku [Al Hakam bin Abaan] dari ['Ikrimah] dari [Ibnu Abbas] Radliyallahu'anhu ia berkata; \" Sesungguhnya Allah Subhanahu wa Ta'ala memberikan keutamaan kepada Nabi Muhammad shallallahu 'alaihi wasallam atas Nabi-nabi yang lainnya dan atas penghuni langit. \" lalu mereka bertanya: \"Wahai Ibnu Abbas, keutamaan apa yang diberikan kepada beliau atas penghuni langit?\" Ibnu Abbas menjawab; \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman kepada penghuni langit: Dari Ibnu Abbas berkata: WAMAN YAQUL MINHUM INNII ILAAHUN MIN DUNIHI FADZALIJKA NAJZIIHI JAHANNAMA KADZALIKA NAJZII AZHA-ZHALIMIIN Dan barang siapa diantara mereka mengatakan, sesungguhnya aku adalah tuhan selain dari pada Allah Subhanahu wa Ta'ala, maka orang itu kami beri balasan dengan jahannam, dengan demikian kami memberikan pembalasan kepada orang-orang zhalim. (Qs. Al Anbiya` /21: 29) Dan Allah Subhanahu wa Ta'ala terhadap dosamu yang telah lalu dan yang akan datang serta menyempurnakan nikmat-Nya atasmu dan memimpin kamu ke jalan yang lurus. ` (Qs. Al Fath /48: 1. 2) Lalu mereka bertanya, \" Apa keutamaan beliau atas semua Nabi-nabi?\" bin Abbas menjawab, \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman, `Kami tidak mengutus seorang Rasul pun, melainkan dengan bahasa kaumnya, supaya ia dapat memberi penjelasan dengan terang kepada mereka. ` (Qs. Ibraahiim /14: 4) dan Allah Subhanahu wa Ta'ala berfirman untuk Nabi Muhammad shallallahu 'alaihi wasallam, ` dan Kami tidak mengutus kamu melainkan kepada umat manusia seluruhnya Sebagai pembawa berita gembira dan pemberi peringatan. ` (Qs. As Saba` 34: 28), maka beliau telah diutus kepada bangsa jin dan manusia. "},{"p":"Malik","n":424,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسِيرُ فِي بَعْضِ أَسْفَارِهِ وَعُمَرُ بْنُ الْخَطَّابِيَسِيرُ مَعَهُ لَيْلًا فَسَأَلَهُ عُمَرُ عَنْ شَيْءٍ فَلَمْ يُجِبْهُ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ فَقَالَ عُمَرُ ثَكِلَتْكَ أُمُّكَ عُمَرُ نَزَرْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مَرَّاتٍ كُلُّ ذَلِكَ لَا يُجِيبُكَ قَالَ عُمَرُ فَحَرَّكْتُ بَعِيرِي حَتَّى إِذَا كُنْتُ أَمَامَ النَّاسِ وَخَشِيتُ أَنْ يُنْزَلَ فِيَّ قُرْآنٌ فَمَا نَشِبْتُ أَنْ سَمِعْتُ صَارِخًا يَصْرُخُ بِي قَالَ فَقُلْتُ لَقَدْ خَشِيتُ أَنْ يَكُونَ نَزَلَ فِيَّ قُرْآنٌ قَالَ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْتُ عَلَيْهِ فَقَالَ لَقَدْ أُنْزِلَتْ عَلَيَّ هَذِهِ اللَّيْلَةَ سُورَةٌ لَهِيَ أَحَبُّ إِلَيَّ مِمَّا طَلَعَتْ عَلَيْهِ الشَّمْسُ ثُمَّ قَرَأَ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا","trj":"Telah menceritakan kepadaku dari Malik dari [Zaid bin Aslam] dari [Bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam berada dalam salah satu perjalanannya, dan [Umar bin Khattab] bersama beliau pada malam hari itu. Umar bertanya kepada beliau tentang suatu hal, namun beliau tidak menjawabnya. Dia bertanya lagi, namun beliau tetap tidak menjawab. Dia bertanya lagi, namun beliau tetap tidak menjawab. 'Umar pun berkata, \"Celaka engkau wahai Umar! Engkau telah memaksa Rasulullah shallallahu 'alaihi wasallam tiga kali, namun semuanya itu tidak ada yang dijawabnya.\" 'Umar berkata, \"Aku gerakkan untaku, sampai ketika aku di hadapan orang-orang, aku khawatir jika turun padaku Al qur'an. Dan tidak berapa lama, aku mendengar orang yang berteriak ke arahku.\" 'Umar berkata, \"Aku berkata, \"Aku khawatir jika ada ayat yang turun kepadaku.\" 'Umar berkata lagi, \"Aku lalu mendatangi Rasulullah shallallahu 'alaihi wasallam, dan mengucapkan salam kepadanya. Beliau bersabda: 'Telah turun padaku tadi malam satu surat, yang lebih aku cintai daripada terbitnya matahari.\" Kemudian beliau membaca: \"'INNAA FATAHNAA LAKA FATHAN MUBIINA (Sesungguhnya Kami telah memberikan kepada kamu kemenangan yang nyata.\" (Qs. Al Fath: 1) ."},{"p":"Muslim","n":3108,"ar":"و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْ قَالَلَمَّا نَزَلَتْ{ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا لِيَغْفِرَ لَكَ اللَّهُ إِلَى قَوْلِهِ فَوْزًا عَظِيمًا }مَرْجِعَهُ مِنْ الْحُدَيْبِيَةِ وَهُمْ يُخَالِطُهُمْ الْحُزْنُ وَالْكَآبَةُ وَقَدْ نَحَرَ الْهَدْيَ بِالْحُدَيْبِيَةِ فَقَالَ لَقَدْ أُنْزِلَتْ عَلَيَّ آيَةٌ هِيَ أَحَبُّ إِلَيَّ مِنْ الدُّنْيَا جَمِيعًاو حَدَّثَنَا عَاصِمُ بْنُ النَّض��رِ التَّيْمِيُّ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا هَمَّامٌ ح و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ جَمِيعًا عَنْ قَتَادَةَ عَنْ أَنَسٍ نَحْوَ حَدِيثِ ابْنِ أَبِي عَرُوبَةَ","trj":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahzhami] telah menceritakan kepada kami [Khalid bin Al Harits] berkata, telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] bahwa [Anas bin Malik] telah menceritakan kepada mereka, dia berkata, \"Ketika turun ayat: '(Sesungguhnya kami telah memberikan kepadamu kemenangan yang nyata, supaya Allah memberikan ampunan kepadamu terhadap dosamu -hingga firmanNya- dengan pertolongan yang kuat (banyak).' (Qs. Al Fath: 1-3), ketika itu mereka baru pulang dari Hudaibiyyah dengan diliputi perasaan jengkel dan kesal, padahal mereka telah menyembelih binatang kurban. Maka beliau bersabda: \"Sungguh telah turun kepadaku suatu ayat yang lebih aku cintai daripada dunia dan isinya.\" Dan telah menceritakan kepada kami ['Ashim bin An Nadlr At Taimi] telah menceritakan kepada kami [Mu'tamir] dia berkata; aku mendengar [ayahku] telah menceritakan kepada kami [Qatadah] dia berkata; aku pernah mendengar [Anas bin Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Hammam] (dalam jalur lain disebutkan) telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban] semuanya dari [Qatadah] dari [Anas] sebagaimana hadits Ibnu Abu 'Arubah.\""}],"48:2":[{"p":"Bukhari","n":3681,"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ عُمَرُ يُدْخِلُنِي مَعَ أَشْيَاخِ بَدْرٍ فَقَالَ بَعْضُهُمْ لِمَ تُدْخِلُ هَذَا الْفَتَى مَعَنَا وَلَنَا أَبْنَاءٌ مِثْلُهُ فَقَالَ إِنَّهُ مِمَّنْ قَدْ عَلِمْتُمْ قَالَ فَدَعَاهُمْ ذَاتَ يَوْمٍ وَدَعَانِي مَعَهُمْ قَالَ وَمَا رُئِيتُهُ دَعَانِي يَوْمَئِذٍ إِلَّا لِيُرِيَهُمْ مِنِّي فَقَالَ مَا تَقُولُونَ فِي{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ وَرَأَيْتَ النَّاسَ يَدْخُلُونَ فِي دِينِ اللَّهِ أَفْوَاجًا }حَتَّى خَتَمَ السُّورَةَ فَقَالَ بَعْضُهُمْ أُمِرْنَا أَنْ نَحْمَدَ اللَّهَ وَنَسْتَغْفِرَهُ إِذَا نُصِرْنَا وَفُتِحَ عَلَيْنَا وَقَالَ بَعْضُهُمْ لَا نَدْرِي أَوْ لَمْ يَقُلْ بَعْضُهُمْ شَيْئًا فَقَالَ لِي يَا ابْنَ عَبَّاسٍ أَكَذَاكَ تَقُولُ قُلْتُ لَا قَالَ فَمَا تَقُولُ قُلْتُ هُوَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ اللَّهُ لَهُ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَتْحُ مَكَّةَ فَذَاكَ عَلَامَةُ أَجَلِكَ{ فَسَبِّحْ بِحَمْدِ رَبِّكَ وَاسْتَغْفِرْهُ إِنَّهُ كَانَ تَوَّابًا }قَالَ عُمَرُ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","trj":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Said bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma, Umar Pernah mengajakku dalam sebuah majlis orang dewasa, sehingga sebagian sahabat bertanya \"Mengapa si anak kecil ini kau ikut sertakan, kami juga punya anak-anak kecil seperti dia?\" Umar menjawab; \"Kalian maklum, anak ini punya \"kualitas\" tersendiri.\" Kata Ibnu Umar, maka suatu hari Umar mengundang mereka dan mengajakku bersama mereka. Seingatku, Umar tidak mengajakku saat itu selain untuk mempertontonkan kepada mereka kualitas keilmuanku. Lantas Umar bertanyal; \"Bagaimana komentar kalian tentang ayat \"Seandainya pertolongan Allah dan kemenangan datang (1) dan kau lihat manusia masuk agama Allah dengan berbondong-bondong (2) -hingga ahkir surat (QS. Alfath 1-3). Sebagian sahabat berkomentar; \"Tentang ayat ini, setahu kami, kita diperintahkan agar memuji Allah dan meminta ampunan kepada-Nya, tepatnya ketika kita diberi pertolongan dan diberi kemenangan.\" Sebagian lagi berkomentar; \"kalau kami nggak tahu.\" Atau bahkan tidak berkomentar sama sekali. Lantas Umar bertanya kepadaku; \"Wahai Ibnu Abbas, beginikah kamu berkomentar mengenai ayat tadi?\"TIDAK\" Jawabku.\"Lalu komentarmu? Tanya Umar. Ibnu Abbas menjawab; \"Surat tersebut adalah pertanda wafat Rasulullah shallallahu 'alaihi wasallam sudah dekat, Allah memberitahunya dengan ayatnya: \"Jika telah datang pertolongan Allah dan kemenangan', itu berarti penaklukan Makkah dan itulah tanda ajalmu (Muhammad), karenanya \"Bertasbihlah dengan memuji Tuhanmu dan mohonlah ampunan, sesungguhnya Dia Maha Menerima taubat. Kata Umar, \"Aku tidak tahu penafsiran ayat tersebut selain seperti yang kamu (Ibnu Abbas) ketahui.\""},{"p":"Bukhari","n":3790,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يُدْنِي ابْنَ عَبَّاسٍ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ إِنَّ لَنَا أَبْنَاءً مِثْلَهُ فَقَالَ إِنَّهُ مِنْ حَيْثُ تَعْلَمُ فَسَأَلَ عُمَرُ ابْنَ عَبَّاسٍ عَنْ هَذِهِ الْآيَةِ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَقَالَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ إِيَّاهُ فَقَالَ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","trj":"Telah menceritakan kepada kami [Muhammad bin Ar'arah] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; Umar bin Khaththab radliallahu 'anhu pernah mendekatiku. Maka Abdurrahman bin Auf berkata kepadanya; Sesungguhnya kita juga punya anak-anak sepertinya. Umar menjawab; kamu sendirikan tahu siapakah Ibnu Abbas. Lalu Umar bertanya kepada Ibnu Abbas tentang ayat; \"Apabila pertolongan dan kemenangan Allah telah datang.(QS. Alfath 1-5) \" Ibnu Abbas menjawab; \"Ajal Rasulullah shallallahu 'alaihi wasallam telah memberitahukan kepada beliau bahwa dia telah datang kepadanya.\" Umar berkata; 'Aku tidak tahu tentang ayat itu kecuali apa yang kamu ketahui.'"},{"p":"Muslim","n":3108,"ar":"و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْ قَالَلَمَّا نَزَلَتْ{ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا لِيَغْفِرَ لَكَ اللَّهُ إِلَى قَوْلِهِ فَوْزًا عَظِيمًا }مَرْجِعَهُ مِنْ الْحُدَيْبِيَةِ وَهُمْ يُخَالِطُهُمْ الْحُزْنُ وَالْكَآبَةُ وَقَدْ نَحَرَ الْهَدْيَ بِالْحُدَيْبِيَةِ فَقَالَ لَقَدْ أُنْزِلَتْ عَلَيَّ آيَةٌ هِيَ أَحَبُّ إِلَيَّ مِنْ الدُّنْيَا جَمِيعًاو حَدَّثَنَا عَاصِمُ بْنُ النَّض��رِ التَّيْمِيُّ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا هَمَّامٌ ح و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ جَمِيعًا عَنْ قَتَادَةَ عَنْ أَنَسٍ نَحْوَ حَدِيثِ ابْنِ أَبِي عَرُوبَةَ","trj":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahzhami] telah menceritakan kepada kami [Khalid bin Al Harits] berkata, telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] bahwa [Anas bin Malik] telah menceritakan kepada mereka, dia berkata, \"Ketika turun ayat: '(Sesungguhnya kami telah memberikan kepadamu kemenangan yang nyata, supaya Allah memberikan ampunan kepadamu terhadap dosamu -hingga firmanNya- dengan pertolongan yang kuat (banyak).' (Qs. Al Fath: 1-3), ketika itu mereka baru pulang dari Hudaibiyyah dengan diliputi perasaan jengkel dan kesal, padahal mereka telah menyembelih binatang kurban. Maka beliau bersabda: \"Sungguh telah turun kepadaku suatu ayat yang lebih aku cintai daripada dunia dan isinya.\" Dan telah menceritakan kepada kami ['Ashim bin An Nadlr At Taimi] telah menceritakan kepada kami [Mu'tamir] dia berkata; aku mendengar [ayahku] telah menceritakan kepada kami [Qatadah] dia berkata; aku pernah mendengar [Anas bin Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Hammam] (dalam jalur lain disebutkan) telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban] semuanya dari [Qatadah] dari [Anas] sebagaimana hadits Ibnu Abu 'Arubah.\""},{"p":"Tirmidzi","n":3015,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَزَلَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لِيَغْفِرَ لَكَ اللَّهُ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ }مَرْجِعَهُ مِنْ الْحُدَيْبِيَةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ نَزَلَتْ عَلَيَّ آيَةٌ أَحَبُّ إِلَيَّ مِمَّا عَلَى الْأَرْضِ ثُمَّ قَرَأَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ فَقَالُوا هَنِيئًا مَرِيئًا يَا رَسُولَ اللَّهِ قَدْ بَيَّنَ اللَّهُ لَكَ مَاذَا يُفْعَلُ بِكَ فَمَاذَا يُفْعَلُ بِنَا فَنَزَلَتْ عَلَيْهِ{ لِيُدْخِلَ الْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ جَنَّاتٍ تَجْرِي مِنْ تَحْتِهَا الْأَنْهَارُ حَتَّى بَلَغَ فَوْزًا عَظِيمًا }قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِيهِ عَنْ مُجَمِّعِ بْنِ جَارِيَةَ","trj":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Qatadah] dari [Anas] radliallahu 'anhu berkata: Turun (ayat) kepada nabi Shallallahu 'alaihi wa Salam: \"Supaya Allah memberi ampunan kepadamu terhadap dosamu yang telah lalu dan yang akan datang.\" (Al Fath: 2) sepulangnya dari Hudaibiyah. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Telah turun ayat padaku yang lebih aku sukai daripada apa yang ada di atas bumi.\" Setelah itu nabi Shallallahu 'alaihi wa Salam membacakannya kepada mereka, mereka berkata: Bergembiralah wahai Rasulullah, Allah telah menjelaskan kepada baginda apa yang akan dilakukan terhadap baginda, lalu apa gerangan yang akan dilakukan terhadap kami? lalu turun ayat: \"Supaya dia memasukkan orang-orang mukmin laki-laki dan perempuan ke dalam surga yang mengalir di bawahnya sungai-sungai, \" sampai firmanNya: \"Keberuntungan yang besar.\" (QS. Alfath 5), Abu Isa berkata: Hadits ini hasan shahih. Dalam hal ini ada hadits serupa dari Mujamma' bin Jariyah."}],"48:3":[{"p":"Bukhari","n":3681,"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ عُمَرُ يُدْخِلُنِي مَعَ أَشْيَاخِ بَدْرٍ فَقَالَ بَعْضُهُمْ لِمَ تُدْخِلُ هَذَا الْفَتَى مَعَنَا وَلَنَا أَبْنَاءٌ مِثْلُهُ فَقَالَ إِنَّهُ مِمَّنْ قَدْ عَلِمْتُمْ قَالَ فَدَعَاهُمْ ذَاتَ يَوْمٍ وَدَعَانِي مَعَهُمْ قَالَ وَمَا رُئِيتُهُ دَعَانِي يَوْمَئِذٍ إِلَّا لِيُرِيَهُمْ مِنِّي فَقَالَ مَا تَقُولُونَ فِي{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ وَرَأَيْتَ النَّاسَ يَدْخُلُونَ فِي دِينِ اللَّهِ أَفْوَاجًا }حَتَّى خَتَمَ السُّورَةَ فَقَالَ بَعْضُهُمْ أُمِرْنَا أَنْ نَحْمَدَ اللَّهَ وَنَسْتَغْفِرَهُ إِذَا نُصِرْنَا وَفُتِحَ عَلَيْنَا وَقَالَ بَعْضُهُمْ لَا نَدْرِي أَوْ لَمْ يَقُلْ بَعْضُهُمْ شَيْئًا فَقَالَ لِي يَا ابْنَ عَبَّاسٍ أَكَذَاكَ تَقُولُ قُلْتُ لَا قَالَ فَمَا تَقُولُ قُلْتُ هُوَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ اللَّهُ لَهُ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَتْحُ مَكَّةَ فَذَاكَ عَلَامَةُ أَجَلِكَ{ فَسَبِّحْ بِحَمْدِ رَبِّكَ وَاسْتَغْفِرْهُ إِنَّهُ كَانَ تَوَّابًا }قَالَ عُمَرُ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","trj":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Said bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma, Umar Pernah mengajakku dalam sebuah majlis orang dewasa, sehingga sebagian sahabat bertanya \"Mengapa si anak kecil ini kau ikut sertakan, kami juga punya anak-anak kecil seperti dia?\" Umar menjawab; \"Kalian maklum, anak ini punya \"kualitas\" tersendiri.\" Kata Ibnu Umar, maka suatu hari Umar mengundang mereka dan mengajakku bersama mereka. Seingatku, Umar tidak mengajakku saat itu selain untuk mempertontonkan kepada mereka kualitas keilmuanku. Lantas Umar bertanyal; \"Bagaimana komentar kalian tentang ayat \"Seandainya pertolongan Allah dan kemenangan datang (1) dan kau lihat manusia masuk agama Allah dengan berbondong-bondong (2) -hingga ahkir surat (QS. Alfath 1-3). Sebagian sahabat berkomentar; \"Tentang ayat ini, setahu kami, kita diperintahkan agar memuji Allah dan meminta ampunan kepada-Nya, tepatnya ketika kita diberi pertolongan dan diberi kemenangan.\" Sebagian lagi berkomentar; \"kalau kami nggak tahu.\" Atau bahkan tidak berkomentar sama sekali. Lantas Umar bertanya kepadaku; \"Wahai Ibnu Abbas, beginikah kamu berkomentar mengenai ayat tadi?\"TIDAK\" Jawabku.\"Lalu komentarmu? Tanya Umar. Ibnu Abbas menjawab; \"Surat tersebut adalah pertanda wafat Rasulullah shallallahu 'alaihi wasallam sudah dekat, Allah memberitahunya dengan ayatnya: \"Jika telah datang pertolongan Allah dan kemenangan', itu berarti penaklukan Makkah dan itulah tanda ajalmu (Muhammad), karenanya \"Bertasbihlah dengan memuji Tuhanmu dan mohonlah ampunan, sesungguhnya Dia Maha Menerima taubat. Kata Umar, \"Aku tidak tahu penafsiran ayat tersebut selain seperti yang kamu (Ibnu Abbas) ketahui.\""},{"p":"Bukhari","n":3790,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يُدْنِي ابْنَ عَبَّاسٍ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ إِنَّ لَنَا أَبْنَاءً مِثْلَهُ فَقَالَ إِنَّهُ مِنْ حَيْثُ تَعْلَمُ فَسَأَلَ عُمَرُ ابْنَ عَبَّاسٍ عَنْ هَذِهِ الْآيَةِ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَقَالَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ إِيَّاهُ فَقَالَ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","trj":"Telah menceritakan kepada kami [Muhammad bin Ar'arah] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; Umar bin Khaththab radliallahu 'anhu pernah mendekatiku. Maka Abdurrahman bin Auf berkata kepadanya; Sesungguhnya kita juga punya anak-anak sepertinya. Umar menjawab; kamu sendirikan tahu siapakah Ibnu Abbas. Lalu Umar bertanya kepada Ibnu Abbas tentang ayat; \"Apabila pertolongan dan kemenangan Allah telah datang.(QS. Alfath 1-5) \" Ibnu Abbas menjawab; \"Ajal Rasulullah shallallahu 'alaihi wasallam telah memberitahukan kepada beliau bahwa dia telah datang kepadanya.\" Umar berkata; 'Aku tidak tahu tentang ayat itu kecuali apa yang kamu ketahui.'"},{"p":"Muslim","n":3108,"ar":"و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْ قَالَلَمَّا نَزَلَتْ{ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا لِيَغْفِرَ لَكَ اللَّهُ إِلَى قَوْلِهِ فَوْزًا عَظِيمًا }مَرْجِعَهُ مِنْ الْحُدَيْبِيَةِ وَهُمْ يُخَالِطُهُمْ الْحُزْنُ وَالْكَآبَةُ وَقَدْ نَحَرَ الْهَدْيَ بِالْحُدَيْبِيَةِ فَقَالَ لَقَدْ أُنْزِلَتْ عَلَيَّ آيَةٌ هِيَ أَحَبُّ إِلَيَّ مِنْ الدُّنْيَا جَمِيعًاو حَدَّثَنَا عَاصِمُ بْنُ النَّض��رِ التَّيْمِيُّ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا هَمَّامٌ ح و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ جَمِيعًا عَنْ قَتَادَةَ عَنْ أَنَسٍ نَحْوَ حَدِيثِ ابْنِ أَبِي عَرُوبَةَ","trj":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahzhami] telah menceritakan kepada kami [Khalid bin Al Harits] berkata, telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] bahwa [Anas bin Malik] telah menceritakan kepada mereka, dia berkata, \"Ketika turun ayat: '(Sesungguhnya kami telah memberikan kepadamu kemenangan yang nyata, supaya Allah memberikan ampunan kepadamu terhadap dosamu -hingga firmanNya- dengan pertolongan yang kuat (banyak).' (Qs. Al Fath: 1-3), ketika itu mereka baru pulang dari Hudaibiyyah dengan diliputi perasaan jengkel dan kesal, padahal mereka telah menyembelih binatang kurban. Maka beliau bersabda: \"Sungguh telah turun kepadaku suatu ayat yang lebih aku cintai daripada dunia dan isinya.\" Dan telah menceritakan kepada kami ['Ashim bin An Nadlr At Taimi] telah menceritakan kepada kami [Mu'tamir] dia berkata; aku mendengar [ayahku] telah menceritakan kepada kami [Qatadah] dia berkata; aku pernah mendengar [Anas bin Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Hammam] (dalam jalur lain disebutkan) telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban] semuanya dari [Qatadah] dari [Anas] sebagaimana hadits Ibnu Abu 'Arubah.\""}],"48:4":[{"p":"Bukhari","n":3790,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يُدْنِي ابْنَ عَبَّاسٍ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ إِنَّ لَنَا أَبْنَاءً مِثْلَهُ فَقَالَ إِنَّهُ مِنْ حَيْثُ تَعْلَمُ فَسَأَلَ عُمَرُ ابْنَ عَبَّاسٍ عَنْ هَذِهِ الْآيَةِ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَقَالَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ إِيَّاهُ فَقَالَ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","trj":"Telah menceritakan kepada kami [Muhammad bin Ar'arah] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; Umar bin Khaththab radliallahu 'anhu pernah mendekatiku. Maka Abdurrahman bin Auf berkata kepadanya; Sesungguhnya kita juga punya anak-anak sepertinya. Umar menjawab; kamu sendirikan tahu siapakah Ibnu Abbas. Lalu Umar bertanya kepada Ibnu Abbas tentang ayat; \"Apabila pertolongan dan kemenangan Allah telah datang.(QS. Alfath 1-5) \" Ibnu Abbas menjawab; \"Ajal Rasulullah shallallahu 'alaihi wasallam telah memberitahukan kepada beliau bahwa dia telah datang kepadanya.\" Umar berkata; 'Aku tidak tahu tentang ayat itu kecuali apa yang kamu ketahui.'"},{"p":"Darimi","n":45,"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا يَزِيدُ بْنُ أَبِي حَكِيمٍ حَدَّثَنِي الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ إِنَّ اللَّهَ فَضَّلَ مُحَمَّدًا عَلَى الْأَنْبِيَاءِ وَعَلَى أَهْلِ السَّمَاءِ فَقَالُوا يَا ابْنَ عَبَّاسٍ بِمَ فَضَّلَهُ عَلَى أَهْلِ السَّمَاءِ قَالَ إِنَّ اللَّهَ قَالَ لِأَهْلِ السَّمَاءِ { وَمَنْ يَقُلْ مِنْهُمْ إِنِّي إِلَهٌ مِنْ دُونِهِ فَذَلِكَ نَجْزِيهِ جَهَنَّمَ كَذَلِكَ نَجْزِي الظَّالِمِينَ } الْآيَةَ وَقَالَ اللَّهُ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا لِيَغْفِرَ لَكَ اللَّهُ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ } قَالُوا فَمَا فَضْلُهُ عَلَى الْأَنْبِيَاءِ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ { وَمَا أَرْسَلْنَا مِنْ رَسُولٍ إِلَّا بِلِسَانِ قَوْمِهِ لِيُبَيِّنَ لَهُمْ } الْآيَةَ وَقَالَ اللَّهُ عَزَّ وَجَلَّ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { وَمَا أَرْسَلْنَاكَ إِلَّا كَافَّةً لِلنَّاسِ } فَأَرْسَلَهُ إِلَى الْجِنِّ وَالْإِنْسِ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Yazid bin Abu Hakim] telah menceritakan kepadaku [Al Hakam bin Abaan] dari ['Ikrimah] dari [Ibnu Abbas] Radliyallahu'anhu ia berkata; \" Sesungguhnya Allah Subhanahu wa Ta'ala memberikan keutamaan kepada Nabi Muhammad shallallahu 'alaihi wasallam atas Nabi-nabi yang lainnya dan atas penghuni langit. \" lalu mereka bertanya: \"Wahai Ibnu Abbas, keutamaan apa yang diberikan kepada beliau atas penghuni langit?\" Ibnu Abbas menjawab; \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman kepada penghuni langit: Dari Ibnu Abbas berkata: WAMAN YAQUL MINHUM INNII ILAAHUN MIN DUNIHI FADZALIJKA NAJZIIHI JAHANNAMA KADZALIKA NAJZII AZHA-ZHALIMIIN Dan barang siapa diantara mereka mengatakan, sesungguhnya aku adalah tuhan selain dari pada Allah Subhanahu wa Ta'ala, maka orang itu kami beri balasan dengan jahannam, dengan demikian kami memberikan pembalasan kepada orang-orang zhalim. (Qs. Al Anbiya` /21: 29) Dan Allah Subhanahu wa Ta'ala terhadap dosamu yang telah lalu dan yang akan datang serta menyempurnakan nikmat-Nya atasmu dan memimpin kamu ke jalan yang lurus. ` (Qs. Al Fath /48: 1. 2) Lalu mereka bertanya, \" Apa keutamaan beliau atas semua Nabi-nabi?\" bin Abbas menjawab, \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman, `Kami tidak mengutus seorang Rasul pun, melainkan dengan bahasa kaumnya, supaya ia dapat memberi penjelasan dengan terang kepada mereka. ` (Qs. Ibraahiim /14: 4) dan Allah Subhanahu wa Ta'ala berfirman untuk Nabi Muhammad shallallahu 'alaihi wasallam, ` dan Kami tidak mengutus kamu melainkan kepada umat manusia seluruhnya Sebagai pembawa berita gembira dan pemberi peringatan. ` (Qs. As Saba` 34: 28), maka beliau telah diutus kepada bangsa jin dan manusia. "}],"48:5":[{"p":"Bukhari","n":3790,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يُدْنِي ابْنَ عَبَّاسٍ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ إِنَّ لَنَا أَبْنَاءً مِثْلَهُ فَقَالَ إِنَّهُ مِنْ حَيْثُ تَعْلَمُ فَسَأَلَ عُمَرُ ابْنَ عَبَّاسٍ عَنْ هَذِهِ الْآيَةِ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَقَالَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ إِيَّاهُ فَقَالَ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","trj":"Telah menceritakan kepada kami [Muhammad bin Ar'arah] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; Umar bin Khaththab radliallahu 'anhu pernah mendekatiku. Maka Abdurrahman bin Auf berkata kepadanya; Sesungguhnya kita juga punya anak-anak sepertinya. Umar menjawab; kamu sendirikan tahu siapakah Ibnu Abbas. Lalu Umar bertanya kepada Ibnu Abbas tentang ayat; \"Apabila pertolongan dan kemenangan Allah telah datang.(QS. Alfath 1-5) \" Ibnu Abbas menjawab; \"Ajal Rasulullah shallallahu 'alaihi wasallam telah memberitahukan kepada beliau bahwa dia telah datang kepadanya.\" Umar berkata; 'Aku tidak tahu tentang ayat itu kecuali apa yang kamu ketahui.'"},{"p":"Darimi","n":414,"ar":" أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ سُلَيْمَانَ أَبُو عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ عَنْ عَبَّادِ بْنِ عَبَّادٍ الْخَوَّاصِ الشَّامِيِّ أَبِي عُتْبَةَ قَالَ أَمَّا بَعْدُ اعْقِلُوا وَالْعَقْلُ نِعْمَةٌ فَرُبَّ ذِي عَقْلٍ قَدْ شُغِلَ قَلْبُهُ بِالتَّعَمُّقِ عَمَّا هُوَ عَلَيْهِ ضَرَرٌ عَنْ الِانْتِفَاعِ بِمَا يَحْتَاجُ إِلَيْهِ حَتَّى صَارَ عَنْ ذَلِكَ سَاهِيًا وَمِنْ فَضْلِ عَقْلِ الْمَرْءِ تَرْكُ النَّظَرِ فِيمَا لَا نَظَرَ فِيهِ حَتَّى لَا يَكُونَ فَضْلُ عَقْلِهِ وَبَالًا عَلَيْهِ فِي تَرْكِ مُنَافَسَةِ مَنْ هُوَ دُونَهُ فِي الْأَعْمَالِ الصَّالِحَةِ أَوْ رَجُلٍ شُغِلَ قَلْبُهُ بِبِدْعَةٍ قَلَّدَ فِيهَا دِينَهُ رِجَالًا دُونَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ اكْتَفَى بِرَأْيِهِ فِيمَا لَا يَرَى الْهُدَى إِلَّا فِيهَا وَلَا يَرَى الضَّلَالَةَ إِلَّا بِتَرْكِهَا يَزْعُمُ أَنَّهُ أَخَذَهَا مِنْ الْقُرْآنِ وَهُوَ يَدْعُو إِلَى فِرَاقِ الْقُرْآنِ أَفَمَا كَانَ لِلْقُرْآنِ حَمَلَةٌ قَبْلَهُ وَقَبْلَ أَصْحَابِهِ يَعْمَلُونَ بِمُحْكَمِهِ وَيُؤْمِنُونَ بِمُتَشَابِهِهِ وَكَانُوا مِنْهُ عَلَى مَنَارٍ كَوَضَحِ الطَّرِيقِ فَكَانَ الْقُرْآنُ إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ إِمَامًا لِأَصْحَابِهِ وَكَانَ أَصْحَابُهُ أَئِمَّةً لِمَنْ بَعْدَهُمْ رِجَالٌ مَعْرُوفُونَ مَنْسُوبُونَ فِي الْبُلْدَانِ مُتَّفِقُونَ فِي الرَّدِّ عَلَى أَصْحَابِ الْأَهْوَاءِ مَعَ مَا كَانَ بَيْنَهُمْ مِنْ الِاخْتِلَافِ وَتَسَكَّعَ أَصْحَابُ الْأَهْوَاءِ بِرَأْيِهِمْ فِي سُبُلٍ مُخْتَلِفَةٍ جَائِرَةٍ عَنْ الْقَصْدِ مُفَارِقَةٍ لِلصِّرَاطِ الْمُسْتَقِيمِ فَتَوَّهَتْ بِهِمْ أَدِلَّاؤُهُمْ فِي مَهَامِهَ مُضِلَّةٍ فَأَمْعَنُوا فِيهَا مُتَعَسِّفِينَ فِي تِيهِهِمْ كُلَّمَا أَحْدَثَ لَهُمْ الشَّيْطَانُ بِدْعَةً فِي ضَلَالَتِهِمْ انْتَقَلُوا مِنْهَا إِلَى غَيْرِهَا لِأَنَّهُمْ لَمْ يَطْلُبُوا أَثَرَ السَّالِفِينَ وَلَمْ يَقْتَدُوا بِالْمُهَاجِرِينَ وَقَدْ ذُكِرَ عَنْ عُمَرَ أَنَّهُ قَالَ لِزِيَادٍ هَلْ تَدْرِي مَا يَهْدِمُ الْإِسْلَامَ زَلَّةُ عَالِمٍ وَجِدَالُ مُنَافِقٍ بِالْقُرْآنِ وَأَئِمَّةٌ مُضِلُّونَ اتَّقُوا اللَّهَ وَمَا حَدَثَ فِي قُرَّائِكُمْ وَأَهْلِ مَسَاجِدِكُمْ مِنْ الْغِيبَةِ وَالنَّمِيمَةِ وَالْمَشْيِ بَيْنَ النَّاسِ بِوَجْهَيْنِ وَلِسَانَيْنِ وَقَدْ ذُكِرَ أَنَّ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ ذَا وَجْهَيْنِ فِي النَّارِ يَلْقَاكَ صَاحِبُ الْغِيبَةِ فَيَغْتَابُ عِنْدَكَ مَنْ يَرَى أَنَّكَ تُحِبُّ غِيبَتَهُ وَيُخَالِفُكَ إِلَى صَاحِبِكَ فَيَأْتِيهِ عَنْكَ بِمِثْلِهِ فَإِذَا هُوَ قَدْ أَصَابَ عِنْدَ كُلِّ وَاحِدٍ مِنْكُمَا حَاجَتَهُ وَخَفِيَ عَلَى كُلِّ وَاحِدٍ مِنْكُمَا مَا أُتِيَ بِهِ عِنْدَ صَاحِبِهِ حُضُورُهُ عِنْدَ مَنْ حَضَرَهُ حُضُورُ الْإِخْوَانِ وَغَيْبَتُهُ عَلَى مَنْ غَابَ عَنْهُ غَيْبَةُ الْأَعْدَاءِ مَنْ حَضَرَ مِنْهُمْ كَانَتْ لَهُ الْأَثَرَةُ وَمَنْ غَابَ مِنْهُمْ لَمْ تَكُنْ لَهُ حُرْمَةٌ يَفْتِنُ مَنْ حَضَرَهُ بِالتَّزْكِيَةِ وَيَغْتَابُ مَنْ غَابَ عَنْهُ بِالْغِيبَةِ فَيَا لَعِبَادَ اللَّهِ أَمَا فِي الْقَوْمِ مِنْ رَشِيدٍ وَلَا مُصْلِحٍ يَقْمَعُ هَذَا عَنْ مَكِيدَتِهِ وَيَرُدُّهُ عَنْ عِرْضِ أَخِيهِ الْمُسْلِمِ بَلْ عَرَفَ هَوَاهُمْ فِيمَا مَشَى بِهِ إِلَيْهِمْ فَاسْتَمْكَنَ مِنْهُمْ وَأَمْكَنُوهُ مِنْ حَاجَتِهِ فَأَكَلَ بِدِينِهِ مَعَ أَدْيَانِهِمْ فَاللَّهَ اللَّهَ ذُبُّوا عَنْ حُرَمِ أَغْيَابِكُمْ وَكُفُّوا أَلْسِنَتَكُمْ عَنْهُمْ إِلَّا مِنْ خَيْرٍ وَنَاصِحُوا اللَّهَ فِي أُمَّتِكُمْ إِذْ كُنْتُمْ حَمَلَةَ الْكِتَابِ وَالسُّنَّةِ فَإِنَّ الْكِتَابَ لَا يَنْطِقُ حَتَّى يُنْطَقَ بِهِ وَإِنَّ السُّنَّةَ لَا تَعْمَلُ حَتَّى يُعْمَلَ بِهَا فَمَتَى يَتَعَلَّمُ الْجَاهِلُ إِذَا سَكَتَ الْعَالِمُ فَلَمْ يُنْكِرْ مَا ظَهَرَ وَلَمْ يَأْمُرْ بِمَا تُرِكَ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } اتَّقُوا اللَّهَ فَإِنَّكُمْ فِي زَمَانٍ رَقَّ فِيهِ الْوَرَعُ وَقَلَّ فِيهِ الْخُشُوعُ وَحَمَلَ الْعِلْمَ مُفْسِدُوهُ فَأَحَبُّوا أَنْ يُعْرَفُوا بِحَمْلِهِ وَكَرِهُوا أَنْ يُعْرَفُوا بِإِضَاعَتِهِ فَنَطَقُوا فِيهِ بِالْهَوَى لَمَّا أَدْخَلُوا فِيهِ مِنْ الْخَطَإِ وَحَرَّفُوا الْكَلِمَ عَمَّا تَرَكُوا مِنْ الْحَقِّ إِلَى مَا عَمِلُوا بِهِ مِنْ بَاطِلٍ فَذُنُوبُهُمْ ذُنُوبٌ لَا يُسْتَغْفَرُ مِنْهَا وَتَقْصِيرُهُمْ تَقْصِيرٌ لَا يُعْتَرَفُ بِهِ كَيْفَ يَهْتَدِي الْمُسْتَدِلُّ الْمُسْتَرْشِدُ إِذَا كَانَ الدَّلِيلُ حَائِرًا أَحَبُّوا الدُّنْيَا وَكَرِهُوا مَنْزِلَةَ أَهْلِهَا فَشَارَكُوهُمْ فِي الْعَيْشِ وَزَايَلُوهُمْ بِالْقَوْلِ وَدَافَعُوا بِالْقَوْلِ عَنْ أَنْفُسِهِمْ أَنْ يُنْسَبُوا إِلَى عَمَلِهِمْ فَلَمْ يَتَبَرَّءُوا مِمَّا انْتَفَوْا مِنْهُ وَلَمْ يَدْخُلُوا فِيمَا نَسَبُوا إِلَيْهِ أَنْفُسَهُمْ لِأَنَّ الْعَامِلَ بِالْحَقِّ مُتَكَلِّمٌ وَإِنْ سَكَتَ وَقَدْ ذُكِرَ أَنَّ اللَّهَ تَعَالَى يَقُولُ إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَنْظُرُ إِلَى هَمِّهِ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ لِي جَعَلْتُ صَمْتَهُ حَمْدًا وَوَقَارًا لِي وَإِنْ لَمْ يَتَكَلَّمْ وَقَالَ اللَّهُ تَعَالَى { مَثَلُ الَّذِينَ حُمِّلُوا التَّوْرَاةَ ثُمَّ لَمْ يَحْمِلُوهَا } لَمْ يَعْمَلُوا بِهَا { كَمَثَلِ الْحِمَارِ يَحْمِلُ أَسْفَارًا } كُتُبًا وَقَالَ { خُذُوا مَا آتَيْنَاكُمْ بِقُوَّةٍ } قَالَ الْعَمَلُ بِمَا فِيهِ وَلَا تَكْتَفُوا مِنْ السُّنَّةِ بِانْتِحَالِهَا بِالْقَوْلِ دُونَ الْعَمَلِ بِهَا فَإِنَّ انْتِحَالَ السُّنَّةِ دُونَ الْعَمَلِ بِهَا كَذِبٌ بِالْقَوْلِ مَعَ إِضَاعَةِ الْعَمَلِ وَلَا تَعِيبُوا بِالْبِدَعِ تَزَيُّنًا بِعَيْبِهَا فَإِنَّ فَسَادَ أَهْلِ الْبِدَعِ لَيْسَ بِزَائِدٍ فِي صَلَاحِكُمْ وَلَا تَعِيبُوهَا بَغْيًا عَلَى أَهْلِهَا فَإِنَّ الْبَغْيَ مِنْ فَسَادِ أَنْفُسِكُمْ وَلَيْسَ يَنْبَغِي لِلطَّبِيبِ أَنْ يُدَاوِيَ الْمَرْضَى بِمَا يُبَرِّئُهُمْ وَيُمْرِضُهُ فَإِنَّهُ إِذَا مَرِضَ اشْتَغَلَ بِمَرَضِهِ عَنْ مُدَاوَاتِهِمْ وَلَكِنْ يَنْبَغِي أَنْ يَلْتَمِسَ لِنَفْسِهِ الصِّحَّةَ لِيَقْوَى بِهِ عَلَى عِلَاجِ الْمَرْضَى فَلْيَكُنْ أَمْرُكُمْ فِيمَا تُنْكِرُونَ عَلَى إِخْوَانِكُمْ نَظَرًا مِنْكُمْ لِأَنْفُسِكُمْ وَنَصِيحَةً مِنْكُمْ لِرَبِّكُمْ وَشَفَقَةً مِنْكُمْ عَلَى إِخْوَانِكُمْ وَأَنْ تَكُونُوا مَعَ ذَلِكَ بِعُيُوبِ أَنْفُسِكُمْ أَعْنَى مِنْكُمْ بِعُيُوبِ غَيْرِكُمْ وَأَنْ يَسْتَطْعِمَ بَعْضُكُمْ بَعْضًا النَّصِيحَةَ وَأَنْ يَحْظَى عِنْدَكُمْ مَنْ بَذَلَهَا لَكُمْ وَقَبِلَهَا مِنْكُمْ وَقَدْ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَحِمَ اللَّهُ مَنْ أَهْدَى إِلَيَّ عُيُوبِي تُحِبُّونَ أَنْ تَقُولُوا فَيُحْتَمَلَ لَكُمْ وَإِنْ قِيلَ لَكُمْ مِثْلُ الَّذِي قُلْتُمْ غَضِبْتُمْ تَجِدُونَ عَلَى النَّاسِ فِيمَا تُنْكِرُونَ مِنْ ��ُمُورِهِمْ وَتَأْتُونَ مِثْلَ ذَلِكَ فَلَا تُحِبُّونَ أَنْ يُوجَدَ عَلَيْكُمْ اتَّهِمُوا رَأْيَكُمْ وَرَأْيَ أَهْلِ زَمَانِكُمْ وَتَثَبَّتُوا قَبْلَ أَنْ تَكَلَّمُوا وَتَعَلَّمُوا قَبْلَ أَنْ تَعْمَلُوا فَإِنَّهُ يَأْتِي زَمَانٌ يَشْتَبِهُ فِيهِ الْحَقُّ وَالْبَاطِلُ وَيَكُونُ الْمَعْرُوفُ فِيهِ مُنْكَرًا وَالْمُنْكَرُ فِيهِ مَعْرُوفًا فَكَمْ مِنْ مُتَقَرِّبٍ إِلَى اللَّهِ بِمَا يُبَاعِدُهُ وَمُتَحَبِّبٍ إِلَيْهِ بِمَا يُغْضِبُهُ عَلَيْهِ قَالَ اللَّهُ تَعَالَى { أَفَمَنْ زُيِّنَ لَهُ سُوءُ عَمَلِهِ فَرَآهُ حَسَنًا } الْآيَةَ فَعَلَيْكُمْ بِالْوُقُوفِ عِنْدَ الشُّبُهَاتِ حَتَّى يَبْرُزَ لَكُمْ وَاضِحُ الْحَقِّ بِالْبَيِّنَةِ فَإِنَّ الدَّاخِلَ فِيمَا لَا يَعْلَمُ بِغَيْرِ عِلْمٍ آثِمٌ وَمَنْ نَظَرَ لِلَّهِ نَظَرَ اللَّهُ لَهُ عَلَيْكُمْ بِالْقُرْآنِ فَأْتَمُّوا بِهِ وَأُمُّوا بِهِ وَعَلَيْكُمْ بِطَلَبِ أَثَرِ الْمَاضِينَ فِيهِ وَلَوْ أَنَّ الْأَحْبَارَ وَالرُّهْبَانَ لَمْ يَتَّقُوا زَوَالَ مَرَاتِبِهِمْ وَفَسَادَ مَنْزِلَتِهِمْ بِإِقَامَةِ الْكِتَابِ وَتِبْيَانِهِ مَا حَرَّفُوهُ وَلَا كَتَمُوهُ وَلَكِنَّهُمْ لَمَّا خَالَفُوا الْكِتَابَ بِأَعْمَالِهِمْ الْتَمَسُوا أَنْ يَخْدَعُوا قَوْمَهُمْ عَمَّا صَنَعُوا مَخَافَةَ أَنْ تَفْسُدَ مَنَازِلُهُمْ وَأَنْ يَتَبَيَّنَ لِلنَّاسِ فَسَادُهُمْ فَحَرَّفُوا الْكِتَابَ بِالتَّفْسِيرِ وَمَا لَمْ يَسْتَطِيعُوا تَحْرِيفَهُ كَتَمُوهُ فَسَكَتُوا عَنْ صَنِيعِ أَنْفُسِهِمْ إِبْقَاءً عَلَى مَنَازِلِهِمْ وَسَكَتُوا عَمَّا صَنَعَ قَوْمُهُمْ مُصَانَعَةً لَهُمْ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } بَلْ مَالَئُوا عَلَيْهِ وَرَقَّقُوا لَهُمْ فِيهِ","trj":"Telah mengabarkan kepada kami [Abdul Malik bin Sulaiman Abu Abdur Rahman Al `Anthaki] dari ['Abbad bin 'Abbad Al Khawwash As Syami Abu 'Utbah] ia berkata: \"Perhatian, gunakanlah akal, karena akal sebuah nikmat. Berapa banyak orang berakal menyibukkan hatinya untuk memperdalam hal-hal yang membahayakan dirinya daripada memanfaatkan apa yang dibutuhkannya, sehingga ia lupa hal itu. Diantara keutamaan akal seseorang adalah meninggalkan perhatian terhadap hal-hal yang tidak perlu sehingga keutamaan akalnya tidak menjadi bencana baginya, yaitu ia meninggalkan persaingan dengan orang yang lebih rendah amal shalihnya, atau seseorang yang menyibukkan hatinya dengan bid'ah, yang ia sekedar mengikuti orang dalam urusan agamanya tanpa mengikuti para sahabat Rasulullah shalallahu 'alahi wa sallam, atau ia hanya merasa cukup dengan pendapatnya sendiri, yang ia tidak melihat petunjuk kecuali kepada akalnya, dan tidak melihat kesesatan kecuali meninggalkannya dengan anggapan bahwa ia mengambilnya dari Al qur`an, padahal ia menyerukan untuk meninggalkan Al qur`an. Bukankah Al qur`an mempunyai pengemban-pengemban sebelumnya, yaitu para pembelanya yang mengamalkan ayat-ayat yang muhkam dan mengimani ayat-ayat yang mutasyabih? Mereka berada di menara layaknya cahaya jalan, Al Quran imam Rasulullah shalallahu'alahi wa sallam, sedang Rasulullah shallahu 'alaihi wa sallam imam para sahabatnya, dan para sahabat adalah imam orang-orang setelah mereka, yaitu orang-orang yang sudah dikenal kebaikannya, mereka menjadi barometer di negeri-negeri mereka yang sepakat menolak para pengagung hawa nafsu walaupun diantara mereka terdapat perselisihan pendapat. Para pengagum hawa nafsu meraba-raba dengan pendapat mereka, yaitu dengan cara yang bermacam-macam, yang melenceng dari tujuan karena memisahkan diri dari jalan yang lurus. Petunjuk mereka menyesatkan mereka sendiri dalam misteri padang pasir yang menyesatkan. Mereka konsentrasi melihat petunjuk jalan dengan penuh kebingungan dalam kesesatannya. Setiap kali setan membuat satu bid'ah dalam kesesatan, mereka berpindah dari satu bid'ah ke bid'ah lain, karena mereka tidak mencari petunjuk para pendahulu dan juga tidak mengikuti jejak kaum muhajirin. Telah disebutkan dalam satu riwayat dari Umar radliallahu 'anhu bahwa ia berkata kepada Ziad: 'Tahukah kamu apa yang (menyebabkan) kehancuran Islam? ', Jawabnya karena kesalahan orang berilmu, perdebatan orang munafik terhadap Al Qur`an dan para imam yang sesat'. Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan waspadailah apa yang terjadi pada ulama kamu dan pengisi masjid-masjid kamu dari perbuatan ghibah, namimah dan berjalan diantara manusia dengan dua wajah dan dua lisan. Dalam satu riwayat disebutkan barangsiapa mempunyai dua wajah di dunia, ia mempunyai dua wajah di neraka. Jika tukang ghibah menemuimu, ia menggunjing orang yang kamu senangi untuk di gunjing, lalu ia berpaling darimu untuk mendatangi temanmu dan melakukan hal yang sama. Jika ia telah memperoleh apa yang ia butuhkan dari setiap kalian, dan menyembunyikan sesuatu dari salah satu (dari) kalian, ia tidak memberi kabar kepada sahabatmu yang lain. Kedatangannya kepada orang yang didatanginya adalah seperti datangnya seorang teman, namun kepergiannya dari teman yang ditinggalkan bagaikan kepergian dari seorang musuh. Siapa saja yang menemuinya, ia dapatkan kemuliaan, sebaliknya siapa yang tidak ditemuinya, tidak ia dapatkan kehormatan, ia menipu orang yang didatanginya dengan penghargaan-penghargaan, dan menggunjing orang yang tidak ditemuinya dengan ghibah mematikan. Wahai hamba-hamba Allah subhanallahu wa ta'ala, tidakkah suatu kaum muncul penunjuk jalan dan reformis, yang ia sanggup mengekang orang seperti ini dari tipu dayanya, dan mengajaknya untuk mempertahankan kehormatan saudaranya semuslim?, bahkan kalau bisa memberitahu mereka niyat orang seperti ini saat datang menemui mereka, yang ia bertindak sekedar ingin memperoleh keperluannya sehingga mereka mempersilahkan, yang ujungnya ia mencaplok agamanya sekaligus agama mereka? Ya Allah, Ya Allah! Pertahankanlah kehormatan kamu, hentikanlah lisanmu (dari menggunjing) mereka kecuali kebaikan semata. Tolong kalian saling mengingatkan untuk berbakti kepada Allah khususnya terhadap umatmu, karena kamu adalah pengemban Al Kitab (Al Qur`an) dan sunah,. Al Kitab tidak berbicara hingga ia dibicarakan, dan sunnah tidak sanggup mengejawantahkan hingga ia diejawantahkan. Bilamana orang bodoh belajar, namun orang alim diam tidak memungkiri apa yang nampak dan tidak memerintahkan apa yang ditinggalkan', bukankah Allah subhanallahu wa ta'ala telah mengambil perjanjian dari orang-orang yang diberikan Al Kitab kepada mereka untuk menjelaskannya kepada manusia dan tidak menyembunyikannya?. Bertakwalah kepada Allah subhanallahu wa ta'ala, karena kamu berada pada zaman menipisnya sifat wara' dan kurangnya kekhusyu'an, dan para pengemban ilmu adalah para perusaknya. Mereka begitu marah jika dikenal sebagai orang-orang yang menghilangkannya, mereka membicarakannya dengan hawa nafsu ketika mengikutsertakan kesalahan dalam ilmu, dan memutarbalikkan perkataan dari kebenaran yang mereka tinggalkan, lantas mereka belokkan menuju kebatilan yang mereka kerjakan. Dosa mereka adalah dosa yang tidak diampuni dan kelalaian mereka adalah kelalaian yang tidak bisa dibenarkan, bagaimana orang yang mencari petunjuk dan tuntunan mendapatkan petunjuk apabila petunjuknya sendiri membingungkan, mereka cinta dunia dan benci terhadap kebahagiaan penduduknya yang memperoleh kedudukan tinggi, lantas mereka menyertai dalam kehidupan dan menyelisihi mereka dengan perkataan, dan mempertahankan diri mereka dengan perkataan, agar mereka dihubung-hubungkan dengan kebaikan mereka. Mereka sama sekali tidak bersih dari kotoran yang mereka hilangkan, dan belum memenuhi kriteria untuk dihargai amal mereka, sebab orang yang benar-benar beramal shalih secara tidak langsung ia ia telah bicara sekalipun dia diam. Dan telah diberitakan bahwa Allah Ta'ala berfirman; Aku tidak menerima semua semua perkataan orang bijak, akan tetapi Aku melihat kepada kecenderungan dan niyat baiknya untuk-Ku. Sebab siapa yang hasrat dan niyatnya untuk-Ku, Aku jadikan diamnya terpuji dan berwibawa, walaupun ia tidak berbicara. Allah subhanallahu wa ta'ala berfirman: \"MATSALULLADZINA HUMMILUT TAURATA TSUMMA LAM YAHMILUUHA KAMATSALIL HIMARI YAHMILUL ASFARA\" (Perumpamaan orang-orang yang dipikulkan kepadanya Taurat, kemudian mereka tidak memikulnya (tidak mengerjakannya) adalah seperti keledai yang membawa kitab-kitab yang tebal) -Qs. Al Jumu'ah: 5-, Allah subhanallahu wa ta'ala juga berfirman: \"KHUDZU MAA ATAINAAKUM BI QUWWAH\" (Peganglah teguh-teguh apa yang telah kami berikan kepadamu) -Qs. Al Baqarah: 63, 93, 171-, ia berkata: 'Maksudnya mengerjakan isi yang terkandung padanya, dan tidak mencukupkan sunnah hanya dengan ucapan tanpa pengalaman. Karena pensifatan sunnah dengan perkataan tanpa perbuatan adalah dusta dengan perkataan, yang sekaligus menghilangkan ilmu. Dan janganlah kamu mencela bid`ah sekedar untuk bungkus keindahanmu dengan meneropong aib-aibnya, karena kerusakan penganut bid`ah tidak menambah kesalehanmu, dan janganlah kamu mencelanya karena dorongan diskriminatif terhadap penganutnya, karena diskriminasi adalah kerusakan dirimu sendiri, sebab tidak selayaknya dokter mengobati pasien dengan obat yang berpotensi menyembuhkan penyakit namun obat itu juga berpotensi mendatangkan penyakit baru. Karena apabila dokter itu sakit, ia sibuk dengan penyakitnya dan lupa mengobati mereka. Akan tetapi selayaknya ia mencari kesehatan untuk dirinya agar ia dapat mengobati para pasien. Hendaklah saat engkau melihat masalah yang menimpa saudara-saudaramu dan hatimu \"kurang sreg\", sebagaimana engkau melihat jika terjadi pada dirimu sendiri dan sebagai \"peringatan\" Tuhanmu terhadapmu, serta rasa kasihanmu kepada saudara-saudara kamu. Walaupun dalam hal itu lebih baik kamu lebih peduli terhadap aib diri kamu sendiri dari pada aib orang lain, dan lakukan saling menasehati satu sama lain diantara kamu, dan hendaklah yang mengorbankan nasehat itu merasa beruntung dan kamu menerimanya. Umar bin Al Khatthab radliallahu 'anhu berkata: 'Semoga Allah subhanallahu wa ta'ala melimpahkan rahmat kepada orang yang menunjukkan aib-aibku kepadaku'. Kamu suka berkata dan orang yang mendengarmu menahan diri demi kebaikanmu, padahal jika dikatakan kepada kamu perkataan yang sama seperti yang kamu katakan, kamu jengkel. Kamu mendapatkan hal-hal yang menjengkelkanmu, sebaliknya kamu mengerjakan apa yang mereka kerjakan, apakah kamu tidak suka dipersalahkan? ', Pikir ulanglah pendapatmu dan pendapat orang-orang yang sezaman denganmu, Selidikilah dahulu sebuah berita sebelum kalian berbicara dan belajarlah sebelum kalian beramal. Karena nanti akan datang suatu zaman yang saat itu yang benar bercampur dengan yang batil, dan yang ma'ruf (baik) menjadi mungkar dan yang mungkar menjadi ma'ruf. Betapa banyak orang yang mendekatkan diri kepada Allah subhanallahu w ta'ala namun dengan hal-hal yang justru menjauhkan dariNya, dan mencari cintaNya dengan hal-hal yang membuatNya murka. Allah subhanallahu wa ta'ala berfirman: \"AFAMAN ZUYYINA LAHU SUU`U 'MALIHI FA RA`AHU HASANA\" (Maka apabila orang yang dijadikan (syaitan) menganggap baik pekerjaannya yang buruk lalu ia meyakini pekerjaan itu baik (sama dengan orang yang tidak ditipu syaitan)? -Qs. Al Fathir: 8-, hendaklah kamu berhenti dari hal-hal yang syubhat sehingga nampak bagi kamu kebenaran yang jelas disertai keterangan, karena orang yang mengintervensi perkara yang ia tidak tahu tanpa ilmu, ia berdosa, dan barangsiapa yang menyelidiki dengan niat ikhlash karena Allah, Allah subhanallahu wa ta'ala akan melihatnya. Hendaklah kamu berpegang teguh dengan Al Qur`an, jadikanlah ia imam dan ajaklah (manusia) untuk menjadikan Al Qur`an sebagai imam. Hendaknya kamu mencari jejak-jejak para pendahulu padanya. Seandainya para ahbar (pendeta yahudi) dan para rahib (pendeta Nashrani) tidak takut kehilangan martabat mereka dan kerusakan kedudukannya dengan menegakkan Al Kitab dan penjelasannya, niscaya mereka tidak akan menyelewengkan dan menyembunyikannya, akan tetapi mereka ketika menentang Al Kitab dengan perbuatan mereka, mereka berusaha mencari cara menipu kaumnya karena perbuatan yang mereka lakukan sendiri, karena mereka khawatir kedudukan mereka dirobohkan, dan manusia memperoleh kejelasan kerusakan mereka, lalu mereka selewengkan Al Kitab dengan tafsir menyeleweng, dan apa yang mereka tidak bisa selewengkan, mereka sembunyikan, lalu mereka diam terhadap perbuatan mereka sendiri karena dorongan untuk mempertahankan kedudukan mereka, dan diam terhadap apa yang diperbuat oleh kaumnya sambil berpura-pura. Sedang Allah subhanallahu wa ta'ala telah mengambil perjanjian dengan orang-orang yang di berikan Al Kitab agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya, akan tetapi mereka justru cenderung kepadanya dan mengajak manusia menganggap enteng masalah itu. "},{"p":"Tirmidzi","n":3015,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَزَلَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لِيَغْفِرَ لَكَ اللَّهُ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ }مَرْجِعَهُ مِنْ الْحُدَيْبِيَةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ نَزَلَتْ عَلَيَّ آيَةٌ أَحَبُّ إِلَيَّ مِمَّا عَلَى الْأَرْضِ ثُمَّ قَرَأَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ فَقَالُوا هَنِيئًا مَرِيئًا يَا رَسُولَ اللَّهِ قَدْ بَيَّنَ اللَّهُ لَكَ مَاذَا يُفْعَلُ بِكَ فَمَاذَا يُفْعَلُ بِنَا فَنَزَلَتْ عَلَيْهِ{ لِيُدْخِلَ الْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ جَنَّاتٍ تَجْرِي مِنْ تَحْتِهَا الْأَنْهَارُ حَتَّى بَلَغَ فَوْزًا عَظِيمًا }قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِيهِ عَنْ مُجَمِّعِ بْنِ جَارِيَةَ","trj":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Qatadah] dari [Anas] radliallahu 'anhu berkata: Turun (ayat) kepada nabi Shallallahu 'alaihi wa Salam: \"Supaya Allah memberi ampunan kepadamu terhadap dosamu yang telah lalu dan yang akan datang.\" (Al Fath: 2) sepulangnya dari Hudaibiyah. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Telah turun ayat padaku yang lebih aku sukai daripada apa yang ada di atas bumi.\" Setelah itu nabi Shallallahu 'alaihi wa Salam membacakannya kepada mereka, mereka berkata: Bergembiralah wahai Rasulullah, Allah telah menjelaskan kepada baginda apa yang akan dilakukan terhadap baginda, lalu apa gerangan yang akan dilakukan terhadap kami? lalu turun ayat: \"Supaya dia memasukkan orang-orang mukmin laki-laki dan perempuan ke dalam surga yang mengalir di bawahnya sungai-sungai, \" sampai firmanNya: \"Keberuntungan yang besar.\" (QS. Alfath 5), Abu Isa berkata: Hadits ini hasan shahih. Dalam hal ini ada hadits serupa dari Mujamma' bin Jariyah."}],"48:8":[{"p":"Darimi","n":414,"ar":" أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ سُلَيْمَانَ أَبُو عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ عَنْ عَبَّادِ بْنِ عَبَّادٍ الْخَوَّاصِ الشَّامِيِّ أَبِي عُتْبَةَ قَالَ أَمَّا بَعْدُ اعْقِلُوا وَالْعَقْلُ نِعْمَةٌ فَرُبَّ ذِي عَقْلٍ قَدْ شُغِلَ قَلْبُهُ بِالتَّعَمُّقِ عَمَّا هُوَ عَلَيْهِ ضَرَرٌ عَنْ الِانْتِفَاعِ بِمَا يَحْتَاجُ إِلَيْهِ حَتَّى صَارَ عَنْ ذَلِكَ سَاهِيًا وَمِنْ فَضْلِ عَقْلِ الْمَرْءِ تَرْكُ النَّظَرِ فِيمَا لَا نَظَرَ فِيهِ حَتَّى لَا يَكُونَ فَضْلُ عَقْلِهِ وَبَالًا عَلَيْهِ فِي تَرْكِ مُنَافَسَةِ مَنْ هُوَ دُونَهُ فِي الْأَعْمَالِ الصَّالِحَةِ أَوْ رَجُلٍ شُغِلَ قَلْبُهُ بِبِدْعَةٍ قَلَّدَ فِيهَا دِينَهُ رِجَالًا دُونَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ اكْتَفَى بِرَأْيِهِ فِيمَا لَا يَرَى الْهُدَى إِلَّا فِيهَا وَلَا يَرَى الضَّلَالَةَ إِلَّا بِتَرْكِهَا يَزْعُمُ أَنَّهُ أَخَذَهَا مِنْ الْقُرْآنِ وَهُوَ يَدْعُو إِلَى فِرَاقِ الْقُرْآنِ أَفَمَا كَانَ لِلْقُرْآنِ حَمَلَةٌ قَبْلَهُ وَقَبْلَ أَصْحَابِهِ يَعْمَلُونَ بِمُحْكَمِهِ وَيُؤْمِنُونَ بِمُتَشَابِهِهِ وَكَانُوا مِنْهُ عَلَى مَنَارٍ كَوَضَحِ الطَّرِيقِ فَكَانَ الْقُرْآنُ إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ إِمَامًا لِأَصْحَابِهِ وَكَانَ أَصْحَابُهُ أَئِمَّةً لِمَنْ بَعْدَهُمْ رِجَالٌ مَعْرُوفُونَ مَنْسُوبُونَ فِي الْبُلْدَانِ مُتَّفِقُونَ فِي الرَّدِّ عَلَى أَصْحَابِ الْأَهْوَاءِ مَعَ مَا كَانَ بَيْنَهُمْ مِنْ الِاخْتِلَافِ وَتَسَكَّعَ أَصْحَابُ الْأَهْوَاءِ بِرَأْيِهِمْ فِي سُبُلٍ مُخْتَلِفَةٍ جَائِرَةٍ عَنْ الْقَصْدِ مُفَارِقَةٍ لِلصِّرَاطِ الْمُسْتَقِيمِ فَتَوَّهَتْ بِهِمْ أَدِلَّاؤُهُمْ فِي مَهَامِهَ مُضِلَّةٍ فَأَمْعَنُوا فِيهَا مُتَعَسِّفِينَ فِي تِيهِهِمْ كُلَّمَا أَحْدَثَ لَهُمْ الشَّيْطَانُ بِدْعَةً فِي ضَلَالَتِهِمْ انْتَقَلُوا مِنْهَا إِلَى غَيْرِهَا لِأَنَّهُمْ لَمْ يَطْلُبُوا أَثَرَ السَّالِفِينَ وَلَمْ يَقْتَدُوا بِالْمُهَاجِرِينَ وَقَدْ ذُكِرَ عَنْ عُمَرَ أَنَّهُ قَالَ لِزِيَادٍ هَلْ تَدْرِي مَا يَهْدِمُ الْإِسْلَامَ زَلَّةُ عَالِمٍ وَجِدَالُ مُنَافِقٍ بِالْقُرْآنِ وَأَئِمَّةٌ مُضِلُّونَ اتَّقُوا اللَّهَ وَمَا حَدَثَ فِي قُرَّائِكُمْ وَأَهْلِ مَسَاجِدِكُمْ مِنْ الْغِيبَةِ وَالنَّمِيمَةِ وَالْمَشْيِ بَيْنَ النَّاسِ بِوَجْهَيْنِ وَلِسَانَيْنِ وَقَدْ ذُكِرَ أَنَّ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ ذَا وَجْهَيْنِ فِي النَّارِ يَلْقَاكَ صَاحِبُ الْغِيبَةِ فَيَغْتَابُ عِنْدَكَ مَنْ يَرَى أَنَّكَ تُحِبُّ غِيبَتَهُ وَيُخَالِفُكَ إِلَى صَاحِبِكَ فَيَأْتِيهِ عَنْكَ بِمِثْلِهِ فَإِذَا هُوَ قَدْ أَصَابَ عِنْدَ كُلِّ وَاحِدٍ مِنْكُمَا حَاجَتَهُ وَخَفِيَ عَلَى كُلِّ وَاحِدٍ مِنْكُمَا مَا أُتِيَ بِهِ عِنْدَ صَاحِبِهِ حُضُورُهُ عِنْدَ مَنْ حَضَرَهُ حُضُورُ الْإِخْوَانِ وَغَيْبَتُهُ عَلَى مَنْ غَابَ عَنْهُ غَيْبَةُ الْأَعْدَاءِ مَنْ حَضَرَ مِنْهُمْ كَانَتْ لَهُ الْأَثَرَةُ وَمَنْ غَابَ مِنْهُمْ لَمْ تَكُنْ لَهُ حُرْمَةٌ يَفْتِنُ مَنْ حَضَرَهُ بِالتَّزْكِيَةِ وَيَغْتَابُ مَنْ غَابَ عَنْهُ بِالْغِيبَةِ فَيَا لَعِبَادَ اللَّهِ أَمَا فِي الْقَوْمِ مِنْ رَشِيدٍ وَلَا مُصْلِحٍ يَقْمَعُ هَذَا عَنْ مَكِيدَتِهِ وَيَرُدُّهُ عَنْ عِرْضِ أَخِيهِ الْمُسْلِمِ بَلْ عَرَفَ هَوَاهُمْ فِيمَا مَشَى بِهِ إِلَيْهِمْ فَاسْتَمْكَنَ مِنْهُمْ وَأَمْكَنُوهُ مِنْ حَاجَتِهِ فَأَكَلَ بِدِينِهِ مَعَ أَدْيَانِهِمْ فَاللَّهَ اللَّهَ ذُبُّوا عَنْ حُرَمِ أَغْيَابِكُمْ وَكُفُّوا أَلْسِنَتَكُمْ عَنْهُمْ إِلَّا مِنْ خَيْرٍ وَنَاصِحُوا اللَّهَ فِي أُمَّتِكُمْ إِذْ كُنْتُمْ حَمَلَةَ الْكِتَابِ وَالسُّنَّةِ فَإِنَّ الْكِتَابَ لَا يَنْطِقُ حَتَّى يُنْطَقَ بِهِ وَإِنَّ السُّنَّةَ لَا تَعْمَلُ حَتَّى يُعْمَلَ بِهَا فَمَتَى يَتَعَلَّمُ الْجَاهِلُ إِذَا سَكَتَ الْعَالِمُ فَلَمْ يُنْكِرْ مَا ظَهَرَ وَلَمْ يَأْمُرْ بِمَا تُرِكَ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } اتَّقُوا اللَّهَ فَإِنَّكُمْ فِي زَمَانٍ رَقَّ فِيهِ الْوَرَعُ وَقَلَّ فِيهِ الْخُشُوعُ وَحَمَلَ الْعِلْمَ مُفْسِدُوهُ فَأَحَبُّوا أَنْ يُعْرَفُوا بِحَمْلِهِ وَكَرِهُوا أَنْ يُعْرَفُوا بِإِضَاعَتِهِ فَنَطَقُوا فِيهِ بِالْهَوَى لَمَّا أَدْخَلُوا فِيهِ مِنْ الْخَطَإِ وَحَرَّفُوا الْكَلِمَ عَمَّا تَرَكُوا مِنْ الْحَقِّ إِلَى مَا عَمِلُوا بِهِ مِنْ بَاطِلٍ فَذُنُوبُهُمْ ذُنُوبٌ لَا يُسْتَغْفَرُ مِنْهَا وَتَقْصِيرُهُمْ تَقْصِيرٌ لَا يُعْتَرَفُ بِهِ كَيْفَ يَهْتَدِي الْمُسْتَدِلُّ الْمُسْتَرْشِدُ إِذَا كَانَ الدَّلِيلُ حَائِرًا أَحَبُّوا الدُّنْيَا وَكَرِهُوا مَنْزِلَةَ أَهْلِهَا فَشَارَكُوهُمْ فِي الْعَيْشِ وَزَايَلُوهُمْ بِالْقَوْلِ وَدَافَعُوا بِالْقَوْلِ عَنْ أَنْفُسِهِمْ أَنْ يُنْسَبُوا إِلَى عَمَلِهِمْ فَلَمْ يَتَبَرَّءُوا مِمَّا انْتَفَوْا مِنْهُ وَلَمْ يَدْخُلُوا فِيمَا نَسَبُوا إِلَيْهِ أَنْفُسَهُمْ لِأَنَّ الْعَامِلَ بِالْحَقِّ مُتَكَلِّمٌ وَإِنْ سَكَتَ وَقَدْ ذُكِرَ أَنَّ اللَّهَ تَعَالَى يَقُولُ إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَنْظُرُ إِلَى هَمِّهِ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ لِي جَعَلْتُ صَمْتَهُ حَمْدًا وَوَقَارًا لِي وَإِنْ لَمْ يَتَكَلَّمْ وَقَالَ اللَّهُ تَعَالَى { مَثَلُ الَّذِينَ حُمِّلُوا التَّوْرَاةَ ثُمَّ لَمْ يَحْمِلُوهَا } لَمْ يَعْمَلُوا بِهَا { كَمَثَلِ الْحِمَارِ يَحْمِلُ أَسْفَارًا } كُتُبًا وَقَالَ { خُذُوا مَا آتَيْنَاكُمْ بِقُوَّةٍ } قَالَ الْعَمَلُ بِمَا فِيهِ وَلَا تَكْتَفُوا مِنْ السُّنَّةِ بِانْتِحَالِهَا بِالْقَوْلِ دُونَ الْعَمَلِ بِهَا فَإِنَّ انْتِحَالَ السُّنَّةِ دُونَ الْعَمَلِ بِهَا كَذِبٌ بِالْقَوْلِ مَعَ إِضَاعَةِ الْعَمَلِ وَلَا تَعِيبُوا بِالْبِدَعِ تَزَيُّنًا بِعَيْبِهَا فَإِنَّ فَسَادَ أَهْلِ الْبِدَعِ لَيْسَ بِزَائِدٍ فِي صَلَاحِكُمْ وَلَا تَعِيبُوهَا بَغْيًا عَلَى أَهْلِهَا فَإِنَّ الْبَغْيَ مِنْ فَسَادِ أَنْفُسِكُمْ وَلَيْسَ يَنْبَغِي لِلطَّبِيبِ أَنْ يُدَاوِيَ الْمَرْضَى بِمَا يُبَرِّئُهُمْ وَيُمْرِضُهُ فَإِنَّهُ إِذَا مَرِضَ اشْتَغَلَ بِمَرَضِهِ عَنْ مُدَاوَاتِهِمْ وَلَكِنْ يَنْبَغِي أَنْ يَلْتَمِسَ لِنَفْسِهِ الصِّحَّةَ لِيَقْوَى بِهِ عَلَى عِلَاجِ الْمَرْضَى فَلْيَكُنْ أَمْرُكُمْ فِيمَا تُنْكِرُونَ عَلَى إِخْوَانِكُمْ نَظَرًا مِنْكُمْ لِأَنْفُسِكُمْ وَنَصِيحَةً مِنْكُمْ لِرَبِّكُمْ وَشَفَقَةً مِنْكُمْ عَلَى إِخْوَانِكُمْ وَأَنْ تَكُونُوا مَعَ ذَلِكَ بِعُيُوبِ أَنْفُسِكُمْ أَعْنَى مِنْكُمْ بِعُيُوبِ غَيْرِكُمْ وَأَنْ يَسْتَطْعِمَ بَعْضُكُمْ بَعْضًا النَّصِيحَةَ وَأَنْ يَحْظَى عِنْدَكُمْ مَنْ بَذَلَهَا لَكُمْ وَقَبِلَهَا مِنْكُمْ وَقَدْ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَحِمَ اللَّهُ مَنْ أَهْدَى إِلَيَّ عُيُوبِي تُحِبُّونَ أَنْ تَقُولُوا فَيُحْتَمَلَ لَكُمْ وَإِنْ قِيلَ لَكُمْ مِثْلُ الَّذِي قُلْتُمْ غَضِبْتُمْ تَجِدُونَ عَلَى النَّاسِ فِيمَا تُنْكِرُونَ مِنْ ��ُمُورِهِمْ وَتَأْتُونَ مِثْلَ ذَلِكَ فَلَا تُحِبُّونَ أَنْ يُوجَدَ عَلَيْكُمْ اتَّهِمُوا رَأْيَكُمْ وَرَأْيَ أَهْلِ زَمَانِكُمْ وَتَثَبَّتُوا قَبْلَ أَنْ تَكَلَّمُوا وَتَعَلَّمُوا قَبْلَ أَنْ تَعْمَلُوا فَإِنَّهُ يَأْتِي زَمَانٌ يَشْتَبِهُ فِيهِ الْحَقُّ وَالْبَاطِلُ وَيَكُونُ الْمَعْرُوفُ فِيهِ مُنْكَرًا وَالْمُنْكَرُ فِيهِ مَعْرُوفًا فَكَمْ مِنْ مُتَقَرِّبٍ إِلَى اللَّهِ بِمَا يُبَاعِدُهُ وَمُتَحَبِّبٍ إِلَيْهِ بِمَا يُغْضِبُهُ عَلَيْهِ قَالَ اللَّهُ تَعَالَى { أَفَمَنْ زُيِّنَ لَهُ سُوءُ عَمَلِهِ فَرَآهُ حَسَنًا } الْآيَةَ فَعَلَيْكُمْ بِالْوُقُوفِ عِنْدَ الشُّبُهَاتِ حَتَّى يَبْرُزَ لَكُمْ وَاضِحُ الْحَقِّ بِالْبَيِّنَةِ فَإِنَّ الدَّاخِلَ فِيمَا لَا يَعْلَمُ بِغَيْرِ عِلْمٍ آثِمٌ وَمَنْ نَظَرَ لِلَّهِ نَظَرَ اللَّهُ لَهُ عَلَيْكُمْ بِالْقُرْآنِ فَأْتَمُّوا بِهِ وَأُمُّوا بِهِ وَعَلَيْكُمْ بِطَلَبِ أَثَرِ الْمَاضِينَ فِيهِ وَلَوْ أَنَّ الْأَحْبَارَ وَالرُّهْبَانَ لَمْ يَتَّقُوا زَوَالَ مَرَاتِبِهِمْ وَفَسَادَ مَنْزِلَتِهِمْ بِإِقَامَةِ الْكِتَابِ وَتِبْيَانِهِ مَا حَرَّفُوهُ وَلَا كَتَمُوهُ وَلَكِنَّهُمْ لَمَّا خَالَفُوا الْكِتَابَ بِأَعْمَالِهِمْ الْتَمَسُوا أَنْ يَخْدَعُوا قَوْمَهُمْ عَمَّا صَنَعُوا مَخَافَةَ أَنْ تَفْسُدَ مَنَازِلُهُمْ وَأَنْ يَتَبَيَّنَ لِلنَّاسِ فَسَادُهُمْ فَحَرَّفُوا الْكِتَابَ بِالتَّفْسِيرِ وَمَا لَمْ يَسْتَطِيعُوا تَحْرِيفَهُ كَتَمُوهُ فَسَكَتُوا عَنْ صَنِيعِ أَنْفُسِهِمْ إِبْقَاءً عَلَى مَنَازِلِهِمْ وَسَكَتُوا عَمَّا صَنَعَ قَوْمُهُمْ مُصَانَعَةً لَهُمْ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } بَلْ مَالَئُوا عَلَيْهِ وَرَقَّقُوا لَهُمْ فِيهِ","trj":"Telah mengabarkan kepada kami [Abdul Malik bin Sulaiman Abu Abdur Rahman Al `Anthaki] dari ['Abbad bin 'Abbad Al Khawwash As Syami Abu 'Utbah] ia berkata: \"Perhatian, gunakanlah akal, karena akal sebuah nikmat. Berapa banyak orang berakal menyibukkan hatinya untuk memperdalam hal-hal yang membahayakan dirinya daripada memanfaatkan apa yang dibutuhkannya, sehingga ia lupa hal itu. Diantara keutamaan akal seseorang adalah meninggalkan perhatian terhadap hal-hal yang tidak perlu sehingga keutamaan akalnya tidak menjadi bencana baginya, yaitu ia meninggalkan persaingan dengan orang yang lebih rendah amal shalihnya, atau seseorang yang menyibukkan hatinya dengan bid'ah, yang ia sekedar mengikuti orang dalam urusan agamanya tanpa mengikuti para sahabat Rasulullah shalallahu 'alahi wa sallam, atau ia hanya merasa cukup dengan pendapatnya sendiri, yang ia tidak melihat petunjuk kecuali kepada akalnya, dan tidak melihat kesesatan kecuali meninggalkannya dengan anggapan bahwa ia mengambilnya dari Al qur`an, padahal ia menyerukan untuk meninggalkan Al qur`an. Bukankah Al qur`an mempunyai pengemban-pengemban sebelumnya, yaitu para pembelanya yang mengamalkan ayat-ayat yang muhkam dan mengimani ayat-ayat yang mutasyabih? Mereka berada di menara layaknya cahaya jalan, Al Quran imam Rasulullah shalallahu'alahi wa sallam, sedang Rasulullah shallahu 'alaihi wa sallam imam para sahabatnya, dan para sahabat adalah imam orang-orang setelah mereka, yaitu orang-orang yang sudah dikenal kebaikannya, mereka menjadi barometer di negeri-negeri mereka yang sepakat menolak para pengagung hawa nafsu walaupun diantara mereka terdapat perselisihan pendapat. Para pengagum hawa nafsu meraba-raba dengan pendapat mereka, yaitu dengan cara yang bermacam-macam, yang melenceng dari tujuan karena memisahkan diri dari jalan yang lurus. Petunjuk mereka menyesatkan mereka sendiri dalam misteri padang pasir yang menyesatkan. Mereka konsentrasi melihat petunjuk jalan dengan penuh kebingungan dalam kesesatannya. Setiap kali setan membuat satu bid'ah dalam kesesatan, mereka berpindah dari satu bid'ah ke bid'ah lain, karena mereka tidak mencari petunjuk para pendahulu dan juga tidak mengikuti jejak kaum muhajirin. Telah disebutkan dalam satu riwayat dari Umar radliallahu 'anhu bahwa ia berkata kepada Ziad: 'Tahukah kamu apa yang (menyebabkan) kehancuran Islam? ', Jawabnya karena kesalahan orang berilmu, perdebatan orang munafik terhadap Al Qur`an dan para imam yang sesat'. Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan waspadailah apa yang terjadi pada ulama kamu dan pengisi masjid-masjid kamu dari perbuatan ghibah, namimah dan berjalan diantara manusia dengan dua wajah dan dua lisan. Dalam satu riwayat disebutkan barangsiapa mempunyai dua wajah di dunia, ia mempunyai dua wajah di neraka. Jika tukang ghibah menemuimu, ia menggunjing orang yang kamu senangi untuk di gunjing, lalu ia berpaling darimu untuk mendatangi temanmu dan melakukan hal yang sama. Jika ia telah memperoleh apa yang ia butuhkan dari setiap kalian, dan menyembunyikan sesuatu dari salah satu (dari) kalian, ia tidak memberi kabar kepada sahabatmu yang lain. Kedatangannya kepada orang yang didatanginya adalah seperti datangnya seorang teman, namun kepergiannya dari teman yang ditinggalkan bagaikan kepergian dari seorang musuh. Siapa saja yang menemuinya, ia dapatkan kemuliaan, sebaliknya siapa yang tidak ditemuinya, tidak ia dapatkan kehormatan, ia menipu orang yang didatanginya dengan penghargaan-penghargaan, dan menggunjing orang yang tidak ditemuinya dengan ghibah mematikan. Wahai hamba-hamba Allah subhanallahu wa ta'ala, tidakkah suatu kaum muncul penunjuk jalan dan reformis, yang ia sanggup mengekang orang seperti ini dari tipu dayanya, dan mengajaknya untuk mempertahankan kehormatan saudaranya semuslim?, bahkan kalau bisa memberitahu mereka niyat orang seperti ini saat datang menemui mereka, yang ia bertindak sekedar ingin memperoleh keperluannya sehingga mereka mempersilahkan, yang ujungnya ia mencaplok agamanya sekaligus agama mereka? Ya Allah, Ya Allah! Pertahankanlah kehormatan kamu, hentikanlah lisanmu (dari menggunjing) mereka kecuali kebaikan semata. Tolong kalian saling mengingatkan untuk berbakti kepada Allah khususnya terhadap umatmu, karena kamu adalah pengemban Al Kitab (Al Qur`an) dan sunah,. Al Kitab tidak berbicara hingga ia dibicarakan, dan sunnah tidak sanggup mengejawantahkan hingga ia diejawantahkan. Bilamana orang bodoh belajar, namun orang alim diam tidak memungkiri apa yang nampak dan tidak memerintahkan apa yang ditinggalkan', bukankah Allah subhanallahu wa ta'ala telah mengambil perjanjian dari orang-orang yang diberikan Al Kitab kepada mereka untuk menjelaskannya kepada manusia dan tidak menyembunyikannya?. Bertakwalah kepada Allah subhanallahu wa ta'ala, karena kamu berada pada zaman menipisnya sifat wara' dan kurangnya kekhusyu'an, dan para pengemban ilmu adalah para perusaknya. Mereka begitu marah jika dikenal sebagai orang-orang yang menghilangkannya, mereka membicarakannya dengan hawa nafsu ketika mengikutsertakan kesalahan dalam ilmu, dan memutarbalikkan perkataan dari kebenaran yang mereka tinggalkan, lantas mereka belokkan menuju kebatilan yang mereka kerjakan. Dosa mereka adalah dosa yang tidak diampuni dan kelalaian mereka adalah kelalaian yang tidak bisa dibenarkan, bagaimana orang yang mencari petunjuk dan tuntunan mendapatkan petunjuk apabila petunjuknya sendiri membingungkan, mereka cinta dunia dan benci terhadap kebahagiaan penduduknya yang memperoleh kedudukan tinggi, lantas mereka menyertai dalam kehidupan dan menyelisihi mereka dengan perkataan, dan mempertahankan diri mereka dengan perkataan, agar mereka dihubung-hubungkan dengan kebaikan mereka. Mereka sama sekali tidak bersih dari kotoran yang mereka hilangkan, dan belum memenuhi kriteria untuk dihargai amal mereka, sebab orang yang benar-benar beramal shalih secara tidak langsung ia ia telah bicara sekalipun dia diam. Dan telah diberitakan bahwa Allah Ta'ala berfirman; Aku tidak menerima semua semua perkataan orang bijak, akan tetapi Aku melihat kepada kecenderungan dan niyat baiknya untuk-Ku. Sebab siapa yang hasrat dan niyatnya untuk-Ku, Aku jadikan diamnya terpuji dan berwibawa, walaupun ia tidak berbicara. Allah subhanallahu wa ta'ala berfirman: \"MATSALULLADZINA HUMMILUT TAURATA TSUMMA LAM YAHMILUUHA KAMATSALIL HIMARI YAHMILUL ASFARA\" (Perumpamaan orang-orang yang dipikulkan kepadanya Taurat, kemudian mereka tidak memikulnya (tidak mengerjakannya) adalah seperti keledai yang membawa kitab-kitab yang tebal) -Qs. Al Jumu'ah: 5-, Allah subhanallahu wa ta'ala juga berfirman: \"KHUDZU MAA ATAINAAKUM BI QUWWAH\" (Peganglah teguh-teguh apa yang telah kami berikan kepadamu) -Qs. Al Baqarah: 63, 93, 171-, ia berkata: 'Maksudnya mengerjakan isi yang terkandung padanya, dan tidak mencukupkan sunnah hanya dengan ucapan tanpa pengalaman. Karena pensifatan sunnah dengan perkataan tanpa perbuatan adalah dusta dengan perkataan, yang sekaligus menghilangkan ilmu. Dan janganlah kamu mencela bid`ah sekedar untuk bungkus keindahanmu dengan meneropong aib-aibnya, karena kerusakan penganut bid`ah tidak menambah kesalehanmu, dan janganlah kamu mencelanya karena dorongan diskriminatif terhadap penganutnya, karena diskriminasi adalah kerusakan dirimu sendiri, sebab tidak selayaknya dokter mengobati pasien dengan obat yang berpotensi menyembuhkan penyakit namun obat itu juga berpotensi mendatangkan penyakit baru. Karena apabila dokter itu sakit, ia sibuk dengan penyakitnya dan lupa mengobati mereka. Akan tetapi selayaknya ia mencari kesehatan untuk dirinya agar ia dapat mengobati para pasien. Hendaklah saat engkau melihat masalah yang menimpa saudara-saudaramu dan hatimu \"kurang sreg\", sebagaimana engkau melihat jika terjadi pada dirimu sendiri dan sebagai \"peringatan\" Tuhanmu terhadapmu, serta rasa kasihanmu kepada saudara-saudara kamu. Walaupun dalam hal itu lebih baik kamu lebih peduli terhadap aib diri kamu sendiri dari pada aib orang lain, dan lakukan saling menasehati satu sama lain diantara kamu, dan hendaklah yang mengorbankan nasehat itu merasa beruntung dan kamu menerimanya. Umar bin Al Khatthab radliallahu 'anhu berkata: 'Semoga Allah subhanallahu wa ta'ala melimpahkan rahmat kepada orang yang menunjukkan aib-aibku kepadaku'. Kamu suka berkata dan orang yang mendengarmu menahan diri demi kebaikanmu, padahal jika dikatakan kepada kamu perkataan yang sama seperti yang kamu katakan, kamu jengkel. Kamu mendapatkan hal-hal yang menjengkelkanmu, sebaliknya kamu mengerjakan apa yang mereka kerjakan, apakah kamu tidak suka dipersalahkan? ', Pikir ulanglah pendapatmu dan pendapat orang-orang yang sezaman denganmu, Selidikilah dahulu sebuah berita sebelum kalian berbicara dan belajarlah sebelum kalian beramal. Karena nanti akan datang suatu zaman yang saat itu yang benar bercampur dengan yang batil, dan yang ma'ruf (baik) menjadi mungkar dan yang mungkar menjadi ma'ruf. Betapa banyak orang yang mendekatkan diri kepada Allah subhanallahu w ta'ala namun dengan hal-hal yang justru menjauhkan dariNya, dan mencari cintaNya dengan hal-hal yang membuatNya murka. Allah subhanallahu wa ta'ala berfirman: \"AFAMAN ZUYYINA LAHU SUU`U 'MALIHI FA RA`AHU HASANA\" (Maka apabila orang yang dijadikan (syaitan) menganggap baik pekerjaannya yang buruk lalu ia meyakini pekerjaan itu baik (sama dengan orang yang tidak ditipu syaitan)? -Qs. Al Fathir: 8-, hendaklah kamu berhenti dari hal-hal yang syubhat sehingga nampak bagi kamu kebenaran yang jelas disertai keterangan, karena orang yang mengintervensi perkara yang ia tidak tahu tanpa ilmu, ia berdosa, dan barangsiapa yang menyelidiki dengan niat ikhlash karena Allah, Allah subhanallahu wa ta'ala akan melihatnya. Hendaklah kamu berpegang teguh dengan Al Qur`an, jadikanlah ia imam dan ajaklah (manusia) untuk menjadikan Al Qur`an sebagai imam. Hendaknya kamu mencari jejak-jejak para pendahulu padanya. Seandainya para ahbar (pendeta yahudi) dan para rahib (pendeta Nashrani) tidak takut kehilangan martabat mereka dan kerusakan kedudukannya dengan menegakkan Al Kitab dan penjelasannya, niscaya mereka tidak akan menyelewengkan dan menyembunyikannya, akan tetapi mereka ketika menentang Al Kitab dengan perbuatan mereka, mereka berusaha mencari cara menipu kaumnya karena perbuatan yang mereka lakukan sendiri, karena mereka khawatir kedudukan mereka dirobohkan, dan manusia memperoleh kejelasan kerusakan mereka, lalu mereka selewengkan Al Kitab dengan tafsir menyeleweng, dan apa yang mereka tidak bisa selewengkan, mereka sembunyikan, lalu mereka diam terhadap perbuatan mereka sendiri karena dorongan untuk mempertahankan kedudukan mereka, dan diam terhadap apa yang diperbuat oleh kaumnya sambil berpura-pura. Sedang Allah subhanallahu wa ta'ala telah mengambil perjanjian dengan orang-orang yang di berikan Al Kitab agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya, akan tetapi mereka justru cenderung kepadanya dan mengajak manusia menganggap enteng masalah itu. "}],"48:18":[{"p":"Tirmidzi","n":1517,"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِفِي قَوْلِهِ تَعَالَى{ لَقَدْ رَضِيَ اللَّهُ عَنْ الْمُؤْمِنِينَ إِذْ يُبَايِعُونَكَ تَحْتَ الشَّجَرَةِ }قَالَ جَابِرٌ بَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَنْ لَا نَفِرَّ وَلَمْ نُبَايِعْهُ عَلَى الْمَوْتِقَالَ وَفِي الْبَاب عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ وَابْنِ عُمَرَ وَعُبَادَةَ وَجَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عِيسَى بْنِ يُونُسَ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ قَالَ جَابِرُ بْنُ عَبْدِ اللَّهِ وَلَمْ يُذْكَرْ فِيهِ أَبُو سَلَمَةَ","trj":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi] berkata, telah menceritakan kepada kami [Isa bin Yunus] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Jabir bin Abdullah] tentang firman Allah: '(Sesungguhnya Allah telah ridha terhadap orang-orang mu'min ketika mereka berjanji setia kepadamu di bawah pohon) ' -Qs. Al Fath: 18- Jabir berkata, \"Kami membaiat Rasulullah shallallahu 'alaihi wasallam untuk tidak lari (dari medan perang), bukan baiat untuk mati.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Salamah Ibnul Akwa', Ibnu Umar, Ubadah dan Jarir bin Abdullah.\" Abu Isa berkata, \"Hadits ini diriwayatkan dari Isa bin Yunus dari Al Auza'I, dari Yahya bin Abu Katsir berkata; Jabir bin Abdullah berkata. Dan dalam hadits tersebut tidak disebut nama Abu Salamah.\""}],"48:24":[{"p":"Muslim","n":3139,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَبُو عَامِرٍ الْعَقَدِيُّ كِلَاهُمَا عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ وَهَذَا حَدِيثُهُ أَخْبَرَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا عِكْرِمَةُ وَهُوَ ابْنُ عَمَّارٍ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ حَدَّثَنِي أَبِي قَالَقَدِمْنَا الْحُدَيْبِيَةَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ أَرْبَعَ عَشْرَةَ مِائَةً وَعَلَيْهَا خَمْسُونَ شَاةً لَا تُرْوِيهَا قَالَ فَقَعَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى جَبَا الرَّكِيَّةِ فَإِمَّا دَعَا وَإِمَّا بَصَقَ فِيهَا قَالَ فَجَاشَتْ فَسَقَيْنَا وَاسْتَقَيْنَا قَالَ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَانَا لِلْبَيْعَةِ فِي أَصْلِ الشَّجَرَةِ قَالَ فَبَايَعْتُهُ أَوَّلَ النَّاسِ ثُمَّ بَايَعَ وَبَايَعَ حَتَّى إِذَا كَانَ فِي وَسَطٍ مِنْ النَّاسِ قَالَ بَايِعْ يَا سَلَمَةُ قَالَ قُلْتُ قَدْ بَايَعْتُكَ يَا رَسُولَ اللَّهِ فِي أَوَّلِ النَّاسِ قَالَ وَأَيْضًا قَالَ وَرَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَزِلًا يَعْنِي لَيْسَ مَعَهُ سِلَاحٌ قَالَ فَأَعْطَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَفَةً أَوْ دَرَقَةً ثُمَّ بَايَعَ حَتَّى إِذَا كَانَ فِي آخِرِ النَّاسِ قَالَ أَلَا تُبَايِعُنِي يَا سَلَمَةُ قَالَ قُلْتُ قَدْ بَايَعْتُكَ يَا رَسُولَ اللَّهِ فِي أَوَّلِ النَّاسِ وَفِي أَوْسَطِ النَّاسِ قَالَ وَأَيْضًا قَالَ فَبَايَعْتُهُ الثَّالِثَةَ ثُمَّ قَالَ لِي يَا سَلَمَةُ أَيْنَ حَجَفَتُكَ أَوْ دَرَقَتُكَ الَّتِي أَعْطَيْتُكَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ لَقِيَنِي عَمِّي عَامِرٌ عَزِلًا فَأَعْطَيْتُهُ إِيَّاهَا قَالَ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّكَ كَالَّذِي قَالَ الْأَوَّلُ اللَّهُمَّ أَبْغِنِي حَبِيبًا هُوَ أَحَبُّ إِلَيَّ مِنْ نَفْسِي ثُمَّ إِنَّ الْمُشْرِكِينَ رَاسَلُونَا الصُّلْحَ حَتَّى مَشَى بَعْضُنَا فِي بَعْضٍ وَاصْطَلَحْنَا قَالَ وَكُنْتُ تَبِيعًا لِطَلْحَةَ بْنِ عُبَيْدِ اللَّهِ أَسْقِي فَرَسَهُ وَأَحُسُّهُ وَأَخْدِمُهُ وَآكُلُ مِنْ طَعَامِهِ وَتَرَكْتُ أَهْلِي وَمَالِي مُهَاجِرًا إِلَى اللَّهِ وَرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَلَمَّا اصْطَلَحْنَا نَحْنُ وَأَهْلُ مَكَّةَ وَاخْتَلَطَ بَعْضُنَا بِبَعْضٍ أَتَيْتُ شَجَرَةً فَكَسَحْتُ شَوْكَهَا فَاضْطَجَعْتُ فِي أَصْلِهَا قَالَ فَأَتَانِي أَرْبَعَةٌ مِنْ الْمُشْرِكِينَ مِنْ أَهْلِ مَكَّةَ فَجَعَلُوا يَقَعُونَ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبْغَضْتُهُمْ فَتَحَوَّلْتُ إِلَى شَجَرَةٍ أُخْرَى وَعَلَّقُوا سِلَاحَهُمْ وَاضْطَجَعُوا فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ نَادَى مُنَادٍ مِنْ أَسْفَلِ الْوَادِي يَا لِلْمُهَاجِرِينَ قُتِلَ ابْنُ زُنَيْمٍ قَالَ فَاخْتَرَطْتُ سَيْفِي ثُمَّ شَدَدْتُ عَلَى أُولَئِكَ الْأَرْبَعَةِ وَهُمْ رُقُودٌ فَأَخَذْتُ سِلَاحَهُمْ فَجَعَلْتُهُ ضِغْثًا فِي يَدِي قَالَ ثُمَّ قُلْتُ وَالَّذِي كَرَّمَ وَجْهَ مُحَمَّدٍ لَا يَرْفَعُ أَحَدٌ مِنْكُمْ رَأْسَهُ إِلَّا ضَرَبْتُ الَّذِي فِيهِ عَيْنَاهُ قَالَ ثُمَّ جِئْتُ بِهِمْ أَسُوقُهُمْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَجَاءَ عَمِّي عَامِرٌ بِرَجُلٍ مِنْ الْعَبَلَاتِ يُقَالُ لَهُ مِكْرَزٌ يَقُودُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى فَرَسٍ مُجَفَّفٍ فِي سَبْعِينَ مِنْ الْمُشْرِكِينَ فَنَظَرَ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ دَعُوهُمْ يَكُنْ لَهُمْ بَدْءُ الْفُجُورِ وَثِنَاهُ فَعَفَا عَنْهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْزَلَ اللَّهُ{ وَهُوَ الَّذِي كَفَّ أَيْدِيَهُمْ عَنْكُمْ وَأَيْدِيَكُمْ عَنْهُمْ بِبَطْنِ مَكَّةَ مِنْ بَعْدِ أَنْ أَظْفَرَكُمْ عَلَيْهِمْ }الْآيَةَ كُلَّهَا قَالَ ثُمَّ خَرَجْنَا رَاجِعِينَ إِلَى الْمَدِينَةِ فَنَزَلْنَا مَنْزِلًا بَيْنَنَا وَبَيْنَ بَنِي لَحْيَانَ جَبَلٌ وَهُمْ الْمُشْرِكُونَ فَاسْتَغْفَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَنْ رَقِيَ هَذَا الْجَبَلَ اللَّيْلَةَ كَأَنَّهُ طَلِيعَةٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابِهِ قَالَ سَلَمَةُ فَرَقِيتُ تِلْكَ اللَّيْلَةَ مَرَّتَيْنِ أَوْ ثَلَاثًا ثُمَّ قَدِمْنَا الْمَدِينَةَ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِظَهْرِهِ مَعَ رَبَاحٍ غُلَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ وَخَرَجْتُ مَعَهُ بِفَرَسِ طَلْحَةَ أُنَدِّيهِ مَعَ الظَّهْرِ فَلَمَّا أَصْبَحْنَا إِذَا عَبْدُ الرَّحْمَنِ الْفَزَارِيُّ قَدْ أَغَارَ عَلَى ظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَاقَهُ أَجْمَعَ وَقَتَلَ رَاعِيَهُ قَالَ فَقُلْتُ يَا رَبَاحُ خُذْ هَذَا الْفَرَسَ فَأَبْلِغْهُ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ وَأَخْبِرْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْمُشْرِكِينَ قَدْ أَغَارُوا عَلَى سَرْحِهِ قَالَ ثُمَّ قُمْتُ عَلَى أَكَمَةٍ فَاسْتَقْبَلْتُ الْمَدِينَةَ فَنَادَيْتُ ثَلَاثًا يَا صَبَاحَاهْ ثُمَّ خَرَجْتُ فِي آثَارِ الْقَوْمِ أَرْمِيهِمْ بِالنَّبْلِ وَأَرْتَجِزُ أَقُولُ أَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِفَأَلْحَقُ رَجُلًا مِنْهُمْ فَأَصُكُّ سَهْمًا فِي رَحْلِهِ حَتَّى خَلَصَ نَصْلُ السَّهْمِ إِلَى كَتِفِهِ قَالَ قُلْتُ خُذْهَا وَأَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِقَالَ فَوَاللَّهِ مَا زِلْتُ أَرْمِيهِمْ وَأَعْقِرُ بِهِمْ فَإِذَا رَجَعَ إِلَيَّ فَارِسٌ أَتَيْتُ شَجَرَةً فَجَلَسْتُ فِي أَصْلِهَا ثُمَّ رَمَيْتُهُ فَعَقَرْتُ بِهِ حَتَّى إِذَا تَضَايَقَ الْجَبَلُ فَدَخَلُوا فِي تَضَايُقِهِ عَلَوْتُ الْجَبَلَ فَجَعَلْتُ أُرَدِّيهِمْ بِالْحِجَارَةِ قَالَ فَمَا زِلْتُ كَذَلِكَ أَتْبَعُهُمْ حَتَّى مَا خَلَقَ اللَّهُ مِنْ بَعِيرٍ مِنْ ظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا خَلَّفْتُهُ وَرَاءَ ظَهْرِي وَخَلَّوْا بَيْنِي وَبَيْنَهُ ثُمَّ اتَّبَعْتُهُمْ أَرْمِيهِمْ حَتَّى أَلْقَوْا أَكْثَرَ مِنْ ثَلَاثِينَ بُرْدَةً وَثَلَاثِينَ رُمْحًا يَسْتَخِفُّونَ وَلَا يَطْرَحُونَ شَيْئًا إِلَّا جَعَلْتُ عَلَيْهِ آرَامًا مِنْ الْحِجَارَةِ يَعْرِفُهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ حَتَّى أَتَوْا مُتَضَايِقًا مِنْ ثَنِيَّةٍ فَإِذَا هُمْ قَدْ أَتَاهُمْ فُلَانُ بْنُ بَدْرٍ الْفَزَارِيُّ فَجَلَسُوا يَتَضَحَّوْنَ يَعْنِي يَتَغَدَّوْنَ وَجَلَسْتُ عَلَى رَأْسِ قَرْنٍ قَالَ الْفَزَارِيُّ مَا هَذَا الَّذِي أَرَى قَالُوا لَقِينَا مِنْ هَذَا الْبَرْحَ وَاللَّهِ مَا فَارَقَنَا مُنْذُ غَلَسٍ يَرْمِينَا حَتَّى انْتَزَعَ كُلَّ شَيْءٍ فِي أَيْدِينَا قَالَ فَلْيَقُمْ إِلَيْهِ نَفَرٌ مِنْكُمْ أَرْبَعَةٌ قَالَ فَصَعِدَ إِلَيَّ مِنْهُمْ أَرْبَعَةٌ فِي الْجَبَلِ قَالَ فَلَمَّا أَمْكَنُونِي مِنْ الْكَلَامِ قَالَ قُلْتُ هَلْ تَعْرِفُونِي قَالُوا لَا وَمَنْ أَنْتَ قَالَ قُلْتُ أَنَا سَلَمَةُ بْنُ الْأَكْوَعِ وَالَّذِي كَرَّمَ وَجْهَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَطْلُبُ رَجُلًا مِنْكُمْ إِلَّا أَدْرَكْتُهُ وَلَا يَطْلُبُنِي رَجُلٌ مِنْكُمْ فَيُدْرِكَنِي قَالَ أَحَدُهُمْ أَنَا أَظُنُّ قَالَ فَرَجَعُوا فَمَا بَرِحْتُ مَكَانِي حَتَّى رَأَيْتُ فَوَارِسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَلَّلُونَ الشَّجَرَ قَالَ فَإِذَا أَوَّلُهُمْ الْأَخْرَمُ الْأَسَدِيُّ عَلَى إِثْرِهِ أَبُو قَتَادَةَ الْأَنْصَارِيُّ وَعَلَى إِثْرِهِ الْمِقْدَادُ بْنُ الْأَسْوَدِ الْكِنْدِيُّ قَالَ فَأَخَذْتُ بِعِنَانِ الْأَخْرَمِ قَالَ فَوَلَّوْا مُدْبِرِينَ قُلْتُ يَا أَخْرَمُ احْذَرْهُمْ لَا يَقْتَطِعُوكَ حَتَّى يَلْحَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ قَالَ يَا سَلَمَةُ إِنْ كُنْتَ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَتَعْلَمُ أَنَّ الْجَنَّةَ حَقٌّ وَالنَّارَ حَقٌّ فَلَا تَحُلْ بَيْنِي وَبَيْنَ الشَّهَادَةِ قَالَ فَخَلَّيْتُهُ فَالْتَقَى هُوَ وَعَبْدُ الرَّحْمَنِ قَالَ فَعَقَرَ بِعَبْدِ الرَّحْمَنِ فَرَسَهُ وَطَعَنَهُ عَبْدُ الرَّحْمَنِ فَقَتَلَهُ وَتَحَوَّلَ عَلَى فَرَسِهِ وَلَحِقَ أَبُو قَتَادَةَ فَارِسُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَبْدِ الرَّحْمَنِ فَطَعَنَهُ فَقَتَلَهُ فَوَالَّذِي كَرَّمَ وَجْهَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَتَبِعْتُهُمْ أَعْدُو عَلَى رِجْلَيَّ حَتَّى مَا أَرَى وَرَائِي مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا غُبَارِهِمْ شَيْئًا حَتَّى يَعْدِلُوا قَبْلَ غُرُوبِ الشَّمْسِ إِلَى شِعْبٍ فِيهِ مَاءٌ يُقَالُ لَهُ ذَو قَرَدٍ لِيَشْرَبُوا مِنْهُ وَهُمْ عِطَاشٌ قَالَ فَنَظَرُوا إِلَيَّ أَعْدُو وَرَاءَهُمْ فَخَلَّيْتُهُمْ عَنْهُ يَعْنِي أَجْلَيْتُهُمْ عَنْهُ فَمَا ذَاقُوا مِنْهُ قَطْرَةً قَالَ وَيَخْرُجُونَ فَيَشْتَدُّونَ فِي ثَنِيَّةٍ قَالَ فَأَعْدُو فَأَلْحَقُ رَجُلًا مِنْهُمْ فَأَصُكُّهُ بِسَهْمٍ فِي نُغْضِ كَتِفِهِ قَالَ قُلْتُ خُذْهَا وَأَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِقَالَ يَا ثَكِلَتْهُ أُمُّ��ُ أَكْوَعُهُ بُكْرَةَ قَالَ قُلْتُ نَعَمْ يَا عَدُوَّ نَفْسِهِ أَكْوَعُكَ بُكْرَةَ قَالَ وَأَرْدَوْا فَرَسَيْنِ عَلَى ثَنِيَّةٍ قَالَ فَجِئْتُ بِهِمَا أَسُوقُهُمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَلَحِقَنِي عَامِرٌ بِسَطِيحَةٍ فِيهَا مَذْقَةٌ مِنْ لَبَنٍ وَسَطِيحَةٍ فِيهَا مَاءٌ فَتَوَضَّأْتُ وَشَرِبْتُ ثُمَّ أَتَيْتُ رَسُولَ اللّ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Hasyim Ibnul Qasim]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abu Amir Al Aqadi] keduanya dari [Ikrimah bin Ammar]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdullah bin 'Abdurrahman Ad Darimi] dan ini adalah haditsnya. Telah mengabarkan kepada kami [Abu Ali Al Hanafi Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Ikrimah] -yaitu Ibnu Ammar- telah menceritakan kepadaku [Iyas bin Salamah] dari [ayahnya] dia berkata, \"Kami pernah ikut perang bersama Rasulullah shallallahu 'alaihi wasallam ke Hudaibiyah, pada saat itu kami berjumlah seribu empat ratus orang, dan kami hanya membawa lima puluh ekor kambing, sehingga air susu kambing sejumlah itu tidak cukup untuk kami minum. Setelah itu, Rasulullah shallallahu 'alaihi wasallam duduk di dekat sumur sambil berdo'a atau meludahinya. Berkat do'a yang dibacakan Rasulullah shallallahu 'alaihi wasallam kepada air susu kambing tersebut, maka kami semua dapat meminum air susu dengan sepuas-puasnya. Kemudian Rasulullah shallallahu 'alaihi wasallam mengajak kami untuk berbai'at kepada beliau di bawah pohon. Aku berbaiat kepada Rasulullah shallallahu 'alaihi wasallam pada rombongan pertama. Kemudian beliau terus menerima pembaiatan dari para sahabat yang hadir pada saat itu. Ketika sampai pada rombongan yang berada di tengah, Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Barbaiatlah wahai Salamah.\" Aku pun berkata kepada beliau, \"Aku telah berbaiat kepada anda pada rombongan pertama wahai Rasulullah.\" Namun beliau justru bersabda kepadaku: \"Berbaiatlah lagi waahi Salamah.\" Aku akhirnya menuruti permintaan beliau. Ketika beliau melihat aku tidak membawa senjata sama sekali, maka Rasulullah shallallahu 'alaihi wasallam memberikan tameng atau perisai kepadaku. Selanjutnya beliau menerima pembaiatan lagi dari rombongan yang terakhir. Pada saat itu, beliau kembali bertanya kepada aku: \"Mengapa kamu tidak ikut berbaiat kepadaku wahai Salamah?\" Aku menjawab, \"Aku telah berbaiat kepadamu wahai Rasulullah, bahkan tadi aku telah berbaiat kepada anda hingga dua kali, yaitu pada rombongan pertama dan rombongan pertengahan.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berbaiatlah sekali lagi wahai Salamah!\" Akhirnya aku ikut berbaiat kepada beliau untuk yang ketiga kalinya. Selesai berbaiat, Rasulullah shallallahu 'alaihi wasallam bertanya kepadaku: \"Wahai Salamah, mana tameng dan perisai yang aku berikan kepadamu?\" aku mencoba menjelaskan pertanyaan beliau, \"Wahai Rasulullah, tadi aku bertemu dengan pamanku, Amir, ternyata dia juga tidak mempunyai senjata sama sekali, maka tameng itu aku berikan kepadanya.\" Mendengar penjelasan itu, Rasulullah shallallahu 'alaihi wasallam tersenyum sambil bersabda: \"Sesungguhnya kamu seperti apa yang dikatakan oleh orang-orang dahulu, 'Ya Allah, ya Rabbku, berikanlah aku seorang kekasih yang lebih aku cintai daripada diriku sendiri'.\" Beberapa hari kemudian, kaum Musyrikin mengajak kami berdamai dengan cara mengirim kurir terlebih dahulu. Setelah mengalami proses yang tidak begitu lama, akhirnya kami sepakat untuk berdamai. Dahulu aku adalah pelayan Thalhah bin Ubaidillah, tugasku memberi minum kuda dan memandikannya. Sebagai imbalan dari pelayanannya tersebut, aku mendapatkan makan darinya. Aku memang bertekat untuk meninggalkan keluarga dan hartaku untuk berhijrah di jalan Allah dan Rasul-Nya. Ketika kesepakatan perjanjian damai antara kami dengan penduduk Makkah telah terjalin, hingga kami sudah bisa saling berbaur, maka suatu hari aku pergi menuju pepohonan untuk beristirahat di bawahnya. Pada saat berbaring di bawah pohon itulah, tiba-tiba datang empat orang Musyrikin dari peduduk kota Makkah yang tengah menggunjing Rasulullah shallallahu 'alaihi wasallam hingga membuat aku geram terhadap mereka. Lalu aku pidah ke batang pohon lainnya sambil melihat mereka menggantungkan senjatanya dan setelah itu mereka tertidur. Pada saat itulah, tiba-tiba terdengar suara orang yang menyeru dari dasar jurang, \"Hai kaum Muhajirin, Ibnu Zunaim telah terbunuh.\" Seketika itu juga aku cabut sambil mendatangi keempat orang musyrikin yang tengah tidur tersebut, aku ambil senjata mereka.\" Salamah melanjutkan, \"Setelah itu aku berkata kepada mereka, 'Demi dzat yang telah memuliakan wajah Muhammad, barangsiapa ada di antara kalian berani mengangkat kepalanya, maka akan kutebas lehernya.' Akhirnya keempat orang kafir Qurasiy tersebut aku giring ke hadapan Rasulullah shallallahu 'alaihi wasallam. Pada saat yang bersamaan aku melihat Amir, paman aku. Ternyata dia juga tengah menggiring seorang laki-laki Quraisy yang bernama Mikraz untuk di ajukan ke hadapan Rasulullah shallallahu 'alaihi wasallam. Lelaki Quraisy yang bernama Mikraz tersebut dibiarkan mengendarai seekor kuda yang ternyata diikuti sekitar tiga puluh orang musyrikin dari anak buahnya. Sejenak Rasulullah shallallahu 'alaihi wasallam memandangi mereka sambil bersabda: \"Biarkanlah mereka, karena mereka akan menaggung kezalimannya dari awal sampai akhir.\" Kemudian Rasulullah shallallahu 'alaihi wasallam memaafkan mereka, maka Allah menurunkan ayat: '(Dan Dialah yang menahan tangan mereka dari (membinasakan) kamu dan (menahan) tangan kamu dari (membinasakan) mereka di tengah kota Makkah setelah Allah memenangkan kamu atas mereka) ' (Qs. Al Fath: 24). Setelah kejadian itu, kami kembali pulang bersama-sama ke kota Madinah dengan membawa kemenangan. Namun sebelumnya, kami berhenti di suatu tempat. Sedangkan jarak kami dengan Bani Lihyan saat itu hanya dipisahkan oleh gunung, menurut informasi yang aku ketahui, kaum Bani Lihyan juga termasuk dari orang-orang Musyrik. Kemudian Rasulullah shallallahu 'alaihi wasallam menyatakan bahwa beliau akan mengampuni seseorang yang sanggup mendaki gunung tersebut pada malam hari. Memang, gunung yang ada di hadapan mereka itu seakan-akan sedang menantang Rasulullah shallallahu 'alaihi wasallam dan para sahabat yang hadir saat itu. Pada malam itu juga, aku berhasil mendaki gunung tersebut sebanyak dua atau tiga kali. Akhirnya kami tiba di kota Madinah. Lalu Rasulullah shallallahu 'alaihi wasallam mengutus Rabbah -pelayan beliau- untuk mengawal unta yang tengah membawa muatan yang cukup besar, lalu aku juga ikut menyertai Rabbah dengan menaiki kuda milik Thalhah. Keesokan harinya, aku mendengar informasi bahwa Abdurrahman Al Fazari hendak mencegat rombongan kami. Ternyata informasi itu benar, Abdurrahman dapat menawan unta Rasulullah shallallahu 'alaihi wasallam beserta muatannya. Bahkan kami dengar, dia berhasil membunuh orang yang mengendarai unta tersebut. Saat itu aku telah mengatakannya kepada Rabbah, 'Wahai Rabbah, ambillah kuda ini dan serahkanlah kepada Thalhah bin Ubaidullah, jangan sampai lupa, beritahukan kepada Rasulullah shallallahu 'alaihi wasallam bahwa orang-orang Musyrikin telah menawan rombongan unta yang beliau utus.' Setelah itu, aku naik ke atas bukit, sambil menghadap kota Madinah, aku berteriak dengan suara lantang, 'Wahai para penduduk! ' Sebanyak tiga kali berturut-turut. Kemudian aku turun dari atas bukit sambil terus melepaskan anak panah ke arah sasaran musuh, sementara itu untuk menghibur hati, aku bersenandung, 'Aku adalah putra Al Akwa', hari ini adalah hari kebinasaan! ' Dalam perjelanan mengejar musuh, aku bertemu seorang laki-laki dari kaum Musyrikin. Lalu aku mulai membidikkan anak panah ke arahnya. Tidak lama kemudian, aku berhasil menancapkan sebatang anak panah tepat mengenai bahunya, dari kejauhan aku katakan kepadanya, 'Rasakanlah anak panah itu, aku adalah putra Al Akwa', hari ini adalah hari kebinasaan'.\" Salamah berkata, \"Demi Allah, aku tetap terus melancarkan anak panah ke arah musuh. Tiba-tiba dari arah depan, aku melihat seorang musuh yang sedang menunggang kuda menuju ke arahku. Lalu aku bersembunyi di balik pohon yang rimbun. Begitu musuh yang menunggang kuda itu melintas, segera aku melepaskan anak panahku hingga berhasil melukainya. Tidak beberapa lama, datang lagi beberapa pasukan musuh. Namun seperti sebelumnya, aku langsung memanjat ke atas bukit. Dari atas bukit tersebut aku berupaya menahan laju mereka dengan cara melemparkan bebatuan ke arah mereka, dan ternyata cara tersebut berhasil. Mereka mundur secara teratur dan membiarkan aku terus mengejarnya. Karena merasa keberatan dengan beban yang mereka bawa, akhirnya mereka menjatuhkan sebagian besar perbekalan mereka dari unta Rasulullah shallallahu 'alaihi wasallam yang mereka ambil, agar lebih ringan dan dapat melarikan kendaraannya. Aku pun terus mengikuti laju mereka sambil melemparkan anak panah. Aku juga membuat jejak di jalan-jalan dengan bebatuan supaya dapat diketahui oleh Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya, dari apa yang telah aku lakukan terhadap musuh-musuh tersebut. Dengan berhimpit-himpitan, pasukan kaum Musyrikin berusaha turun dari bukit dengan melewati jalan sempit yang ada di bukit. Untungnya, Fulan bin Badri Al Fazari telah siap menanti di bawah untuk membantu mereka. Kemudian mereka duduk sambil beristirahat karena kelelahan, sementara aku duduk di atas bukit. Dari atas bukit, aku mendengar Al Fazari bertanya kepada teman-temannya yang baru saja turun dari bukit, 'Ada apa ini? Apa yang telah terjadi pada kalian? ' mereka menjawab, 'Kami telah mengalami kepayahan, demi Allah, tidaklah kami melalui akhir malam, melainkan kami selalu dihujani anak panah, sehingga kami membuang sebagian besar perbekalan kami.' Lalu Al Fazari memerintahkan empat orang dari mereka untuk menghadapiku, akhirnya keempat orang tersebut bergegas naik ke atas bukit untuk menghadapiku. Ketika jarak antara aku dengan mereka sudah semakin dekat, hingga memungkinkan mereka mendengar suara aku, maka aku berseru, \"Hai kalian berempat, apakah kalian mengenalku? ' mereka menjawab, 'Tidak, kami tidak mengenalmu, siapa sebenarnya kamu? ' aku menjawab, 'Aku adalah Salamah bin Al Akwa', demi dzat yang memuliakan wajah Muhammad, aku tidak akan membiarkan kalian hidup, mungkin begitu pula dengan kalian yang tidak mungkin membiarkan aku hidup.' Lalu aku mendengar salah seorang dari keempat orang tersebut menjawab seperti yang aku katakan. Belum sampai aku pindah tempat, tiba-tiba aku melihat beberapa orang sahabat Rasulullah shallallahu 'alaihi wasallam yang tengah mengendarai kuda keluar dari balik semak-semak pepohonan menuju arah tempat aku berada.\" Salamah berkata, \"Pertama kali yang aku lihat adalah Akhram Al Asadi, disusul oleh Abu Qatadah Al Anshari. Setelah itu, muncullah Miqdad bin Aswad Al Kindi.\" Salamah melanjutkan, \"Lalu aku memegang tali kekang kuda milik akhram, ternyata mereka bergegas hendak maju membantu aku, segera aku berkata, \"Wahai Akhram, hati-hatilah terhadap mereka, jangan sampai mereka melukai atau mencelakaimu, hingga datang bala bantuan dari Rasulullah shallallahu 'alaihi wasallam dan para sahabat yang lain.\" Dia menjawab, \"Wahai Salamah, jika kamu benar-benar beriman kepada Allah dan Allah dan hari Kiamat, serta kamu yakin bahwa surga dan neraka itu sesuatu yang benar, maka janganlah kamu menghalangiku untuk memperoleh syahid.\" Salamah berkata, \"Kemudian aku membiarkannya maju untuk bertempur satu lawan satu, lalu Abdurrahman maju ke hadapan menghadapi Akhram, pada awalnya dia dapat melukai kuda Abdurrahman, namun akhirnya Abdurrahman dapat menikam akhram hingga dia gugur. Abdurrahman lantas menaiki kudanya. Setelah itu, majulah Abu Qatadah -prajurit penunggang kuda Rasulullah shallallahu 'alaihi wasallam- menghadapi Abdurrahman. Lalu Abu Qatadah dapat menikam Abdurrahman dan membunuhnya, demi dzat yang memuliakan wajah Muhammad shallallahu 'alaihi wasallam, aku terus membuntuti mereka dengan berjalan kaki hingga tak kulihat satupun sahabat Muhammad shallallahu 'alaihi wasallam dan tidak juga debunya. Menjelang matahari terbenam, mereka menuju ke jalan di bukit yang terdapat mata airnya bernama Dzu Qard, untuk mereka minum karena kehausan.\" Salamah berkata, \"Kemudian mereka melihatku berlari membuntuti mereka, kuhalangi mereka dari telaga itu sehingga mereka tak bisa meneguk setetes air.\" Salamah berkata, \"Lantas mereka meninggalkan tempat tersebut dengan bersusah payah menyusuri lereng-lereng bukit.\" Salamah melanjutkan, \"Lalu aku berlari dan menjumpai seseorang dari mereka, lantas kutusuk dengan anak panah tepat mengenai ujung tulang bahu.\" Salamah melanjutkan, \"Lalu kukatakan dengan nada mengejek, 'Coba kau cabut anak panah yang kutusukkan, aku adalah putra Al Akwa', hari ini adalah hari kebinasaan.' Sang musuh berujar, 'Pagi yang sial, betulkah kamu Akwa'? ' Aku menjawab, 'Betul hai musuh Allah, akulah Akwa' yang pagi dini membawa kesialan bagimu.' Akwa' meneruskan, \"Musuh mencelakai dua ekor kudanya di lereng gunung. Kugiring keduanya kepada Rasulullah shallallahu 'alaihi wasallam. Amir menyusulku dengan membawa geriba kulit berkantung dua, satu berisi susu campuran, dan satunya berisi air murni. Aku berwudlu dan minum, lantas kutemui Rasulullah shallallahu 'alaihi wasallam yang beliau tengah berada di sumber air yang kuhalangi musuh meminumnya. Ternyata Rasulullah telah mengambil seluruh unta dan segala yang kuselamatkan dari pasukan musyrik, juga tombak dan kain burdah. Saat itu, Bilal telah menyembelih seekor unta dari beberapa unta yang aku selamatkan dari orang Musyrik, kemudian dia mengambil hatinya dan punuknya dan membakarnya, setelah itu ia mempersembahkannya kepada Rasulullah shallallahu 'alaihi wasallam.\" Salamah melanjutkan, 'Aku berkata, 'Wahai Rasulullah, biarkanlah aku memilih seratus orang dari pasukan musuh, kemudian aku mengikuti mereka hingga tidak ada lagi yang menginformasikan posisi kita melainkan aku tebas batang lehernya'.\" Salamah berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam tersenyum sehingga gigi geraham beliau terlihat jelas siang hari itu. Kemudian beliau bertanya: \"Wahai Salamah, apakah kamu telah siap dengan apa yang akan kamu lakukan itu?\" aku menjawab, \"Tentu, demi dzat yang telah memuliakan anda.\" Selanjutnya beliau bersabda: \"Ketahuilah wahai Salamah, sesungguhnya mereka sekarang sedang berada di wilayah kekuasaan orang-orang Ghathafan.\" Salamah berkata, \"Lalu datanglah seorang laki-laki dari Ghathafan seraya berkata, \"Si fulan telah menyembelih unta untuk mereka, ketika mereka menguliti hewan tersebut, tiba-tiba mereka melihat debu mengepul, hingga mereka lari terbirit-birit.\" Keesokan harinya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik prajurit penunggang kuda saat ini adalah Abu Qatadah, sedangkan sebaik-baik prajurit pejalan kaki adalah salamah.\" Salamah melanjutkan, \"Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan dua batang tombak kepadaku, yaitu; tombak untuk pasukan berkuda dan tombak untuk pejalan kaki, dan saat itu aku menggabungkan menjadi satu. Kemudian kami kembali ke Madinah dan aku membonceng di belakang Rasulullah shallallahu 'alaihi wasallam dengan menaiki Adzba`.\" Salamah berkata, \"Ketika kami berada di tengah jalan, -Salamah berkata- ada seorang sahabat Anshar yang mengajak kami untuk lomba lari cepat. Salamah berkata, \"Lalu sahabat Anshar itu berkata, 'Tidakkah ada orang yang mau berlomba lari menuju Madinah? ' dan ia mengulanginya sampai beberapa kali.\" Salamah melanjutkan, \"Setelah aku mendengar perkataannya, aku berkata, 'Apakah kamu hendak memuliakan orang yang mulia, ataukah hendak memperoleh wibawa di hadapan orang yang terpandang? ' dia menjawab, \"Tidak, namun untuk Rasulullah shallallahu 'alaihi wasallam.\" Salamah melanjutkan, \"Aku berkata, \"Wahai Rasulullah, demi ayah dan ibuku, biarkanlah aku melayani tantangan lomba lari laki-laki itu!\" Beliau menjawab: \"Silahkan jika kamu mau.\" Salamah berkata, \"Ayo mulai.\" Lalu aku berlari dengan kakiku, memang aku sengaja membiarkan dia hingga ia mendaki satu atau dua bukit, sebab aku khawatir akan kehabisan tenaga, kemudian aku berlari melewati jejaknya dan aku masih membiarkan dia mendaki satu atau dua bukit. Kemudian aku pacu lagi lariku sekencang-kencangnya sehingga aku dapat menjumpainya.\" Salamah berkata, \"Kemudian aku menepuk di antara pundaknya.\" Salamah melanjutkan, \"Aku berkata, 'Demi Allah, kamu telah didahului'.\" -Iyasy berkata; aku kira Salamah berkata- \"aku telah mendahuluinya ke Madinah.\" Salamah melanjutkan, \"Demi Allah, kami waktu i"},{"p":"Muslim","n":3140,"ar":"حَدَّثَنِي عَمْرُو بْنُ مُحَمَّدٍ النَّاقِدُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ ثَمَانِينَ رَجُلًا مِنْ أَهْلِ مَكَّةَ هَبَطُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ جَبَلِ التَّنْعِيمِ مُتَسَلِّحِينَ يُرِيدُونَ غِرَّةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابِهِ فَأَخَذَهُمْ سِلْمًا فَاسْتَحْيَاهُمْ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَهُوَ الَّذِي كَفَّ أَيْدِيَهُمْ عَنْكُمْ وَأَيْدِيَكُمْ عَنْهُمْ بِبَطْنِ مَكَّةَ مِنْ بَعْدِ أَنْ أَظْفَرَكُمْ عَلَيْهِمْ }","trj":"Telah menceritakan kepadaku [Amru bin Muhammad An Naqid] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas bin Malik], bahwa delapan puluh orang dari penduduk Makkah turun dari bukit Tan'im kepada Rasulullah shallallahu 'alaihi wasallam dengan persenjataan yang lengkap. Mereka hendak menyerang Nabi shallallahu 'alaihi wasallam dan para sahabatnya karena bentuk permusuhannya terhadap beliau. Namun akhirnya mereka menyerah dan beliau membiarkan mereka hidup, maka Allah Azza Wa Jalla menurunkan ayatnya: '(Dan Dialah yang menahan tangan mereka dari (membinasakan) kamu dan (menahan) tangan kamu dari (membinasakan) mereka di tengah kota Makkah sesudah Allah memenangkan kamu atas mereka) ' (Qs. Al Fath: 24)."}],"48:28":[{"p":"Darimi","n":45,"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا يَزِيدُ بْنُ أَبِي حَكِيمٍ حَدَّثَنِي الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ إِنَّ اللَّهَ فَضَّلَ مُحَمَّدًا عَلَى الْأَنْبِيَاءِ وَعَلَى أَهْلِ السَّمَاءِ فَقَالُوا يَا ابْنَ عَبَّاسٍ بِمَ فَضَّلَهُ عَلَى أَهْلِ السَّمَاءِ قَالَ إِنَّ اللَّهَ قَالَ لِأَهْلِ السَّمَاءِ { وَمَنْ يَقُلْ مِنْهُمْ إِنِّي إِلَهٌ مِنْ دُونِهِ فَذَلِكَ نَجْزِيهِ جَهَنَّمَ كَذَلِكَ نَجْزِي الظَّالِمِينَ } الْآيَةَ وَقَالَ اللَّهُ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا لِيَغْفِرَ لَكَ اللَّهُ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ } قَالُوا فَمَا فَضْلُهُ عَلَى الْأَنْبِيَاءِ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ { وَمَا أَرْسَلْنَا مِنْ رَسُولٍ إِلَّا بِلِسَانِ قَوْمِهِ لِيُبَيِّنَ لَهُمْ } الْآيَةَ وَقَالَ اللَّهُ عَزَّ وَجَلَّ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { وَمَا أَرْسَلْنَاكَ إِلَّا كَافَّةً لِلنَّاسِ } فَأَرْسَلَهُ إِلَى الْجِنِّ وَالْإِنْسِ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Yazid bin Abu Hakim] telah menceritakan kepadaku [Al Hakam bin Abaan] dari ['Ikrimah] dari [Ibnu Abbas] Radliyallahu'anhu ia berkata; \" Sesungguhnya Allah Subhanahu wa Ta'ala memberikan keutamaan kepada Nabi Muhammad shallallahu 'alaihi wasallam atas Nabi-nabi yang lainnya dan atas penghuni langit. \" lalu mereka bertanya: \"Wahai Ibnu Abbas, keutamaan apa yang diberikan kepada beliau atas penghuni langit?\" Ibnu Abbas menjawab; \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman kepada penghuni langit: Dari Ibnu Abbas berkata: WAMAN YAQUL MINHUM INNII ILAAHUN MIN DUNIHI FADZALIJKA NAJZIIHI JAHANNAMA KADZALIKA NAJZII AZHA-ZHALIMIIN Dan barang siapa diantara mereka mengatakan, sesungguhnya aku adalah tuhan selain dari pada Allah Subhanahu wa Ta'ala, maka orang itu kami beri balasan dengan jahannam, dengan demikian kami memberikan pembalasan kepada orang-orang zhalim. (Qs. Al Anbiya` /21: 29) Dan Allah Subhanahu wa Ta'ala terhadap dosamu yang telah lalu dan yang akan datang serta menyempurnakan nikmat-Nya atasmu dan memimpin kamu ke jalan yang lurus. ` (Qs. Al Fath /48: 1. 2) Lalu mereka bertanya, \" Apa keutamaan beliau atas semua Nabi-nabi?\" bin Abbas menjawab, \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman, `Kami tidak mengutus seorang Rasul pun, melainkan dengan bahasa kaumnya, supaya ia dapat memberi penjelasan dengan terang kepada mereka. ` (Qs. Ibraahiim /14: 4) dan Allah Subhanahu wa Ta'ala berfirman untuk Nabi Muhammad shallallahu 'alaihi wasallam, ` dan Kami tidak mengutus kamu melainkan kepada umat manusia seluruhnya Sebagai pembawa berita gembira dan pemberi peringatan. ` (Qs. As Saba` 34: 28), maka beliau telah diutus kepada bangsa jin dan manusia. "}],"48:29":[{"p":"Darimi","n":45,"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا يَزِيدُ بْنُ أَبِي حَكِيمٍ حَدَّثَنِي الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ إِنَّ اللَّهَ فَضَّلَ مُحَمَّدًا عَلَى الْأَنْبِيَاءِ وَعَلَى أَهْلِ السَّمَاءِ فَقَالُوا يَا ابْنَ عَبَّاسٍ بِمَ فَضَّلَهُ عَلَى أَهْلِ السَّمَاءِ قَالَ إِنَّ اللَّهَ قَالَ لِأَهْلِ السَّمَاءِ { وَمَنْ يَقُلْ مِنْهُمْ إِنِّي إِلَهٌ مِنْ دُونِهِ فَذَلِكَ نَجْزِيهِ جَهَنَّمَ كَذَلِكَ نَجْزِي الظَّالِمِينَ } الْآيَةَ وَقَالَ اللَّهُ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا لِيَغْفِرَ لَكَ اللَّهُ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ } قَالُوا فَمَا فَضْلُهُ عَلَى الْأَنْبِيَاءِ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ { وَمَا أَرْسَلْنَا مِنْ رَسُولٍ إِلَّا بِلِسَانِ قَوْمِهِ لِيُبَيِّنَ لَهُمْ } الْآيَةَ وَقَالَ اللَّهُ عَزَّ وَجَلَّ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { وَمَا أَرْسَلْنَاكَ إِلَّا كَافَّةً لِلنَّاسِ } فَأَرْسَلَهُ إِلَى الْجِنِّ وَالْإِنْسِ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Yazid bin Abu Hakim] telah menceritakan kepadaku [Al Hakam bin Abaan] dari ['Ikrimah] dari [Ibnu Abbas] Radliyallahu'anhu ia berkata; \" Sesungguhnya Allah Subhanahu wa Ta'ala memberikan keutamaan kepada Nabi Muhammad shallallahu 'alaihi wasallam atas Nabi-nabi yang lainnya dan atas penghuni langit. \" lalu mereka bertanya: \"Wahai Ibnu Abbas, keutamaan apa yang diberikan kepada beliau atas penghuni langit?\" Ibnu Abbas menjawab; \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman kepada penghuni langit: Dari Ibnu Abbas berkata: WAMAN YAQUL MINHUM INNII ILAAHUN MIN DUNIHI FADZALIJKA NAJZIIHI JAHANNAMA KADZALIKA NAJZII AZHA-ZHALIMIIN Dan barang siapa diantara mereka mengatakan, sesungguhnya aku adalah tuhan selain dari pada Allah Subhanahu wa Ta'ala, maka orang itu kami beri balasan dengan jahannam, dengan demikian kami memberikan pembalasan kepada orang-orang zhalim. (Qs. Al Anbiya` /21: 29) Dan Allah Subhanahu wa Ta'ala terhadap dosamu yang telah lalu dan yang akan datang serta menyempurnakan nikmat-Nya atasmu dan memimpin kamu ke jalan yang lurus. ` (Qs. Al Fath /48: 1. 2) Lalu mereka bertanya, \" Apa keutamaan beliau atas semua Nabi-nabi?\" bin Abbas menjawab, \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman, `Kami tidak mengutus seorang Rasul pun, melainkan dengan bahasa kaumnya, supaya ia dapat memberi penjelasan dengan terang kepada mereka. ` (Qs. Ibraahiim /14: 4) dan Allah Subhanahu wa Ta'ala berfirman untuk Nabi Muhammad shallallahu 'alaihi wasallam, ` dan Kami tidak mengutus kamu melainkan kepada umat manusia seluruhnya Sebagai pembawa berita gembira dan pemberi peringatan. ` (Qs. As Saba` 34: 28), maka beliau telah diutus kepada bangsa jin dan manusia. "}]},"mapping_surah":[{"p":"Abu Dawud","n":1226,"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ وَهُوَ عَلَى نَاقَةٍ يَقْرَأُ بِسُورَةِ الْفَتْحِ وَهُوَ يُرَجِّعُ","trj":"Telah menceritakan kepada Kami [Hafsh bin Umar], telah menceritakan kepada Kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Abdullah bin Mughaffal], ia berkata; saya melihat Rasulullah shallAllahu wa'alaihi wa sallam pada saat penaklukan Mekkah berada di atas unta membaca surat Al Fath, dan beliau mengulang-ulangnya. "},{"p":"Ahmad","n":784,"ar":"حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ سِيَاهٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ قَالَأَتَيْتُ أَبَا وَائِلٍ فِي مَسْجِدِ أَهْلِهِ أَسْأَلُهُ عَنْ هَؤُلَاءِ الْقَوْمِ الَّذِينَ قَتَلَهُمْ عَلِيٌّ بِالنَّهْرَوَانِ فَفِيمَا اسْتَجَابُوا لَهُ وَفِيمَا فَارَقُوهُ وَفِيمَا اسْتَحَلَّ قِتَالَهُمْ قَالَ كُنَّا بِصِفِّينَ فَلَمَّا اسْتَحَرَّ الْقَتْلُ بِأَهْلِ الشَّامِ اعْتَصَمُوا بِتَلٍّ فَقَالَ عَمْرُو بْنُ الْعَاصِ لِمُعَاوِيَةَ أَرْسِلْ إِلَى عَلِيٍّ بِمُصْحَفٍ وَادْعُهُ إِلَى كِتَابِ اللَّهِ فَإِنَّهُ لَنْ يَأْبَى عَلَيْكَ فَجَاءَ بِهِ رَجُلٌ فَقَالَ بَيْنَنَا وَبَيْنَكُمْ كِتَابُ اللَّهِ{ أَلَمْ تَرَ إِلَى الَّذِينَ أُوتُوا نَصِيبًا مِنْ الْكِتَابِ يُدْعَوْنَ إِلَى كِتَابِ اللَّهِ لِيَحْكُمَ بَيْنَهُمْ ثُمَّ يَتَوَلَّى فَرِيقٌ مِنْهُمْ وَهُمْ مُعْرِضُونَ }فَقَالَ عَلِيٌّ نَعَمْ أَنَا أَوْلَى بِذَلِكَ بَيْنَنَا وَبَيْنَكُمْ كِتَابُ اللَّهِ قَالَ فَجَاءَتْهُ الْخَوَارِجُ وَنَحْنُ نَدْعُوهُمْ يَوْمَئِذٍ الْقُرَّاءَ وَسُيُوفُهُمْ عَلَى عَوَاتِقِهِمْ فَقَالُوا يَا أَمِيرَ الْمُؤْمِنِينَ مَا نَنْتَظِرُ بِهَؤُلَاءِ الْقَوْمِ الَّذِينَ عَلَى التَّلِّ أَلَا نَمْشِي إِلَيْهِمْ بِسُيُوفِنَا حَتَّى يَحْكُمَ اللَّهُ بَيْنَنَا وَبَيْنَهُمْ فَتَكَلَّمَ سَهْلُ بْنُ حُنَيْفٍ فَقَالَ يَا أَيُّهَا النَّاسُ اتَّهِمُوا أَنْفُسَكُمْ فَلَقَدْ رَأَيْتُنَا يَوْمَ الْحُدَيْبِيَةِ يَعْنِي الصُّلْحَ الَّذِي كَانَ بَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ الْمُشْرِكِينَ وَلَوْ نَرَى قِتَالًا لَقَاتَلْنَا فَجَاءَ عُمَرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَلَسْنَا عَلَى الْحَقِّ وَهُمْ عَلَى بَاطِلٍ أَلَيْسَ قَتْلَانَا فِي الْجَنَّةِ وَقَتْلَاهُمْ فِي النَّارِ قَالَ بَلَى قَالَ فَفِيمَ نُعْطِي الدَّنِيَّةَ فِي دِينِنَا وَنَرْجِعُ وَلَمَّا يَحْكُمِ اللَّهُ بَيْنَنَا وَبَيْنَهُمْ فَقَالَ يَا ابْنَ الْخَطَّابِ إِنِّي رَسُولُ اللَّهِ وَلَنْ يُضَيِّعَنِي أَبَدًا قَالَ فَرَجَعَ وَهُوَ مُتَغَيِّظٌ فَلَمْ يَصْبِرْ حَتَّى أَتَى أَبَا بَكْرٍ فَقَالَ يَا أَبَا بَكْرٍ أَلَسْنَا عَلَى حَقٍّ وَهُمْ عَلَى بَاطِلٍ أَلَيْسَ قَتْلَانَا فِي الْجَنَّةِ وَقَتْلَاهُمْ فِي النَّارِ قَالَ بَلَى قَالَ فَفِيمَ نُعْطِي الدَّنِيَّةَ فِي دِينِنَا وَنَرْجِعُ وَلَمَّا يَحْكُمِ اللَّهُ بَيْنَنَا وَبَيْنَهُمْ فَقَالَ يَا ابْنَ الْخَطَّابِ إِنَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَنْ يُضَيِّعَهُ اللَّهُ أَبَدًا قَالَ فَنَزَلَتْ سُورَةُ الْفَتْحِ قَالَ فَأَرْسَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عُمَرَ فَأَقْرَأَهَا إِيَّاهُ قَالَ يَا رَسُولَ اللَّهِ وَفَتْحٌ هُوَ قَالَ نَعَمْ","trj":"Telah menceritakan kepada kami [Ya'la bin 'Ubaid] dari [Abdul Aziz bin Siyah] dari [Habib bin Abu Tsabit] berkata; saya mendatangi [Abu Wa'il] di masjid keluarganya, saya bertanya kepadanya tentang kaum yang diperangi 'Ali di Nahrawan, hal-hal apa saja yang mereka terima, hal-hal apa saja yang mereka tak cocok, dan hal-hal apa saja sehingga 'Ali menganggap halal mereka diperangi. (Abu Wa'il radliyallahu'anhu) berkata; kami saat itu sedang di Shiffin, tatkala berkecamuk perang dengan penduduk Syam, mereka berpegang teguh untuk tetap di tempat yang tinggi. Lalu 'Amr bin Al 'Ash berkata kepada Mu'awiyah 'Utuslah seseorang kepada 'Ali dengan mushaf dan ajaklah dia kepada kitab Allah, dia tidak bakalan menolaknya.' Sang utusan pun datang menemui 'Ali dan berujar 'Antara kita dan kalian ada kitab Allah, 'Tidakkah kamu memperhatikan orang-orang yang telah diberi bahagian yaitu Al Kitab (Taurat), mereka diseru kepada Kitab Allah supaya Kitab itu menetapkan hukum diantara mereka; Kemudian sebahagian dari mereka berpaling, dan mereka selalu membelakangi (kebenaran) ' 'Ali berkata; ya saya lebih layak untuk melakukan hal itu, antara kami dan kalian ada kitab Allah. Lalu datanglah Al Khawarij, pada saat itu kami memanggil mereka dengan istilah Al Qurra', pedang mereka diletakkan pada pundak-pundak mereka. Mereka berkata; Wahai Amirul Mukminin, kenapa kita menunggu mereka, kaum yang berada di atas dataran tinggi itu, tidak sebaiknyakah kita berjalan kepada mereka dengan membawa pedang kita, sampai Allah memutuskan antara kita dengan mereka?. Lalu [Sahl bin Hunaif] berkata; Wahai manusia, koreksilah diri kalian sendiri, kami telah mengadakan perdamaian pada saat Hudaibiyah antara Rasulullah Shallallahu'alaihiwasallam dan kaum musrikin. Jika kami hendak berperang niscaya itu akan terjadi. Lalu datanglah 'Umar kepada Rasulullah Shallallahu'alaihiwasallam, berkata; \"Wahai Rasulullah, bukankah kita berada di atas kebenaran dan mereka berada di atas kebatilan, bukankah jika ada yang terbunuh diantara kita berada di surga dan jika ada yang terbunuh dari mereka akan berada di neraka?.\" Beliau menjawab, ya. ('Umar radliyallahu'anhu) berkata; kenapa kita memberi kehinaan kepada agama kita ini dan kita kembali, bukankah Allah telah memutuskan antara kita dan mereka?. beliau bersabda: \"Wahai Ibnu Khattab, saya adalah Rasulullah Shallallahu'alaihiwasallam dan (Allah Azzawajalla) tidak akan menelantarkanku selamanya.\" (Abu Wa'il radliyallahu'anhu) berkata; lalu Umar pulang dalam keadaan marah dan tidak sabar sehingga mendatangi Abu Bakar, seraya bertanya-tanya, Wahai Abu Bakar, bukankah kita berada di atas kebenaran dan mereka di atas kebatilan, bukankah korban dari kita berada di syurga dan korban dari mereka di neraka?.\" (Abu Bakar) menjawab, ya. ('Umar radliyallahu'anhu) berkata; kenapa kita memberi kekurangan pada agama kita ini dan kita kembali, bukankah Allah telah memutuskan antara kita dan mereka?. Abu Bakar terus mengatakan, \"Wahai Ibnu Al Khattab, dia adalah Rasulullah Shallallahu'alaihiwasallam dan Allah Azzawajalla tidak bakalan menelantarkannya selama-lamanya.\" (Abu Wa'il radliyallahu'anhu) berkata; lalu turunlah Surat Al Fath. Lantas Rasulullah Shallallahu'alaihiwasallam mengutusku kepada 'Umar, dan saya membacakan kepadanya. Dia berkata; Wahai Rasulullah, apakah itu berarti kemenangan?. Beliau menjawab, Ya."},{"p":"Bukhari","n":2945,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ أَبِيهِ حَدَّثَنَا حَبِيبُ بْنُ أَبِي ثَابِتٍ قَالَ حَدَّثَنِي أَبُو وَائِلٍ قَالَكُنَّا بِصِفِّينَ فَقَامَ سَهْلُ بْنُ حُنَيْفٍ فَقَالَ أَيُّهَا النَّاسُ اتَّهِمُوا أَنْفُسَكُمْ فَإِنَّا كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِ وَلَوْ نَرَى قِتَالًا لَقَاتَلْنَا فَجَاءَ عُمَرُ بْنُ الْخَطَّابِ فَقَالَ يَا رَسُولَ اللَّهِ أَلَسْنَا عَلَى الْحَقِّ وَهُمْ عَلَى الْبَاطِلِ فَقَالَ بَلَى فَقَالَ أَلَيْسَ قَتْلَانَا فِي الْجَنَّةِ وَقَتْلَاهُمْ فِي النَّارِ قَالَ بَلَى قَالَ فَعَلَامَ نُعْطِي الدَّنِيَّةَ فِي دِينِنَا أَنَرْجِعُ وَلَمَّا يَحْكُمِ اللَّهُ بَيْنَنَا وَبَيْنَهُمْ فَقَالَ يَا ابْنَ الْخَطَّابِ إِنِّي رَسُولُ اللَّهِ وَلَنْ يُضَيِّعَنِي اللَّهُ أَبَدًا فَانْطَلَقَ عُمَرُ إِلَى أَبِي بَكْرٍ فَقَالَ لَهُ مِثْلَ مَا قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ رَسُولُ اللَّهِ وَلَنْ يُضَيِّعَهُ اللَّهُ أَبَدًا فَنَزَلَتْ سُورَةُ الْفَتْحِ فَقَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عُمَرَ إِلَى آخِرِهَا فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ أَوَفَتْحٌ هُوَ قَالَ نَعَمْ","trj":"Telah bercerita kepada kami ['Abdullah bin Muhammad] telah bercerita kepada kami [Yahya bin Adam] telah bercerita kepada kami [Yazid bin 'Abdul 'Aziz] dari [bapaknya] telah bercerita kepada kami [Habib bin Abu Tsabit] berkata telah bercerita kepadaku [Abu Wa'il] berkata; Kami terlibat dalam perang Shiffiin lalu [Sahal bin Hunaif] berkata; \"Wahai sekalian manusia, berhati-hatilah kalian dengan diri kalian. Sungguh kami pernah bersama Rasulullah shallallahu 'alaihi wasallam pada hari Perjanjian Hudaibiyah. Seandainya saat itu kami berpendapat untuk perang pasti kami sudah berperang hingga datang 'Umar bin Al Khaththab seraya berkata; \"Wahai Rasulullah, bukankah kita berada di atas kebenaran sedangkan mereka di atas kebathilan?\". Beliau Shallallahu'alaihiwasallam menjawab: \"Ya, benar\". Lalu dia bertanya lagi; \"Bukankah siapa yang gugur diantara kita akan masuk surga sedang orang yang tewas dari mereka akan masuk neraka?\". Beliau Shallallahu'alaihiwasallam menjawab: \"Ya, benar\". 'Umar bertanya; \"Lalu atas dasar alasan apa kita menimpakan kehinaan dalam agama kita ini, apakah kita akan pulang sedangkan Allah belum memutuskan perkara antara kita dan mereka?\". Maka Beliau menjawab: \"Wahai putra Al Khaththab, aku ini Rasulullah dan Allah sekali-kali tidak akan menyia-nyiakan aku selamanya\". Kemudian 'Umar mendatangi Abu Bakr lalu mengatakan seperti yang dia katakan kepada Nabi shallallahu 'alaihi wasallam. Maka Abu Bakr berkata; \"Beliau itu Rasulullah dan Allah sekali-kali tidak akan menyia-nyiakan Beliau selamanya\". Maka kemudian turunlah surah al-Fath lalu Rasulullah shallallahu 'alaihi wasallam membacakannya kepada 'Umar hingga akhir surat. Lalu 'Umar bertanya; \"Wahai Rasulullah, apakah (keputusan) ini tanda kemenangan?\". Beliau menjawab: \"Ya\"."},{"p":"Bukhari","n":3670,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ عَلَى نَاقَتِهِ وَهُوَ يَقْرَأُ سُورَةَ الْفَتْحِ يُرَجِّعُ وَقَالَ لَوْلَا أَنْ يَجْتَمِعَ النَّاسُ حَوْلِي لَرَجَّعْتُ كَمَا رَجَّعَ","trj":"Telah menceritakan kepada kami [Abul Walid] Telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] katanya, kudengar [Abdullah bin Mughaffal] mengatakan; aku Pernah melihat Rasulullah shallallahu 'alaihi wasallam pada hari penaklukan Makkah diatas hewan tunggangannya membaca surat Al Fath dan beliau ulang-ulang. Dan Mu'awiyah berkata; \"Kalaulah para sahabat tidak berkumpul di sekitarku, niscaya akan kuulang-ulang sebagaimana Rasulullah mengulang-ulanginya.\""},{"p":"Bukhari","n":3681,"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ عُمَرُ يُدْخِلُنِي مَعَ أَشْيَاخِ بَدْرٍ فَقَالَ بَعْضُهُمْ لِمَ تُدْخِلُ هَذَا الْفَتَى مَعَنَا وَلَنَا أَبْنَاءٌ مِثْلُهُ فَقَالَ إِنَّهُ مِمَّنْ قَدْ عَلِمْتُمْ قَالَ فَدَعَاهُمْ ذَاتَ يَوْمٍ وَدَعَانِي مَعَهُمْ قَالَ وَمَا رُئِيتُهُ دَعَانِي يَوْمَئِذٍ إِلَّا لِيُرِيَهُمْ مِنِّي فَقَالَ مَا تَقُولُونَ فِي{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ وَرَأَيْتَ النَّاسَ يَدْخُلُونَ فِي دِينِ اللَّهِ أَفْوَاجًا }حَتَّى خَتَمَ السُّورَةَ فَقَالَ بَعْضُهُمْ أُمِرْنَا أَنْ نَحْمَدَ اللَّهَ وَنَسْتَغْفِرَهُ إِذَا نُصِرْنَا وَفُتِحَ عَلَيْنَا وَقَالَ بَعْضُهُمْ لَا نَدْرِي أَوْ لَمْ يَقُلْ بَعْضُهُمْ شَيْئًا فَقَالَ لِي يَا ابْنَ عَبَّاسٍ أَكَذَاكَ تَقُولُ قُلْتُ لَا قَالَ فَمَا تَقُولُ قُلْتُ هُوَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ اللَّهُ لَهُ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَتْحُ مَكَّةَ فَذَاكَ عَلَامَةُ أَجَلِكَ{ فَسَبِّحْ بِحَمْدِ رَبِّكَ وَاسْتَغْفِرْهُ إِنَّهُ كَانَ تَوَّابًا }قَالَ عُمَرُ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","trj":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Said bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma, Umar Pernah mengajakku dalam sebuah majlis orang dewasa, sehingga sebagian sahabat bertanya \"Mengapa si anak kecil ini kau ikut sertakan, kami juga punya anak-anak kecil seperti dia?\" Umar menjawab; \"Kalian maklum, anak ini punya \"kualitas\" tersendiri.\" Kata Ibnu Umar, maka suatu hari Umar mengundang mereka dan mengajakku bersama mereka. Seingatku, Umar tidak mengajakku saat itu selain untuk mempertontonkan kepada mereka kualitas keilmuanku. Lantas Umar bertanyal; \"Bagaimana komentar kalian tentang ayat \"Seandainya pertolongan Allah dan kemenangan datang (1) dan kau lihat manusia masuk agama Allah dengan berbondong-bondong (2) -hingga ahkir surat (QS. Alfath 1-3). Sebagian sahabat berkomentar; \"Tentang ayat ini, setahu kami, kita diperintahkan agar memuji Allah dan meminta ampunan kepada-Nya, tepatnya ketika kita diberi pertolongan dan diberi kemenangan.\" Sebagian lagi berkomentar; \"kalau kami nggak tahu.\" Atau bahkan tidak berkomentar sama sekali. Lantas Umar bertanya kepadaku; \"Wahai Ibnu Abbas, beginikah kamu berkomentar mengenai ayat tadi?\"TIDAK\" Jawabku.\"Lalu komentarmu? Tanya Umar. Ibnu Abbas menjawab; \"Surat tersebut adalah pertanda wafat Rasulullah shallallahu 'alaihi wasallam sudah dekat, Allah memberitahunya dengan ayatnya: \"Jika telah datang pertolongan Allah dan kemenangan', itu berarti penaklukan Makkah dan itulah tanda ajalmu (Muhammad), karenanya \"Bertasbihlah dengan memuji Tuhanmu dan mohonlah ampunan, sesungguhnya Dia Maha Menerima taubat. Kata Umar, \"Aku tidak tahu penafsiran ayat tersebut selain seperti yang kamu (Ibnu Abbas) ketahui.\""},{"p":"Bukhari","n":3790,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يُدْنِي ابْنَ عَبَّاسٍ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ إِنَّ لَنَا أَبْنَاءً مِثْلَهُ فَقَالَ إِنَّهُ مِنْ حَيْثُ تَعْلَمُ فَسَأَلَ عُمَرُ ابْنَ عَبَّاسٍ عَنْ هَذِهِ الْآيَةِ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَقَالَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ إِيَّاهُ فَقَالَ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","trj":"Telah menceritakan kepada kami [Muhammad bin Ar'arah] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; Umar bin Khaththab radliallahu 'anhu pernah mendekatiku. Maka Abdurrahman bin Auf berkata kepadanya; Sesungguhnya kita juga punya anak-anak sepertinya. Umar menjawab; kamu sendirikan tahu siapakah Ibnu Abbas. Lalu Umar bertanya kepada Ibnu Abbas tentang ayat; \"Apabila pertolongan dan kemenangan Allah telah datang.(QS. Alfath 1-5) \" Ibnu Abbas menjawab; \"Ajal Rasulullah shallallahu 'alaihi wasallam telah memberitahukan kepada beliau bahwa dia telah datang kepadanya.\" Umar berkata; 'Aku tidak tahu tentang ayat itu kecuali apa yang kamu ketahui.'"},{"p":"Bukhari","n":4151,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسِيرُ فِي بَعْضِ أَسْفَارِهِ وَعُمَرُ بْنُ الْخَطَّابِ يَسِيرُ مَعَهُ لَيْلًا فَسَأَلَهُ عُمَرُ بْنُ الْخَطَّابِ عَنْ شَيْءٍ فَلَمْ يُجِبْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ ثَكِلَتْ أُمُّ عُمَرَ نَزَرْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مَرَّاتٍ كُلَّ ذَلِكَ لَا يُجِيبُكَ قَالَ عُمَرُ فَحَرَّكْتُ بَعِيرِي ثُمَّ تَقَدَّمْتُ أَمَامَ النَّاسِ وَخَشِيتُ أَنْ يُنْزَلَ فِيَّ قُرْآنٌ فَمَا نَشِبْتُ أَنْ سَمِعْتُ صَارِخًا يَصْرُخُ بِي فَقُلْتُ لَقَدْ خَشِيتُ أَنْ يَكُونَ نَزَلَ فِيَّ قُرْآنٌ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْتُ عَلَيْهِ فَقَالَ لَقَدْ أُنْزِلَتْ عَلَيَّ اللَّيْلَةَ سُورَةٌ لَهِيَ أَحَبُّ إِلَيَّ مِمَّا طَلَعَتْ عَلَيْهِ الشَّمْسُ ثُمَّ قَرَأَ{ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا }","trj":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Zaid bin Aslam] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam pergi dalam salah satu perjalanannya. Dan Umar bin Khattab bersama beliau pada malam hari itu. Umar bertanya kepada beliau tentang suatu hal, namun beliau tidak menjawabnya. Dia bertanya lagi, namun beliau tetap tidak menjawab. Dia bertanya lagi, namun beliau tetap tidak menjawab. ' [Umar] berkata; \"Huss kamu, 'Umar. Kamu telah memaksa Rasulullah shallallahu 'alaihi wasallam tiga kali namun semuanya itu tidak ada yang dijawabnya.' 'Umar berkata; \"Saya gerakkan untaku, dan aku maju ke hadapan orang-orang, saya khawatir jika turun padaku Al qur'an. tidak berapa lama, saya mendengar orang yang berteriak ke arahku.\" ('Umar radliallahu 'anhu) berkata; \"Saya berkata; \"Saya khawatir jika ada ayat yang turun kepadaku, \" 'Umar radliallahu 'anhu berkata; \"Maka saya mendatangi Rasulullah shallallahu 'alaihi wasallam. Saya mengucapkan salam kepada beliau. Beliau bersabda: 'Telah turun padaku tadi malam satu surat, yang lebih saya cintai daripada matahari terbit'. Beliau membaca: 'INNAA FATAHNA LAKA FATHAN MUBINAA'.\" (QS. Alfath)."},{"p":"Bukhari","n":4153,"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُعَاوِيَةُ بْنُ قُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ سُورَةَ الْفَتْحِ فَرَجَّعَ فِيهَا قَالَ مُعَاوِيَةُ لَوْ شِئْتُ أَنْ أَحْكِيَ لَكُمْ قِرَاءَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَفَعَلْتُ","trj":"Telah menceritakan kepada kami [Muslim bin Ibrahim] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Mu'awiyah bin Qurrah] dari [Abdullah bin Mughaffal] dia berkata; pada waktu fathu Makkah, Nabi shallallahu 'alaihi wasallam membaca surat Al Fath, dan beliau mengulang-ngulangnya. Mu'awiyah berkata; Jika aku ingin menceritakan kepada kalian bacaan Nabi shallallahu 'alaihi wasallam, tentu akan aku ceritakan.'"},{"p":"Bukhari","n":4161,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِسْحَاقَ السُّلَمِيُّ حَدَّثَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ سِيَاهٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ قَالَ أَتَيْتُ أَبَا وَائِلٍأَسْأَلُهُ فَقَالَ كُنَّا بِصِفِّينَ فَقَالَ رَجُلٌ أَلَمْ تَرَ إِلَى الَّذِينَ يُدْعَوْنَ إِلَى كِتَابِ اللَّهِ فَقَالَ عَلِيٌّ نَعَمْ فَقَالَ سَهْلُ بْنُ حُنَيْفٍ اتَّهِمُوا أَنْفُسَكُمْ فَلَقَدْ رَأَيْتُنَا يَوْمَ الْحُدَيْبِيَةِ يَعْنِي الصُّلْحَ الَّذِي كَانَ بَيْنَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُشْرِكِينَ وَلَوْ نَرَى قِتَالًا لَقَاتَلْنَا فَجَاءَ عُمَرُ فَقَالَ أَلَسْنَا عَلَى الْحَقِّ وَهُمْ عَلَى الْبَاطِلِ أَلَيْسَ قَتْلَانَا فِي الْجَنَّةِ وَقَتْلَاهُمْ فِي النَّارِ قَالَ بَلَى قَالَ فَفِيمَ نُعْطِي الدَّنِيَّةَ فِي دِينِنَا وَنَرْجِعُ وَلَمَّا يَحْكُمِ اللَّهُ بَيْنَنَا فَقَالَ يَا ابْنَ الْخَطَّابِ إِنِّي رَسُولُ اللَّهِ وَلَنْ يُضَيِّعَنِي اللَّهُ أَبَدًا فَرَجَعَ مُتَغَيِّظًا فَلَمْ يَصْبِرْ حَتَّى جَاءَ أَبَا بَكْرٍ فَقَالَ يَا أَبَا بَكْرٍ أَلَسْنَا عَلَى الْحَقِّ وَهُمْ عَلَى الْبَاطِلِ قَالَ يَا ابْنَ الْخَطَّابِ إِنَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَنْ يُضَيِّعَهُ اللَّهُ أَبَدًا فَنَزَلَتْ سُورَةُ الْفَتْحِ","trj":"Telah menceritakan kepada kami [Ahmad bin Ishaq As Sulami] Telah menceritakan kepada kami [Ya'la] Telah menceritakan kepada kami [Abdul Aziz bin Siyah] dari [Habib bin Abu Tsabit] dia berkata; Aku menemui [Abu Wa'il] untuk menanyakan sesuatu. Katanya; ketika itu kami di Shiffin, lantas seseorang berkata; Tidakkah kamu telah melihat orang-orang yang menyeru kepada kitabullah?. Maka Ali menjawab; 'Ya.' [Sahal bin Hunaif] berkata; Tolong koreksilah diri kalian, sungguh aku pernah melihat kami pada hari perjanjian Hudaibiyah, yang terjadi antara Nabi shallallahu 'alaihi wasallam dan kaum Musyrikin, kalaulah kita berpendapat untuk berperang maka tentu kita akan berperang, hingga Umar datang dan berkata; 'Bukankah kita berada dalam kebenaran sedangkan mereka dalam kebatilan, bukankah orang-orang yang terbunuh dari kami berada di Surga, sedangkan orang-orang yang terbunuh dari mereka berada di Neraka? Nabi shallallahu 'alaihi wasallam menjawab; 'Ya.' Umar berkata; kalau begitu kenapa kita merendahkan agama kita dan kembali, padahal Allah belum memutuskan untuk kita. Maka Nabi shallallahu 'alaihi wasallam bersabda: Wahai Ibnu Khaththab; Sesungguhnya aku Rasulullah shallallahu 'alaihi wasallam, sekali-kali Allah tidak akan menyia-nyiakanku. Maka Umar pun kembali dalam keadaan tidak puas dan tidak sabar, lalu ia menemui Abu Bakr seraya berkata; Wahai Abu Bakr, bukankah kita berada dalam kebenaran dan mereka dalam kebatilan, Abu Bakr menjawab; Wahai Ibnu Khatthab, sesunggunya ia adalah Rasulullah shallallahu 'alaihi wasallam, Allah pasti tidak akan menyia-nyiakannya untuk selama-lamanya, maka turunlah surat Al Fath."},{"p":"Bukhari","n":4321,"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسِيرُ فِي بَعْضِ أَسْفَارِهِ وَعُمَرُ بْنُ الْخَطَّابِ يَسِيرُ مَعَهُ لَيْلًا فَسَأَلَهُ عُمَرُ عَنْ شَيْءٍ فَلَمْ يُجِبْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ فَقَالَ عُمَرُ ثَكِلَتْكَ أُمُّكَ نَزَرْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مَرَّاتٍ كُلَّ ذَلِكَ لَا يُجِيبُكَ قَالَ عُمَرُ فَحَرَّكْتُ بَعِيرِي حَتَّى كُنْتُ أَمَامَ النَّاسِ وَخَشِيتُ أَنْ يَنْزِلَ فِيَّ قُرْآنٌ فَمَا نَشِبْتُ أَنْ سَمِعْتُ صَارِخًا يَصْرُخُ بِي قَالَ فَقُلْتُ لَقَدْ خَشِيتُ أَنْ يَكُونَ نَزَلَ فِيَّ قُرْآنٌ قَالَ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْتُ عَلَيْهِ فَقَالَ لَقَدْ أُنْزِلَتْ عَلَيَّ اللَّيْلَةَ سُورَةٌ لَهِيَ أَحَبُّ إِلَيَّ مِمَّا طَلَعَتْ عَلَيْهِ الشَّمْسُ ثُمَّ قَرَأَ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا","trj":"Telah menceritakan kepada kami [Isma'il] ia berkata, Telah menceritakan kepadaku [Malik] dari [Zaid bin Aslam] dari [bapaknya] bahwasanya; Rasulullah shallallahu 'alaihi wasallam tengah berjalan dalam suatu safar yang dilakukannya. Lalu pada suatu malam, Umar bin Al Khaththab berjalan bersama beliau, lalu Umar bertanya tentang sesuatu, namun Rasulullah shallallahu 'alaihi wasallam tidak menjawabnya. Kemudian ia bertanya lagi, dan belum juga menjawabnya. Lalu bertanya lagi, tetapi tidak menjawabnya. Maka [Umar] pun berkata, \"Alangkah merugilah kamu, kamu bertanya kepada Rasulullah shallallahu 'alaihi wasallam, namun semua itu tidak dihiraukannya.\" Kemudian Umar berkata; \"Maka aku pun memacu Untau hingga berjalan di hadapan orang-orang, dan aku khawatir ayat Al Qur`an akan turun berkenaan denganku. Aku tak peduli lagi, bilamana aku mendengar teriakan suara yang memanggilku.\" Umar melanjutkan, \"Sungguh, aku khawatir ayat Al Qur`an akan turun berkenaan denganku. Karena itu, aku segera mendatangi Rasulullah shallallahu 'alaihi wasallam lalu mengucapkan salam atasnya. Beliau bersabda: 'Sesungguhnya, semalam telah turun satu surat padaku, dan surat itu lebih aku sukai, daripada terbitnya matahari.' Dan beliau pun membacakannya pada kami: 'INNAA FATAHNAA LAKA FATHAN MUBIINAA..'\" (QS. Alfath) "},{"p":"Bukhari","n":4341,"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي أَبُو إِيَاسٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ وَهُوَ يَقْرَأُ عَلَى رَاحِلَتِهِ سُورَةَ الْفَتْحِ","trj":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Syu'bah] ia berkata; Telah mengabarkan kepadaku [Abu Iyas] ia berkata; Aku mendengar [Abdullah bin Mughaffal] berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam pada hari Fathu Makkah, dan saat itu, beliau sedang membaca surat Al Fath di atas kendaraannya.\""},{"p":"Bukhari","n":4354,"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو إِيَاسٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ وَهُوَ عَلَى نَاقَتِهِ أَوْ جَمَلِهِ وَهِيَ تَسِيرُ بِهِ وَهُوَ يَقْرَأُ سُورَةَ الْفَت��حِ أَوْ مِنْ سُورَةِ الْفَتْحِ قِرَاءَةً لَيِّنَةً يَقْرَأُ وَهُوَ يُرَجِّعُ","trj":"Telah menceritakan kepada kami [Adam bin Abu Iyas] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Abu Iyas] ia berkata, Aku mendengar [Abdullah bin Mughaffal] berkata; Aku pernah melihat Nabi shallallahu 'alaihi wasallam membaca saat beliau berada di atas Untanya yang berjalan, ketika itu beliau membaca surat Al Fath atau bagian dari surat Al Fath, yakni dengan bacaan yang pelan seraya mengulang-ngulangnya.\""},{"p":"Bukhari","n":6616,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي سُرَيْجٍ أَخْبَرَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ الْمُزَنِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ عَلَى نَاقَةٍ لَهُ يَقْرَأُ سُورَةَ الْفَتْحِ أَوْ مِنْ سُورَةِ الْفَتْحِ قَالَ فَرَجَّعَ فِيهَا قَالَ ثُمَّ قَرَأَ مُعَاوِيَةُ يَحْكِي قِرَاءَةَ ابْنِ مُغَفَّلٍ وَقَالَ لَوْلَا أَنْ يَجْتَمِعَ النَّاسُ عَلَيْكُمْ لَرَجَّعْتُ كَمَا رَجَّعَ ابْنُ مُغَفَّلٍ يَحْكِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لِمُعَاوِيَةَ كَيْفَ كَانَ تَرْجِيعُهُ قَالَ آ آ آ ثَلَاثَ مَرَّاتٍ","trj":"Telah menceritakan kepada kami [Ahmad bin Abu Suraij] telah mengabarkan kepada kami [Syababah] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari ['Abdullah bin Mughaffal Al Muzanni] berkata, \"Pernah aku melihat Rasulullah shallallahu 'alaihi wasallam pada hari pembebasan Makkah di atas untanya membaca surat al Fath, atau sebagian dari surat al Fath.\" Abdullah bin Mughaffal berkata, \"Lantas beliau mengulang-ulang suaranya dan mengeraskannya.\" Kemudian Mu'awiyah membaca dengan menirukan bacaan Abdullah bin Mughaffal seraya berkata, \"Kalaulah manusia tidak berkumpul kepada kalian, niscaya aku mengulang-ulang bacaan dan mengeraskannya sebagaimana Ibnu Mughaffal mengulang-ulang dan mengeraskan bacaan ketika menirukan nabi shallallahu 'alaihi wasallam.\" Maka aku katakana kepada Mu'awiyah, \"Bagaimana beliau mengulang-ulang dan mengeraskan bacaannya?\" Mu'awiyah menjawab, \"Dengan mengucapkan AAA (dengan bacaan panjang enam harakat), AAA (dengan bacaan panjang enam harakat), AAA (dengan bacaan panjang enam harakat), beliau ucapkan tiga kali.\""},{"p":"Darimi","n":45,"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا يَزِيدُ بْنُ أَبِي حَكِيمٍ حَدَّثَنِي الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ إِنَّ اللَّهَ فَضَّلَ مُحَمَّدًا عَلَى الْأَنْبِيَاءِ وَعَلَى أَهْلِ السَّمَاءِ فَقَالُوا يَا ابْنَ عَبَّاسٍ بِمَ فَضَّلَهُ عَلَى أَهْلِ السَّمَاءِ قَالَ إِنَّ اللَّهَ قَالَ لِأَهْلِ السَّمَاءِ { وَمَنْ يَقُلْ مِنْهُمْ إِنِّي إِلَهٌ مِنْ دُونِهِ فَذَلِكَ نَجْزِيهِ جَهَنَّمَ كَذَلِكَ نَجْزِي الظَّالِمِينَ } الْآيَةَ وَقَالَ اللَّهُ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا لِيَغْفِرَ لَكَ اللَّهُ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ } قَالُوا فَمَا فَضْلُهُ عَلَى الْأَنْبِيَاءِ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ { وَمَا أَرْسَلْنَا مِنْ رَسُولٍ إِلَّا بِلِسَانِ قَوْمِهِ لِيُبَيِّنَ لَهُمْ } الْآيَةَ وَقَالَ اللَّهُ عَزَّ وَجَلَّ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { وَمَا أَرْسَلْنَاكَ إِلَّا كَافَّةً لِلنَّاسِ } فَأَرْسَلَهُ إِلَى الْجِنِّ وَالْإِنْسِ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Yazid bin Abu Hakim] telah menceritakan kepadaku [Al Hakam bin Abaan] dari ['Ikrimah] dari [Ibnu Abbas] Radliyallahu'anhu ia berkata; \" Sesungguhnya Allah Subhanahu wa Ta'ala memberikan keutamaan kepada Nabi Muhammad shallallahu 'alaihi wasallam atas Nabi-nabi yang lainnya dan atas penghuni langit. \" lalu mereka bertanya: \"Wahai Ibnu Abbas, keutamaan apa yang diberikan kepada beliau atas penghuni langit?\" Ibnu Abbas menjawab; \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman kepada penghuni langit: Dari Ibnu Abbas berkata: WAMAN YAQUL MINHUM INNII ILAAHUN MIN DUNIHI FADZALIJKA NAJZIIHI JAHANNAMA KADZALIKA NAJZII AZHA-ZHALIMIIN Dan barang siapa diantara mereka mengatakan, sesungguhnya aku adalah tuhan selain dari pada Allah Subhanahu wa Ta'ala, maka orang itu kami beri balasan dengan jahannam, dengan demikian kami memberikan pembalasan kepada orang-orang zhalim. (Qs. Al Anbiya` /21: 29) Dan Allah Subhanahu wa Ta'ala terhadap dosamu yang telah lalu dan yang akan datang serta menyempurnakan nikmat-Nya atasmu dan memimpin kamu ke jalan yang lurus. ` (Qs. Al Fath /48: 1. 2) Lalu mereka bertanya, \" Apa keutamaan beliau atas semua Nabi-nabi?\" bin Abbas menjawab, \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman, `Kami tidak mengutus seorang Rasul pun, melainkan dengan bahasa kaumnya, supaya ia dapat memberi penjelasan dengan terang kepada mereka. ` (Qs. Ibraahiim /14: 4) dan Allah Subhanahu wa Ta'ala berfirman untuk Nabi Muhammad shallallahu 'alaihi wasallam, ` dan Kami tidak mengutus kamu melainkan kepada umat manusia seluruhnya Sebagai pembawa berita gembira dan pemberi peringatan. ` (Qs. As Saba` 34: 28), maka beliau telah diutus kepada bangsa jin dan manusia. "},{"p":"Darimi","n":414,"ar":" أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ سُلَيْمَانَ أَبُو عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ عَنْ عَبَّادِ بْنِ عَبَّادٍ الْخَوَّاصِ الشَّامِيِّ أَبِي عُتْبَةَ قَالَ أَمَّا بَعْدُ اعْقِلُوا وَالْعَقْلُ نِعْمَةٌ فَرُبَّ ذِي عَقْلٍ قَدْ شُغِلَ قَلْبُهُ بِالتَّعَمُّقِ عَمَّا هُوَ عَلَيْهِ ضَرَرٌ عَنْ الِانْتِفَاعِ بِمَا يَحْتَاجُ إِلَيْهِ حَتَّى صَارَ عَنْ ذَلِكَ سَاهِيًا وَمِنْ فَضْلِ عَقْلِ الْمَرْءِ تَرْكُ النَّظَرِ فِيمَا لَا نَظَرَ فِيهِ حَتَّى لَا يَكُونَ فَضْلُ عَقْلِهِ وَبَالًا عَلَيْهِ فِي تَرْكِ مُنَافَسَةِ مَنْ هُوَ دُونَهُ فِي الْأَعْمَالِ الصَّالِحَةِ أَوْ رَجُلٍ شُغِلَ قَلْبُهُ بِبِدْعَةٍ قَلَّدَ فِيهَا دِينَهُ رِجَالًا دُونَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ اكْتَفَى بِرَأْيِهِ فِيمَا لَا يَرَى الْهُدَى إِلَّا فِيهَا وَلَا يَرَى الضَّلَالَةَ إِلَّا بِتَرْكِهَا يَزْعُمُ أَنَّهُ أَخَذَهَا مِنْ الْقُرْآنِ وَهُوَ يَدْعُو إِلَى فِرَاقِ الْقُرْآنِ أَفَمَا كَانَ لِلْقُرْآنِ حَمَلَةٌ قَبْلَهُ وَقَبْلَ أَصْحَابِهِ يَعْمَلُونَ بِمُحْكَمِهِ وَيُؤْمِنُونَ بِمُتَشَابِهِهِ وَكَانُوا مِنْهُ عَلَى مَنَارٍ كَوَضَحِ الطَّرِيقِ فَكَانَ الْقُرْآنُ إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ إِمَامًا لِأَصْحَابِهِ وَكَانَ أَصْحَابُهُ أَئِمَّةً لِمَنْ بَعْدَهُمْ رِجَالٌ مَعْرُوفُونَ مَنْسُوبُونَ فِي الْبُلْدَانِ مُتَّفِقُونَ فِي الرَّدِّ عَلَى أَصْحَابِ الْأَهْوَاءِ مَعَ مَا كَانَ بَيْنَهُمْ مِنْ الِاخْتِلَافِ وَتَسَكَّعَ أَصْحَابُ الْأَهْوَاءِ بِرَأْيِهِمْ فِي سُبُلٍ مُخْتَلِفَةٍ جَائِرَةٍ عَنْ الْقَصْدِ مُفَارِقَةٍ لِلصِّرَاطِ الْمُسْتَقِيمِ فَتَوَّهَتْ بِهِمْ أَدِلَّاؤُهُمْ فِي مَهَامِهَ مُضِلَّةٍ فَأَمْعَنُوا فِيهَا مُتَعَسِّفِينَ فِي تِيهِهِمْ كُلَّمَا أَحْدَثَ لَهُمْ الشَّيْطَانُ بِدْعَةً فِي ضَلَالَتِهِمْ انْتَقَلُوا مِنْهَا إِلَى غَيْرِهَا لِأَنَّهُمْ لَمْ يَطْلُبُوا أَثَرَ السَّالِفِينَ وَلَمْ يَقْتَدُوا بِالْمُهَاجِرِينَ وَقَدْ ذُكِرَ عَنْ عُمَرَ أَنَّهُ قَالَ لِزِيَادٍ هَلْ تَدْرِي مَا يَهْدِمُ الْإِسْلَامَ زَلَّةُ عَالِمٍ وَجِدَالُ مُنَافِقٍ بِالْقُرْآنِ وَأَئِمَّةٌ مُضِلُّونَ اتَّقُوا اللَّهَ وَمَا حَدَثَ فِي قُرَّائِكُمْ وَأَهْلِ مَسَاجِدِكُمْ مِنْ الْغِيبَةِ وَالنَّمِيمَةِ وَالْمَشْيِ بَيْنَ النَّاسِ بِوَجْهَيْنِ وَلِسَانَيْنِ وَقَدْ ذُكِرَ أَنَّ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ ذَا وَجْهَيْنِ فِي النَّارِ يَلْقَاكَ صَاحِبُ الْغِيبَةِ فَيَغْتَابُ عِنْدَكَ مَنْ يَرَى أَنَّكَ تُحِبُّ غِيبَتَهُ وَيُخَالِفُكَ إِلَى صَاحِبِكَ فَيَأْتِيهِ عَنْكَ بِمِثْلِهِ فَإِذَا هُوَ قَدْ أَصَابَ عِنْدَ كُلِّ وَاحِدٍ مِنْكُمَا حَاجَتَهُ وَخَفِيَ عَلَى كُلِّ وَاحِدٍ مِنْكُمَا مَا أُتِيَ بِهِ عِنْدَ صَاحِبِهِ حُضُورُهُ عِنْدَ مَنْ حَضَرَهُ حُضُورُ الْإِخْوَانِ وَغَيْبَتُهُ عَلَى مَنْ غَابَ عَنْهُ غَيْبَةُ الْأَعْدَاءِ مَنْ حَضَرَ مِنْهُمْ كَانَتْ لَهُ الْأَثَرَةُ وَمَنْ غَابَ مِنْهُمْ لَمْ تَكُنْ لَهُ حُرْمَةٌ يَفْتِنُ مَنْ حَضَرَهُ بِالتَّزْكِيَةِ وَيَغْتَابُ مَنْ غَابَ عَنْهُ بِالْغِيبَةِ فَيَا لَعِبَادَ اللَّهِ أَمَا فِي الْقَوْمِ مِنْ رَشِيدٍ وَلَا مُصْلِحٍ يَقْمَعُ هَذَا عَنْ مَكِيدَتِهِ وَيَرُدُّهُ عَنْ عِرْضِ أَخِيهِ الْمُسْلِمِ بَلْ عَرَفَ هَوَاهُمْ فِيمَا مَشَى بِهِ إِلَيْهِمْ فَاسْتَمْكَنَ مِنْهُمْ وَأَمْكَنُوهُ مِنْ حَاجَتِهِ فَأَكَلَ بِدِينِهِ مَعَ أَدْيَانِهِمْ فَاللَّهَ اللَّهَ ذُبُّوا عَنْ حُرَمِ أَغْيَابِكُمْ وَكُفُّوا أَلْسِنَتَكُمْ عَنْهُمْ إِلَّا مِنْ خَيْرٍ وَنَاصِحُوا اللَّهَ فِي أُمَّتِكُمْ إِذْ كُنْتُمْ حَمَلَةَ الْكِتَابِ وَالسُّنَّةِ فَإِنَّ الْكِتَابَ لَا يَنْطِقُ حَتَّى يُنْطَقَ بِهِ وَإِنَّ السُّنَّةَ لَا تَعْمَلُ حَتَّى يُعْمَلَ بِهَا فَمَتَى يَتَعَلَّمُ الْجَاهِلُ إِذَا سَكَتَ الْعَالِمُ فَلَمْ يُنْكِرْ مَا ظَهَرَ وَلَمْ يَأْمُرْ بِمَا تُرِكَ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } اتَّقُوا اللَّهَ فَإِنَّكُمْ فِي زَمَانٍ رَقَّ فِيهِ الْوَرَعُ وَقَلَّ فِيهِ الْخُشُوعُ وَحَمَلَ الْعِلْمَ مُفْسِدُوهُ فَأَحَبُّوا أَنْ يُعْرَفُوا بِحَمْلِهِ وَكَرِهُوا أَنْ يُعْرَفُوا بِإِضَاعَتِهِ فَنَطَقُوا فِيهِ بِالْهَوَى لَمَّا أَدْخَلُوا فِيهِ مِنْ الْخَطَإِ وَحَرَّفُوا الْكَلِمَ عَمَّا تَرَكُوا مِنْ الْحَقِّ إِلَى مَا عَمِلُوا بِهِ مِنْ بَاطِلٍ فَذُنُوبُهُمْ ذُنُوبٌ لَا يُسْتَغْفَرُ مِنْهَا وَتَقْصِيرُهُمْ تَقْصِيرٌ لَا يُعْتَرَفُ بِهِ كَيْفَ يَهْتَدِي الْمُسْتَدِلُّ الْمُسْتَرْشِدُ إِذَا كَانَ الدَّلِيلُ حَائِرًا أَحَبُّوا الدُّنْيَا وَكَرِهُوا مَنْزِلَةَ أَهْلِهَا فَشَارَكُوهُمْ فِي الْعَيْشِ وَزَايَلُوهُمْ بِالْقَوْلِ وَدَافَعُوا بِالْقَوْلِ عَنْ أَنْفُسِهِمْ أَنْ يُنْسَبُوا إِلَى عَمَلِهِمْ فَلَمْ يَتَبَرَّءُوا مِمَّا انْتَفَوْا مِنْهُ وَلَمْ يَدْخُلُوا فِيمَا نَسَبُوا إِلَيْهِ أَنْفُسَهُمْ لِأَنَّ الْعَامِلَ بِالْحَقِّ مُتَكَلِّمٌ وَإِنْ سَكَتَ وَقَدْ ذُكِرَ أَنَّ اللَّهَ تَعَالَى يَقُولُ إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَنْظُرُ إِلَى هَمِّهِ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ لِي جَعَلْتُ صَمْتَهُ حَمْدًا وَوَقَارًا لِي وَإِنْ لَمْ يَتَكَلَّمْ وَقَالَ اللَّهُ تَعَالَى { مَثَلُ الَّذِينَ حُمِّلُوا التَّوْرَاةَ ثُمَّ لَمْ يَحْمِلُوهَا } لَمْ يَعْمَلُوا بِهَا { كَمَثَلِ الْحِمَارِ يَحْمِلُ أَسْفَارًا } كُتُبًا وَقَالَ { خُذُوا مَا آتَيْنَاكُمْ بِقُوَّةٍ } قَالَ الْعَمَلُ بِمَا فِيهِ وَلَا تَكْتَفُوا مِنْ السُّنَّةِ بِانْتِحَالِهَا بِالْقَوْلِ دُونَ الْعَمَلِ بِهَا فَإِنَّ انْتِحَالَ السُّنَّةِ دُونَ الْعَمَلِ بِهَا كَذِبٌ بِالْقَوْلِ مَعَ إِضَاعَةِ الْعَمَلِ وَلَا تَعِيبُوا بِالْبِدَعِ تَزَيُّنًا بِعَيْبِهَا فَإِنَّ فَسَادَ أَهْلِ الْبِدَعِ لَيْسَ بِزَائِدٍ فِي صَلَاحِكُمْ وَلَا تَعِيبُوهَا بَغْيًا عَلَى أَهْلِهَا فَإِنَّ الْبَغْيَ مِنْ فَسَادِ أَنْفُسِكُمْ وَلَيْسَ يَنْبَغِي لِلطَّبِيبِ أَنْ يُدَاوِيَ الْمَرْضَى بِمَا يُبَرِّئُهُمْ وَيُمْرِضُهُ فَإِنَّهُ إِذَا مَرِضَ اشْتَغَلَ بِمَرَضِهِ عَنْ مُدَاوَاتِهِمْ وَلَكِنْ يَنْبَغِي أَنْ يَلْتَمِسَ لِنَفْسِهِ الصِّحَّةَ لِيَقْوَى بِهِ عَلَى عِلَاجِ الْمَرْضَى فَلْيَكُنْ أَمْرُكُمْ فِيمَا تُنْكِرُونَ عَلَى إِخْوَانِكُمْ نَظَرًا مِنْكُمْ لِأَنْفُسِكُمْ وَنَصِيحَةً مِنْكُمْ لِرَبِّكُمْ وَشَفَقَةً مِنْكُمْ عَلَى إِخْوَانِكُمْ وَأَنْ تَكُونُوا مَعَ ذَلِكَ بِعُيُوبِ أَنْفُسِكُمْ أَعْنَى مِنْكُمْ بِعُيُوبِ غَيْرِكُمْ وَأَنْ يَسْتَطْعِمَ بَعْضُكُمْ بَعْضًا النَّصِيحَةَ وَأَنْ يَحْظَى عِنْدَكُمْ مَنْ بَذَلَهَا لَكُمْ وَقَبِلَهَا مِنْكُمْ وَقَدْ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَحِمَ اللَّهُ مَنْ أَهْدَى إِلَيَّ عُيُوبِي تُحِبُّونَ أَنْ تَقُولُوا فَيُحْتَمَلَ لَكُمْ وَإِنْ قِيلَ لَكُمْ مِثْلُ الَّذِي قُلْتُمْ غَضِبْتُمْ تَجِدُونَ عَلَى النَّاسِ فِيمَا تُنْكِرُونَ مِنْ ��ُمُورِهِمْ وَتَأْتُونَ مِثْلَ ذَلِكَ فَلَا تُحِبُّونَ أَنْ يُوجَدَ عَلَيْكُمْ اتَّهِمُوا رَأْيَكُمْ وَرَأْيَ أَهْلِ زَمَانِكُمْ وَتَثَبَّتُوا قَبْلَ أَنْ تَكَلَّمُوا وَتَعَلَّمُوا قَبْلَ أَنْ تَعْمَلُوا فَإِنَّهُ يَأْتِي زَمَانٌ يَشْتَبِهُ فِيهِ الْحَقُّ وَالْبَاطِلُ وَيَكُونُ الْمَعْرُوفُ فِيهِ مُنْكَرًا وَالْمُنْكَرُ فِيهِ مَعْرُوفًا فَكَمْ مِنْ مُتَقَرِّبٍ إِلَى اللَّهِ بِمَا يُبَاعِدُهُ وَمُتَحَبِّبٍ إِلَيْهِ بِمَا يُغْضِبُهُ عَلَيْهِ قَالَ اللَّهُ تَعَالَى { أَفَمَنْ زُيِّنَ لَهُ سُوءُ عَمَلِهِ فَرَآهُ حَسَنًا } الْآيَةَ فَعَلَيْكُمْ بِالْوُقُوفِ عِنْدَ الشُّبُهَاتِ حَتَّى يَبْرُزَ لَكُمْ وَاضِحُ الْحَقِّ بِالْبَيِّنَةِ فَإِنَّ الدَّاخِلَ فِيمَا لَا يَعْلَمُ بِغَيْرِ عِلْمٍ آثِمٌ وَمَنْ نَظَرَ لِلَّهِ نَظَرَ اللَّهُ لَهُ عَلَيْكُمْ بِالْقُرْآنِ فَأْتَمُّوا بِهِ وَأُمُّوا بِهِ وَعَلَيْكُمْ بِطَلَبِ أَثَرِ الْمَاضِينَ فِيهِ وَلَوْ أَنَّ الْأَحْبَارَ وَالرُّهْبَانَ لَمْ يَتَّقُوا زَوَالَ مَرَاتِبِهِمْ وَفَسَادَ مَنْزِلَتِهِمْ بِإِقَامَةِ الْكِتَابِ وَتِبْيَانِهِ مَا حَرَّفُوهُ وَلَا كَتَمُوهُ وَلَكِنَّهُمْ لَمَّا خَالَفُوا الْكِتَابَ بِأَعْمَالِهِمْ الْتَمَسُوا أَنْ يَخْدَعُوا قَوْمَهُمْ عَمَّا صَنَعُوا مَخَافَةَ أَنْ تَفْسُدَ مَنَازِلُهُمْ وَأَنْ يَتَبَيَّنَ لِلنَّاسِ فَسَادُهُمْ فَحَرَّفُوا الْكِتَابَ بِالتَّفْسِيرِ وَمَا لَمْ يَسْتَطِيعُوا تَحْرِيفَهُ كَتَمُوهُ فَسَكَتُوا عَنْ صَنِيعِ أَنْفُسِهِمْ إِبْقَاءً عَلَى مَنَازِلِهِمْ وَسَكَتُوا عَمَّا صَنَعَ قَوْمُهُمْ مُصَانَعَةً لَهُمْ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } بَلْ مَالَئُوا عَلَيْهِ وَرَقَّقُوا لَهُمْ فِيهِ","trj":"Telah mengabarkan kepada kami [Abdul Malik bin Sulaiman Abu Abdur Rahman Al `Anthaki] dari ['Abbad bin 'Abbad Al Khawwash As Syami Abu 'Utbah] ia berkata: \"Perhatian, gunakanlah akal, karena akal sebuah nikmat. Berapa banyak orang berakal menyibukkan hatinya untuk memperdalam hal-hal yang membahayakan dirinya daripada memanfaatkan apa yang dibutuhkannya, sehingga ia lupa hal itu. Diantara keutamaan akal seseorang adalah meninggalkan perhatian terhadap hal-hal yang tidak perlu sehingga keutamaan akalnya tidak menjadi bencana baginya, yaitu ia meninggalkan persaingan dengan orang yang lebih rendah amal shalihnya, atau seseorang yang menyibukkan hatinya dengan bid'ah, yang ia sekedar mengikuti orang dalam urusan agamanya tanpa mengikuti para sahabat Rasulullah shalallahu 'alahi wa sallam, atau ia hanya merasa cukup dengan pendapatnya sendiri, yang ia tidak melihat petunjuk kecuali kepada akalnya, dan tidak melihat kesesatan kecuali meninggalkannya dengan anggapan bahwa ia mengambilnya dari Al qur`an, padahal ia menyerukan untuk meninggalkan Al qur`an. Bukankah Al qur`an mempunyai pengemban-pengemban sebelumnya, yaitu para pembelanya yang mengamalkan ayat-ayat yang muhkam dan mengimani ayat-ayat yang mutasyabih? Mereka berada di menara layaknya cahaya jalan, Al Quran imam Rasulullah shalallahu'alahi wa sallam, sedang Rasulullah shallahu 'alaihi wa sallam imam para sahabatnya, dan para sahabat adalah imam orang-orang setelah mereka, yaitu orang-orang yang sudah dikenal kebaikannya, mereka menjadi barometer di negeri-negeri mereka yang sepakat menolak para pengagung hawa nafsu walaupun diantara mereka terdapat perselisihan pendapat. Para pengagum hawa nafsu meraba-raba dengan pendapat mereka, yaitu dengan cara yang bermacam-macam, yang melenceng dari tujuan karena memisahkan diri dari jalan yang lurus. Petunjuk mereka menyesatkan mereka sendiri dalam misteri padang pasir yang menyesatkan. Mereka konsentrasi melihat petunjuk jalan dengan penuh kebingungan dalam kesesatannya. Setiap kali setan membuat satu bid'ah dalam kesesatan, mereka berpindah dari satu bid'ah ke bid'ah lain, karena mereka tidak mencari petunjuk para pendahulu dan juga tidak mengikuti jejak kaum muhajirin. Telah disebutkan dalam satu riwayat dari Umar radliallahu 'anhu bahwa ia berkata kepada Ziad: 'Tahukah kamu apa yang (menyebabkan) kehancuran Islam? ', Jawabnya karena kesalahan orang berilmu, perdebatan orang munafik terhadap Al Qur`an dan para imam yang sesat'. Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan waspadailah apa yang terjadi pada ulama kamu dan pengisi masjid-masjid kamu dari perbuatan ghibah, namimah dan berjalan diantara manusia dengan dua wajah dan dua lisan. Dalam satu riwayat disebutkan barangsiapa mempunyai dua wajah di dunia, ia mempunyai dua wajah di neraka. Jika tukang ghibah menemuimu, ia menggunjing orang yang kamu senangi untuk di gunjing, lalu ia berpaling darimu untuk mendatangi temanmu dan melakukan hal yang sama. Jika ia telah memperoleh apa yang ia butuhkan dari setiap kalian, dan menyembunyikan sesuatu dari salah satu (dari) kalian, ia tidak memberi kabar kepada sahabatmu yang lain. Kedatangannya kepada orang yang didatanginya adalah seperti datangnya seorang teman, namun kepergiannya dari teman yang ditinggalkan bagaikan kepergian dari seorang musuh. Siapa saja yang menemuinya, ia dapatkan kemuliaan, sebaliknya siapa yang tidak ditemuinya, tidak ia dapatkan kehormatan, ia menipu orang yang didatanginya dengan penghargaan-penghargaan, dan menggunjing orang yang tidak ditemuinya dengan ghibah mematikan. Wahai hamba-hamba Allah subhanallahu wa ta'ala, tidakkah suatu kaum muncul penunjuk jalan dan reformis, yang ia sanggup mengekang orang seperti ini dari tipu dayanya, dan mengajaknya untuk mempertahankan kehormatan saudaranya semuslim?, bahkan kalau bisa memberitahu mereka niyat orang seperti ini saat datang menemui mereka, yang ia bertindak sekedar ingin memperoleh keperluannya sehingga mereka mempersilahkan, yang ujungnya ia mencaplok agamanya sekaligus agama mereka? Ya Allah, Ya Allah! Pertahankanlah kehormatan kamu, hentikanlah lisanmu (dari menggunjing) mereka kecuali kebaikan semata. Tolong kalian saling mengingatkan untuk berbakti kepada Allah khususnya terhadap umatmu, karena kamu adalah pengemban Al Kitab (Al Qur`an) dan sunah,. Al Kitab tidak berbicara hingga ia dibicarakan, dan sunnah tidak sanggup mengejawantahkan hingga ia diejawantahkan. Bilamana orang bodoh belajar, namun orang alim diam tidak memungkiri apa yang nampak dan tidak memerintahkan apa yang ditinggalkan', bukankah Allah subhanallahu wa ta'ala telah mengambil perjanjian dari orang-orang yang diberikan Al Kitab kepada mereka untuk menjelaskannya kepada manusia dan tidak menyembunyikannya?. Bertakwalah kepada Allah subhanallahu wa ta'ala, karena kamu berada pada zaman menipisnya sifat wara' dan kurangnya kekhusyu'an, dan para pengemban ilmu adalah para perusaknya. Mereka begitu marah jika dikenal sebagai orang-orang yang menghilangkannya, mereka membicarakannya dengan hawa nafsu ketika mengikutsertakan kesalahan dalam ilmu, dan memutarbalikkan perkataan dari kebenaran yang mereka tinggalkan, lantas mereka belokkan menuju kebatilan yang mereka kerjakan. Dosa mereka adalah dosa yang tidak diampuni dan kelalaian mereka adalah kelalaian yang tidak bisa dibenarkan, bagaimana orang yang mencari petunjuk dan tuntunan mendapatkan petunjuk apabila petunjuknya sendiri membingungkan, mereka cinta dunia dan benci terhadap kebahagiaan penduduknya yang memperoleh kedudukan tinggi, lantas mereka menyertai dalam kehidupan dan menyelisihi mereka dengan perkataan, dan mempertahankan diri mereka dengan perkataan, agar mereka dihubung-hubungkan dengan kebaikan mereka. Mereka sama sekali tidak bersih dari kotoran yang mereka hilangkan, dan belum memenuhi kriteria untuk dihargai amal mereka, sebab orang yang benar-benar beramal shalih secara tidak langsung ia ia telah bicara sekalipun dia diam. Dan telah diberitakan bahwa Allah Ta'ala berfirman; Aku tidak menerima semua semua perkataan orang bijak, akan tetapi Aku melihat kepada kecenderungan dan niyat baiknya untuk-Ku. Sebab siapa yang hasrat dan niyatnya untuk-Ku, Aku jadikan diamnya terpuji dan berwibawa, walaupun ia tidak berbicara. Allah subhanallahu wa ta'ala berfirman: \"MATSALULLADZINA HUMMILUT TAURATA TSUMMA LAM YAHMILUUHA KAMATSALIL HIMARI YAHMILUL ASFARA\" (Perumpamaan orang-orang yang dipikulkan kepadanya Taurat, kemudian mereka tidak memikulnya (tidak mengerjakannya) adalah seperti keledai yang membawa kitab-kitab yang tebal) -Qs. Al Jumu'ah: 5-, Allah subhanallahu wa ta'ala juga berfirman: \"KHUDZU MAA ATAINAAKUM BI QUWWAH\" (Peganglah teguh-teguh apa yang telah kami berikan kepadamu) -Qs. Al Baqarah: 63, 93, 171-, ia berkata: 'Maksudnya mengerjakan isi yang terkandung padanya, dan tidak mencukupkan sunnah hanya dengan ucapan tanpa pengalaman. Karena pensifatan sunnah dengan perkataan tanpa perbuatan adalah dusta dengan perkataan, yang sekaligus menghilangkan ilmu. Dan janganlah kamu mencela bid`ah sekedar untuk bungkus keindahanmu dengan meneropong aib-aibnya, karena kerusakan penganut bid`ah tidak menambah kesalehanmu, dan janganlah kamu mencelanya karena dorongan diskriminatif terhadap penganutnya, karena diskriminasi adalah kerusakan dirimu sendiri, sebab tidak selayaknya dokter mengobati pasien dengan obat yang berpotensi menyembuhkan penyakit namun obat itu juga berpotensi mendatangkan penyakit baru. Karena apabila dokter itu sakit, ia sibuk dengan penyakitnya dan lupa mengobati mereka. Akan tetapi selayaknya ia mencari kesehatan untuk dirinya agar ia dapat mengobati para pasien. Hendaklah saat engkau melihat masalah yang menimpa saudara-saudaramu dan hatimu \"kurang sreg\", sebagaimana engkau melihat jika terjadi pada dirimu sendiri dan sebagai \"peringatan\" Tuhanmu terhadapmu, serta rasa kasihanmu kepada saudara-saudara kamu. Walaupun dalam hal itu lebih baik kamu lebih peduli terhadap aib diri kamu sendiri dari pada aib orang lain, dan lakukan saling menasehati satu sama lain diantara kamu, dan hendaklah yang mengorbankan nasehat itu merasa beruntung dan kamu menerimanya. Umar bin Al Khatthab radliallahu 'anhu berkata: 'Semoga Allah subhanallahu wa ta'ala melimpahkan rahmat kepada orang yang menunjukkan aib-aibku kepadaku'. Kamu suka berkata dan orang yang mendengarmu menahan diri demi kebaikanmu, padahal jika dikatakan kepada kamu perkataan yang sama seperti yang kamu katakan, kamu jengkel. Kamu mendapatkan hal-hal yang menjengkelkanmu, sebaliknya kamu mengerjakan apa yang mereka kerjakan, apakah kamu tidak suka dipersalahkan? ', Pikir ulanglah pendapatmu dan pendapat orang-orang yang sezaman denganmu, Selidikilah dahulu sebuah berita sebelum kalian berbicara dan belajarlah sebelum kalian beramal. Karena nanti akan datang suatu zaman yang saat itu yang benar bercampur dengan yang batil, dan yang ma'ruf (baik) menjadi mungkar dan yang mungkar menjadi ma'ruf. Betapa banyak orang yang mendekatkan diri kepada Allah subhanallahu w ta'ala namun dengan hal-hal yang justru menjauhkan dariNya, dan mencari cintaNya dengan hal-hal yang membuatNya murka. Allah subhanallahu wa ta'ala berfirman: \"AFAMAN ZUYYINA LAHU SUU`U 'MALIHI FA RA`AHU HASANA\" (Maka apabila orang yang dijadikan (syaitan) menganggap baik pekerjaannya yang buruk lalu ia meyakini pekerjaan itu baik (sama dengan orang yang tidak ditipu syaitan)? -Qs. Al Fathir: 8-, hendaklah kamu berhenti dari hal-hal yang syubhat sehingga nampak bagi kamu kebenaran yang jelas disertai keterangan, karena orang yang mengintervensi perkara yang ia tidak tahu tanpa ilmu, ia berdosa, dan barangsiapa yang menyelidiki dengan niat ikhlash karena Allah, Allah subhanallahu wa ta'ala akan melihatnya. Hendaklah kamu berpegang teguh dengan Al Qur`an, jadikanlah ia imam dan ajaklah (manusia) untuk menjadikan Al Qur`an sebagai imam. Hendaknya kamu mencari jejak-jejak para pendahulu padanya. Seandainya para ahbar (pendeta yahudi) dan para rahib (pendeta Nashrani) tidak takut kehilangan martabat mereka dan kerusakan kedudukannya dengan menegakkan Al Kitab dan penjelasannya, niscaya mereka tidak akan menyelewengkan dan menyembunyikannya, akan tetapi mereka ketika menentang Al Kitab dengan perbuatan mereka, mereka berusaha mencari cara menipu kaumnya karena perbuatan yang mereka lakukan sendiri, karena mereka khawatir kedudukan mereka dirobohkan, dan manusia memperoleh kejelasan kerusakan mereka, lalu mereka selewengkan Al Kitab dengan tafsir menyeleweng, dan apa yang mereka tidak bisa selewengkan, mereka sembunyikan, lalu mereka diam terhadap perbuatan mereka sendiri karena dorongan untuk mempertahankan kedudukan mereka, dan diam terhadap apa yang diperbuat oleh kaumnya sambil berpura-pura. Sedang Allah subhanallahu wa ta'ala telah mengambil perjanjian dengan orang-orang yang di berikan Al Kitab agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya, akan tetapi mereka justru cenderung kepadanya dan mengajak manusia menganggap enteng masalah itu. "},{"p":"Malik","n":424,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسِيرُ فِي بَعْضِ أَسْفَارِهِ وَعُمَرُ بْنُ الْخَطَّابِيَسِيرُ مَعَهُ لَيْلًا فَسَأَلَهُ عُمَرُ عَنْ شَيْءٍ فَلَمْ يُجِبْهُ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ فَقَالَ عُمَرُ ثَكِلَتْكَ أُمُّكَ عُمَرُ نَزَرْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مَرَّاتٍ كُلُّ ذَلِكَ لَا يُجِيبُكَ قَالَ عُمَرُ فَحَرَّكْتُ بَعِيرِي حَتَّى إِذَا كُنْتُ أَمَامَ النَّاسِ وَخَشِيتُ أَنْ يُنْزَلَ فِيَّ قُرْآنٌ فَمَا نَشِبْتُ أَنْ سَمِعْتُ صَارِخًا يَصْرُخُ بِي قَالَ فَقُلْتُ لَقَدْ خَشِيتُ أَنْ يَكُونَ نَزَلَ فِيَّ قُرْآنٌ قَالَ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْتُ عَلَيْهِ فَقَالَ لَقَدْ أُنْزِلَتْ عَلَيَّ هَذِهِ اللَّيْلَةَ سُورَةٌ لَهِيَ أَحَبُّ إِلَيَّ مِمَّا طَلَعَتْ عَلَيْهِ الشَّمْسُ ثُمَّ قَرَأَ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا","trj":"Telah menceritakan kepadaku dari Malik dari [Zaid bin Aslam] dari [Bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam berada dalam salah satu perjalanannya, dan [Umar bin Khattab] bersama beliau pada malam hari itu. Umar bertanya kepada beliau tentang suatu hal, namun beliau tidak menjawabnya. Dia bertanya lagi, namun beliau tetap tidak menjawab. Dia bertanya lagi, namun beliau tetap tidak menjawab. 'Umar pun berkata, \"Celaka engkau wahai Umar! Engkau telah memaksa Rasulullah shallallahu 'alaihi wasallam tiga kali, namun semuanya itu tidak ada yang dijawabnya.\" 'Umar berkata, \"Aku gerakkan untaku, sampai ketika aku di hadapan orang-orang, aku khawatir jika turun padaku Al qur'an. Dan tidak berapa lama, aku mendengar orang yang berteriak ke arahku.\" 'Umar berkata, \"Aku berkata, \"Aku khawatir jika ada ayat yang turun kepadaku.\" 'Umar berkata lagi, \"Aku lalu mendatangi Rasulullah shallallahu 'alaihi wasallam, dan mengucapkan salam kepadanya. Beliau bersabda: 'Telah turun padaku tadi malam satu surat, yang lebih aku cintai daripada terbitnya matahari.\" Kemudian beliau membaca: \"'INNAA FATAHNAA LAKA FATHAN MUBIINA (Sesungguhnya Kami telah memberikan kepada kamu kemenangan yang nyata.\" (Qs. Al Fath: 1) ."},{"p":"Muslim","n":1242,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَوَكِيعٌ عَنْ شُعْبَةَ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ الْمُزَنِيَّ يَقُولُاقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ فِي مَسِيرٍ لَهُ سُورَةَ الْفَتْحِ عَلَى رَاحِلَتِهِ فَرَجَّعَ فِي قِرَاءَتِهِقَالَ مُعَاوِيَةُ لَوْلَا أَنِّي أَخَافُ أَنْ يَجْتَمِعَ عَلَيَّ النَّاسُ لَحَكَيْتُ لَكُمْ قِرَاءَتَهُ","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dan [Waki'] dari [Syu'bah] dari [Mu'awiyah bin Qurrah] ia berkata, saya mendengar [Abdullah bin Mughaffal Al Muzani] berkata; Nabi shallallahu 'alaihi wasallam membaca surat Al Fath pada tahun Al Fath (penaklukan kota Makkah) dalam suatu perjalanan disaat beliau berada di atas kendaraannya. Kemudian beliau mengulang-mengulang bacaannya. Mu'awiyah berkata; \"Sekiranya aku tidak khawatir manusia akan berkumpul mengerumuniku, niscaya akan saya ceritakan kepada kalian seperti apa bacaan beliau.\""},{"p":"Muslim","n":1243,"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ عَلَى نَاقَتِهِ يَقْرَأُ سُورَةَ الْفَتْحِقَالَ فَقَرَأَ ابْنُ مُغَفَّلٍ وَرَجَّعَ فَقَالَ مُعَاوِيَةُ لَوْلَا النَّاسُ لَأَخَذْتُ لَكُمْ بِذَلِكَ الَّذِي ذَكَرَهُ ابْنُ مُغَفَّلٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنَاه يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي قَالَا حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَفِي حَدِيثِ خَالِدِ بْنِ الْحَارِثِ قَالَ عَلَى رَاحِلَةٍ يَسِيرُ وَهُوَ يَقْرَأُ سُورَةَ الْفَتْحِ","trj":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] -Ibnul Mutsanna- berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] ia berkata, saya mendengar [Abdullah bin Mughaffal], ia berkata; Pada hari Fathu Makkah, saya melihat Rasulullah shallallahu 'alaihi wasallam di atas untanya membaca surat Al Fath. Ibnu Mughaffal pun membacanya dan mengulangi bacaannya kembali. Kemudian Mu'awiyah berkata, \"Sekiranya bukan karena (akan berkumpulnya) manusia, niscaya saya melakukan seperti yang telah disebutkan oleh Ibnu Mughaffal dari Nabi shallallahu 'alaihi wasallam.\" Dan telah menceritakannya kepada kami [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid bin Harits] -dalam jalur lain- Dan telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [bapakku] ia berkata, telah menceritakan kepada kami [Syu'bah] dengan isnad ini semisalnya. Dan di dalam hadits Khalid bin Harits, ia berkata; \"Di atas kendaraannya yang berjalan, sementara beliau membaca surat Al Fath.\""},{"p":"Muslim","n":3105,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَتَقَارَبَا فِي اللَّفْظِ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ سِيَاهٍ حَدَّثَنَا حَبِيبُ بْنُ أَبِي ثَابِتٍ عَنْ أَبِي وَائِلٍ قَالَقَامَ سَهْلُ بْنُ حُنَيْفٍ يَوْمَ صِفِّينَ فَقَالَ أَيُّهَا النَّاسُ اتَّهِمُوا أَنْفُسَكُمْ لَقَدْ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِ وَلَوْ نَرَى قِتَالًا لَقَاتَلْنَا وَذَلِكَ فِي الصُّلْحِ الَّذِي كَانَ بَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ الْمُشْرِكِينَ فَجَاءَ عُمَرُ بْنُ الْخَطَّابِ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَلَسْنَا عَلَى حَقٍّ وَهُمْ عَلَى بَاطِلٍ قَالَ بَلَى قَالَ أَلَيْسَ قَتْلَانَا فِي الْجَنَّةِ وَقَتْلَاهُمْ فِي النَّارِ قَالَ بَلَى قَالَ فَفِيمَ نُعْطِي الدَّنِيَّةَ فِي دِينِنَا وَنَرْجِعُ وَلَمَّا يَحْكُمِ اللَّهُ بَيْنَنَا وَبَيْنَهُمْ فَقَالَ يَا ابْنَ الْخَطَّابِ إِنِّي رَسُولُ اللَّهِ وَلَنْ يُضَيِّعَنِي اللَّهُ أَبَدًا قَالَ فَانْطَلَقَ عُمَرُ فَلَمْ يَصْبِرْ مُتَغَيِّظًا فَأَتَى أَبَا بَكْرٍ فَقَالَ يَا أَبَا بَكْرٍ أَلَسْنَا عَلَى حَقٍّ وَهُمْ عَلَى بَاطِلٍ قَالَ بَلَى قَالَ أَلَيْسَ قَتْلَانَا فِي الْجَنَّةِ وَقَتْلَاهُمْ فِي النَّارِ قَالَ بَلَى قَالَ فَعَلَامَ نُعْطِي الدَّنِيَّةَ فِي دِينِنَا وَنَرْجِعُ وَلَمَّا يَحْكُمِ اللَّهُ بَيْنَنَا وَبَيْنَهُمْ فَقَالَ يَا ابْنَ الْخَطَّابِ إِنَّهُ رَسُولُ اللَّهِ وَلَنْ يُضَيِّعَهُ اللَّهُ أَبَدًا قَالَ فَنَزَلَ الْقُرْآنُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْفَتْحِ فَأَرْسَلَ إِلَى عُمَرَ فَأَقْرَأَهُ إِيَّاهُ فَقَالَ يَا رَسُولَ اللَّهِ أَوْ فَتْحٌ هُوَ قَالَ نَعَمْ فَطَابَتْ نَفْسُهُ وَرَجَعَ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Numair] sedangkan lafadznya saling berdekatan, telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Abdul Aziz bin Siyah] telah menceritakan kepada kami [Habib bin Abu Tsabit] dari [Abu Wa`il] dia berkata, \" [Sahal bin Hunaif] pernah berdiri ketika terjadi perang Shifin, dia berseru, \"Wahai manusia, koreksilah diri kalian masing-masing. Ketika terjadi perjanjian Hudaibiyyah, kami bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam. Seandainya waktu itu kami melihat adanya pembunuhan, pasti kami telah berperang. Hal ini terjadi ketika terjadi perjanjian damai antara Rasulullah shallallahu 'alaihi wasallam dengan orang-orang Musyrik. Maka umar bin Khatthab datang menghampiri Rasulullah shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, tidakkah kita dalam kebenaran dan mereka dalam kebathilan?\" beliau bersabda: \"Ya.\" Dia berkata, \"Bukankah jika kita terbunuh akan masuk surga? sedangkan jika mereka terbunuh, mereka akan masuk neraka?\" beliau menjawab: \"Ya benar.\" Umar bertanya, \"Mengapakah kita harus mengalah mengenai agama kita, dan pulang begitu saja? Padahal Allah belum memberikan keputusan apa-apa antara kita dengan mereka?\" Beliau menjawab: \"Wahai Ibnul Khattab, sesungguhnya aku adalah Rasulullah, dan sekali-kali Allah tidak akan menyia-nyiakan aku selama-lamanya.\" Abu Wa'il berkata, \"Umar lalu pergi dalam keadaan tidak puas, bahkan terlihat marah. Lalu dia mendatangi Abu Bakar seraya berkata, \"Wahai Abu Bakar, bukankah kita di atas yang hak dan mereka dalam kebathilan.\" Dia menjawab, \"Ya, benar.\" Umar bertanya, \"Tidakkah jika kita terbunuh, maka kita akan masuk surga, sedangkan jika mereka yang terbunuh, maka mereka akan masuk neraka?\" Abu Bakar menjawab, \"Ya, benar.\" Umar bertanya lagi, \"Mengapakah kita harus mengalah mengenai agama kita, dan pulang begitu saja? Padahal Allah belum memberikan keputusan apa-apa antara kita dengan mereka?\" Maka Abu Bakar berkata, \"Wahai Ibnul Khattab, sesungguhnya beliau adalah Rasulullah, dan sekali-kali Allah tidak akan menyia-nyiakan beliau selama-lamanya.\" Suhail berkata, \"Maka turunlah ayat Al Qur'an kepada Rasulullah, yaitu surat Al Fath. Maka beliau menyuruh seseorang untuk membacakan kepada Umar, lantas dia bertanya, \"Wahai Rasulullah, apakah itu yang dimaksud dengan kemenangan?\" beliau bersabda: \"Ya, benar.\" Barulah dia bertaubat dan kembali.\""},{"p":"Muslim","n":3108,"ar":"و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْ قَالَلَمَّا نَزَلَتْ{ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا لِيَغْفِرَ لَكَ اللَّهُ إِلَى قَوْلِهِ فَوْزًا عَظِيمًا }مَرْجِعَهُ مِنْ الْحُدَيْبِيَةِ وَهُمْ يُخَالِطُهُمْ الْحُزْنُ وَالْكَآبَةُ وَقَدْ نَحَرَ الْهَدْيَ بِالْحُدَيْبِيَةِ فَقَالَ لَقَدْ أُنْزِلَتْ عَلَيَّ آيَةٌ هِيَ أَحَبُّ إِلَيَّ مِنْ الدُّنْيَا جَمِيعًاو حَدَّثَنَا عَاصِمُ بْنُ النَّض��رِ التَّيْمِيُّ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا هَمَّامٌ ح و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ جَمِيعًا عَنْ قَتَادَةَ عَنْ أَنَسٍ نَحْوَ حَدِيثِ ابْنِ أَبِي عَرُوبَةَ","trj":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahzhami] telah menceritakan kepada kami [Khalid bin Al Harits] berkata, telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] bahwa [Anas bin Malik] telah menceritakan kepada mereka, dia berkata, \"Ketika turun ayat: '(Sesungguhnya kami telah memberikan kepadamu kemenangan yang nyata, supaya Allah memberikan ampunan kepadamu terhadap dosamu -hingga firmanNya- dengan pertolongan yang kuat (banyak).' (Qs. Al Fath: 1-3), ketika itu mereka baru pulang dari Hudaibiyyah dengan diliputi perasaan jengkel dan kesal, padahal mereka telah menyembelih binatang kurban. Maka beliau bersabda: \"Sungguh telah turun kepadaku suatu ayat yang lebih aku cintai daripada dunia dan isinya.\" Dan telah menceritakan kepada kami ['Ashim bin An Nadlr At Taimi] telah menceritakan kepada kami [Mu'tamir] dia berkata; aku mendengar [ayahku] telah menceritakan kepada kami [Qatadah] dia berkata; aku pernah mendengar [Anas bin Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Hammam] (dalam jalur lain disebutkan) telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban] semuanya dari [Qatadah] dari [Anas] sebagaimana hadits Ibnu Abu 'Arubah.\""},{"p":"Muslim","n":3139,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَبُو عَامِرٍ الْعَقَدِيُّ كِلَاهُمَا عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ وَهَذَا حَدِيثُهُ أَخْبَرَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا عِكْرِمَةُ وَهُوَ ابْنُ عَمَّارٍ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ حَدَّثَنِي أَبِي قَالَقَدِمْنَا الْحُدَيْبِيَةَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ أَرْبَعَ عَشْرَةَ مِائَةً وَعَلَيْهَا خَمْسُونَ شَاةً لَا تُرْوِيهَا قَالَ فَقَعَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى جَبَا الرَّكِيَّةِ فَإِمَّا دَعَا وَإِمَّا بَصَقَ فِيهَا قَالَ فَجَاشَتْ فَسَقَيْنَا وَاسْتَقَيْنَا قَالَ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَانَا لِلْبَيْعَةِ فِي أَصْلِ الشَّجَرَةِ قَالَ فَبَايَعْتُهُ أَوَّلَ النَّاسِ ثُمَّ بَايَعَ وَبَايَعَ حَتَّى إِذَا كَانَ فِي وَسَطٍ مِنْ النَّاسِ قَالَ بَايِعْ يَا سَلَمَةُ قَالَ قُلْتُ قَدْ بَايَعْتُكَ يَا رَسُولَ اللَّهِ فِي أَوَّلِ النَّاسِ قَالَ وَأَيْضًا قَالَ وَرَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَزِلًا يَعْنِي لَيْسَ مَعَهُ سِلَاحٌ قَالَ فَأَعْطَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَفَةً أَوْ دَرَقَةً ثُمَّ بَايَعَ حَتَّى إِذَا كَانَ فِي آخِرِ النَّاسِ قَالَ أَلَا تُبَايِعُنِي يَا سَلَمَةُ قَالَ قُلْتُ قَدْ بَايَعْتُكَ يَا رَسُولَ اللَّهِ فِي أَوَّلِ النَّاسِ وَفِي أَوْسَطِ النَّاسِ قَالَ وَأَيْضًا قَالَ فَبَايَعْتُهُ الثَّالِثَةَ ثُمَّ قَالَ لِي يَا سَلَمَةُ أَيْنَ حَجَفَتُكَ أَوْ دَرَقَتُكَ الَّتِي أَعْطَيْتُكَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ لَقِيَنِي عَمِّي عَامِرٌ عَزِلًا فَأَعْطَيْتُهُ إِيَّاهَا قَالَ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّكَ كَالَّذِي قَالَ الْأَوَّلُ اللَّهُمَّ أَبْغِنِي حَبِيبًا هُوَ أَحَبُّ إِلَيَّ مِنْ نَفْسِي ثُمَّ إِنَّ الْمُشْرِكِينَ رَاسَلُونَا الصُّلْحَ حَتَّى مَشَى بَعْضُنَا فِي بَعْضٍ وَاصْطَلَحْنَا قَالَ وَكُنْتُ تَبِيعًا لِطَلْحَةَ بْنِ عُبَيْدِ اللَّهِ أَسْقِي فَرَسَهُ وَأَحُسُّهُ وَأَخْدِمُهُ وَآكُلُ مِنْ طَعَامِهِ وَتَرَكْتُ أَهْلِي وَمَالِي مُهَاجِرًا إِلَى اللَّهِ وَرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَلَمَّا اصْطَلَحْنَا نَحْنُ وَأَهْلُ مَكَّةَ وَاخْتَلَطَ بَعْضُنَا بِبَعْضٍ أَتَيْتُ شَجَرَةً فَكَسَحْتُ شَوْكَهَا فَاضْطَجَعْتُ فِي أَصْلِهَا قَالَ فَأَتَانِي أَرْبَعَةٌ مِنْ الْمُشْرِكِينَ مِنْ أَهْلِ مَكَّةَ فَجَعَلُوا يَقَعُونَ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبْغَضْتُهُمْ فَتَحَوَّلْتُ إِلَى شَجَرَةٍ أُخْرَى وَعَلَّقُوا سِلَاحَهُمْ وَاضْطَجَعُوا فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ نَادَى مُنَادٍ مِنْ أَسْفَلِ الْوَادِي يَا لِلْمُهَاجِرِينَ قُتِلَ ابْنُ زُنَيْمٍ قَالَ فَاخْتَرَطْتُ سَيْفِي ثُمَّ شَدَدْتُ عَلَى أُولَئِكَ الْأَرْبَعَةِ وَهُمْ رُقُودٌ فَأَخَذْتُ سِلَاحَهُمْ فَجَعَلْتُهُ ضِغْثًا فِي يَدِي قَالَ ثُمَّ قُلْتُ وَالَّذِي كَرَّمَ وَجْهَ مُحَمَّدٍ لَا يَرْفَعُ أَحَدٌ مِنْكُمْ رَأْسَهُ إِلَّا ضَرَبْتُ الَّذِي فِيهِ عَيْنَاهُ قَالَ ثُمَّ جِئْتُ بِهِمْ أَسُوقُهُمْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَجَاءَ عَمِّي عَامِرٌ بِرَجُلٍ مِنْ الْعَبَلَاتِ يُقَالُ لَهُ مِكْرَزٌ يَقُودُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى فَرَسٍ مُجَفَّفٍ فِي سَبْعِينَ مِنْ الْمُشْرِكِينَ فَنَظَرَ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ دَعُوهُمْ يَكُنْ لَهُمْ بَدْءُ الْفُجُورِ وَثِنَاهُ فَعَفَا عَنْهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْزَلَ اللَّهُ{ وَهُوَ الَّذِي كَفَّ أَيْدِيَهُمْ عَنْكُمْ وَأَيْدِيَكُمْ عَنْهُمْ بِبَطْنِ مَكَّةَ مِنْ بَعْدِ أَنْ أَظْفَرَكُمْ عَلَيْهِمْ }الْآيَةَ كُلَّهَا قَالَ ثُمَّ خَرَجْنَا رَاجِعِينَ إِلَى الْمَدِينَةِ فَنَزَلْنَا مَنْزِلًا بَيْنَنَا وَبَيْنَ بَنِي لَحْيَانَ جَبَلٌ وَهُمْ الْمُشْرِكُونَ فَاسْتَغْفَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَنْ رَقِيَ هَذَا الْجَبَلَ اللَّيْلَةَ كَأَنَّهُ طَلِيعَةٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابِهِ قَالَ سَلَمَةُ فَرَقِيتُ تِلْكَ اللَّيْلَةَ مَرَّتَيْنِ أَوْ ثَلَاثًا ثُمَّ قَدِمْنَا الْمَدِينَةَ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِظَهْرِهِ مَعَ رَبَاحٍ غُلَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ وَخَرَجْتُ مَعَهُ بِفَرَسِ طَلْحَةَ أُنَدِّيهِ مَعَ الظَّهْرِ فَلَمَّا أَصْبَحْنَا إِذَا عَبْدُ الرَّحْمَنِ الْفَزَارِيُّ قَدْ أَغَارَ عَلَى ظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَاقَهُ أَجْمَعَ وَقَتَلَ رَاعِيَهُ قَالَ فَقُلْتُ يَا رَبَاحُ خُذْ هَذَا الْفَرَسَ فَأَبْلِغْهُ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ وَأَخْبِرْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْمُشْرِكِينَ قَدْ أَغَارُوا عَلَى سَرْحِهِ قَالَ ثُمَّ قُمْتُ عَلَى أَكَمَةٍ فَاسْتَقْبَلْتُ الْمَدِينَةَ فَنَادَيْتُ ثَلَاثًا يَا صَبَاحَاهْ ثُمَّ خَرَجْتُ فِي آثَارِ الْقَوْمِ أَرْمِيهِمْ بِالنَّبْلِ وَأَرْتَجِزُ أَقُولُ أَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِفَأَلْحَقُ رَجُلًا مِنْهُمْ فَأَصُكُّ سَهْمًا فِي رَحْلِهِ حَتَّى خَلَصَ نَصْلُ السَّهْمِ إِلَى كَتِفِهِ قَالَ قُلْتُ خُذْهَا وَأَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِقَالَ فَوَاللَّهِ مَا زِلْتُ أَرْمِيهِمْ وَأَعْقِرُ بِهِمْ فَإِذَا رَجَعَ إِلَيَّ فَارِسٌ أَتَيْتُ شَجَرَةً فَجَلَسْتُ فِي أَصْلِهَا ثُمَّ رَمَيْتُهُ فَعَقَرْتُ بِهِ حَتَّى إِذَا تَضَايَقَ الْجَبَلُ فَدَخَلُوا فِي تَضَايُقِهِ عَلَوْتُ الْجَبَلَ فَجَعَلْتُ أُرَدِّيهِمْ بِالْحِجَارَةِ قَالَ فَمَا زِلْتُ كَذَلِكَ أَتْبَعُهُمْ حَتَّى مَا خَلَقَ اللَّهُ مِنْ بَعِيرٍ مِنْ ظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا خَلَّفْتُهُ وَرَاءَ ظَهْرِي وَخَلَّوْا بَيْنِي وَبَيْنَهُ ثُمَّ اتَّبَعْتُهُمْ أَرْمِيهِمْ حَتَّى أَلْقَوْا أَكْثَرَ مِنْ ثَلَاثِينَ بُرْدَةً وَثَلَاثِينَ رُمْحًا يَسْتَخِفُّونَ وَلَا يَطْرَحُونَ شَيْئًا إِلَّا جَعَلْتُ عَلَيْهِ آرَامًا مِنْ الْحِجَارَةِ يَعْرِفُهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ حَتَّى أَتَوْا مُتَضَايِقًا مِنْ ثَنِيَّةٍ فَإِذَا هُمْ قَدْ أَتَاهُمْ فُلَانُ بْنُ بَدْرٍ الْفَزَارِيُّ فَجَلَسُوا يَتَضَحَّوْنَ يَعْنِي يَتَغَدَّوْنَ وَجَلَسْتُ عَلَى رَأْسِ قَرْنٍ قَالَ الْفَزَارِيُّ مَا هَذَا الَّذِي أَرَى قَالُوا لَقِينَا مِنْ هَذَا الْبَرْحَ وَاللَّهِ مَا فَارَقَنَا مُنْذُ غَلَسٍ يَرْمِينَا حَتَّى انْتَزَعَ كُلَّ شَيْءٍ فِي أَيْدِينَا قَالَ فَلْيَقُمْ إِلَيْهِ نَفَرٌ مِنْكُمْ أَرْبَعَةٌ قَالَ فَصَعِدَ إِلَيَّ مِنْهُمْ أَرْبَعَةٌ فِي الْجَبَلِ قَالَ فَلَمَّا أَمْكَنُونِي مِنْ الْكَلَامِ قَالَ قُلْتُ هَلْ تَعْرِفُونِي قَالُوا لَا وَمَنْ أَنْتَ قَالَ قُلْتُ أَنَا سَلَمَةُ بْنُ الْأَكْوَعِ وَالَّذِي كَرَّمَ وَجْهَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَطْلُبُ رَجُلًا مِنْكُمْ إِلَّا أَدْرَكْتُهُ وَلَا يَطْلُبُنِي رَجُلٌ مِنْكُمْ فَيُدْرِكَنِي قَالَ أَحَدُهُمْ أَنَا أَظُنُّ قَالَ فَرَجَعُوا فَمَا بَرِحْتُ مَكَانِي حَتَّى رَأَيْتُ فَوَارِسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَلَّلُونَ الشَّجَرَ قَالَ فَإِذَا أَوَّلُهُمْ الْأَخْرَمُ الْأَسَدِيُّ عَلَى إِثْرِهِ أَبُو قَتَادَةَ الْأَنْصَارِيُّ وَعَلَى إِثْرِهِ الْمِقْدَادُ بْنُ الْأَسْوَدِ الْكِنْدِيُّ قَالَ فَأَخَذْتُ بِعِنَانِ الْأَخْرَمِ قَالَ فَوَلَّوْا مُدْبِرِينَ قُلْتُ يَا أَخْرَمُ احْذَرْهُمْ لَا يَقْتَطِعُوكَ حَتَّى يَلْحَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ قَالَ يَا سَلَمَةُ إِنْ كُنْتَ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَتَعْلَمُ أَنَّ الْجَنَّةَ حَقٌّ وَالنَّارَ حَقٌّ فَلَا تَحُلْ بَيْنِي وَبَيْنَ الشَّهَادَةِ قَالَ فَخَلَّيْتُهُ فَالْتَقَى هُوَ وَعَبْدُ الرَّحْمَنِ قَالَ فَعَقَرَ بِعَبْدِ الرَّحْمَنِ فَرَسَهُ وَطَعَنَهُ عَبْدُ الرَّحْمَنِ فَقَتَلَهُ وَتَحَوَّلَ عَلَى فَرَسِهِ وَلَحِقَ أَبُو قَتَادَةَ فَارِسُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَبْدِ الرَّحْمَنِ فَطَعَنَهُ فَقَتَلَهُ فَوَالَّذِي كَرَّمَ وَجْهَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَتَبِعْتُهُمْ أَعْدُو عَلَى رِجْلَيَّ حَتَّى مَا أَرَى وَرَائِي مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا غُبَارِهِمْ شَيْئًا حَتَّى يَعْدِلُوا قَبْلَ غُرُوبِ الشَّمْسِ إِلَى شِعْبٍ فِيهِ مَاءٌ يُقَالُ لَهُ ذَو قَرَدٍ لِيَشْرَبُوا مِنْهُ وَهُمْ عِطَاشٌ قَالَ فَنَظَرُوا إِلَيَّ أَعْدُو وَرَاءَهُمْ فَخَلَّيْتُهُمْ عَنْهُ يَعْنِي أَجْلَيْتُهُمْ عَنْهُ فَمَا ذَاقُوا مِنْهُ قَطْرَةً قَالَ وَيَخْرُجُونَ فَيَشْتَدُّونَ فِي ثَنِيَّةٍ قَالَ فَأَعْدُو فَأَلْحَقُ رَجُلًا مِنْهُمْ فَأَصُكُّهُ بِسَهْمٍ فِي نُغْضِ كَتِفِهِ قَالَ قُلْتُ خُذْهَا وَأَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِقَالَ يَا ثَكِلَتْهُ أُمُّ��ُ أَكْوَعُهُ بُكْرَةَ قَالَ قُلْتُ نَعَمْ يَا عَدُوَّ نَفْسِهِ أَكْوَعُكَ بُكْرَةَ قَالَ وَأَرْدَوْا فَرَسَيْنِ عَلَى ثَنِيَّةٍ قَالَ فَجِئْتُ بِهِمَا أَسُوقُهُمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَلَحِقَنِي عَامِرٌ بِسَطِيحَةٍ فِيهَا مَذْقَةٌ مِنْ لَبَنٍ وَسَطِيحَةٍ فِيهَا مَاءٌ فَتَوَضَّأْتُ وَشَرِبْتُ ثُمَّ أَتَيْتُ رَسُولَ اللّ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Hasyim Ibnul Qasim]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abu Amir Al Aqadi] keduanya dari [Ikrimah bin Ammar]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdullah bin 'Abdurrahman Ad Darimi] dan ini adalah haditsnya. Telah mengabarkan kepada kami [Abu Ali Al Hanafi Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Ikrimah] -yaitu Ibnu Ammar- telah menceritakan kepadaku [Iyas bin Salamah] dari [ayahnya] dia berkata, \"Kami pernah ikut perang bersama Rasulullah shallallahu 'alaihi wasallam ke Hudaibiyah, pada saat itu kami berjumlah seribu empat ratus orang, dan kami hanya membawa lima puluh ekor kambing, sehingga air susu kambing sejumlah itu tidak cukup untuk kami minum. Setelah itu, Rasulullah shallallahu 'alaihi wasallam duduk di dekat sumur sambil berdo'a atau meludahinya. Berkat do'a yang dibacakan Rasulullah shallallahu 'alaihi wasallam kepada air susu kambing tersebut, maka kami semua dapat meminum air susu dengan sepuas-puasnya. Kemudian Rasulullah shallallahu 'alaihi wasallam mengajak kami untuk berbai'at kepada beliau di bawah pohon. Aku berbaiat kepada Rasulullah shallallahu 'alaihi wasallam pada rombongan pertama. Kemudian beliau terus menerima pembaiatan dari para sahabat yang hadir pada saat itu. Ketika sampai pada rombongan yang berada di tengah, Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Barbaiatlah wahai Salamah.\" Aku pun berkata kepada beliau, \"Aku telah berbaiat kepada anda pada rombongan pertama wahai Rasulullah.\" Namun beliau justru bersabda kepadaku: \"Berbaiatlah lagi waahi Salamah.\" Aku akhirnya menuruti permintaan beliau. Ketika beliau melihat aku tidak membawa senjata sama sekali, maka Rasulullah shallallahu 'alaihi wasallam memberikan tameng atau perisai kepadaku. Selanjutnya beliau menerima pembaiatan lagi dari rombongan yang terakhir. Pada saat itu, beliau kembali bertanya kepada aku: \"Mengapa kamu tidak ikut berbaiat kepadaku wahai Salamah?\" Aku menjawab, \"Aku telah berbaiat kepadamu wahai Rasulullah, bahkan tadi aku telah berbaiat kepada anda hingga dua kali, yaitu pada rombongan pertama dan rombongan pertengahan.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berbaiatlah sekali lagi wahai Salamah!\" Akhirnya aku ikut berbaiat kepada beliau untuk yang ketiga kalinya. Selesai berbaiat, Rasulullah shallallahu 'alaihi wasallam bertanya kepadaku: \"Wahai Salamah, mana tameng dan perisai yang aku berikan kepadamu?\" aku mencoba menjelaskan pertanyaan beliau, \"Wahai Rasulullah, tadi aku bertemu dengan pamanku, Amir, ternyata dia juga tidak mempunyai senjata sama sekali, maka tameng itu aku berikan kepadanya.\" Mendengar penjelasan itu, Rasulullah shallallahu 'alaihi wasallam tersenyum sambil bersabda: \"Sesungguhnya kamu seperti apa yang dikatakan oleh orang-orang dahulu, 'Ya Allah, ya Rabbku, berikanlah aku seorang kekasih yang lebih aku cintai daripada diriku sendiri'.\" Beberapa hari kemudian, kaum Musyrikin mengajak kami berdamai dengan cara mengirim kurir terlebih dahulu. Setelah mengalami proses yang tidak begitu lama, akhirnya kami sepakat untuk berdamai. Dahulu aku adalah pelayan Thalhah bin Ubaidillah, tugasku memberi minum kuda dan memandikannya. Sebagai imbalan dari pelayanannya tersebut, aku mendapatkan makan darinya. Aku memang bertekat untuk meninggalkan keluarga dan hartaku untuk berhijrah di jalan Allah dan Rasul-Nya. Ketika kesepakatan perjanjian damai antara kami dengan penduduk Makkah telah terjalin, hingga kami sudah bisa saling berbaur, maka suatu hari aku pergi menuju pepohonan untuk beristirahat di bawahnya. Pada saat berbaring di bawah pohon itulah, tiba-tiba datang empat orang Musyrikin dari peduduk kota Makkah yang tengah menggunjing Rasulullah shallallahu 'alaihi wasallam hingga membuat aku geram terhadap mereka. Lalu aku pidah ke batang pohon lainnya sambil melihat mereka menggantungkan senjatanya dan setelah itu mereka tertidur. Pada saat itulah, tiba-tiba terdengar suara orang yang menyeru dari dasar jurang, \"Hai kaum Muhajirin, Ibnu Zunaim telah terbunuh.\" Seketika itu juga aku cabut sambil mendatangi keempat orang musyrikin yang tengah tidur tersebut, aku ambil senjata mereka.\" Salamah melanjutkan, \"Setelah itu aku berkata kepada mereka, 'Demi dzat yang telah memuliakan wajah Muhammad, barangsiapa ada di antara kalian berani mengangkat kepalanya, maka akan kutebas lehernya.' Akhirnya keempat orang kafir Qurasiy tersebut aku giring ke hadapan Rasulullah shallallahu 'alaihi wasallam. Pada saat yang bersamaan aku melihat Amir, paman aku. Ternyata dia juga tengah menggiring seorang laki-laki Quraisy yang bernama Mikraz untuk di ajukan ke hadapan Rasulullah shallallahu 'alaihi wasallam. Lelaki Quraisy yang bernama Mikraz tersebut dibiarkan mengendarai seekor kuda yang ternyata diikuti sekitar tiga puluh orang musyrikin dari anak buahnya. Sejenak Rasulullah shallallahu 'alaihi wasallam memandangi mereka sambil bersabda: \"Biarkanlah mereka, karena mereka akan menaggung kezalimannya dari awal sampai akhir.\" Kemudian Rasulullah shallallahu 'alaihi wasallam memaafkan mereka, maka Allah menurunkan ayat: '(Dan Dialah yang menahan tangan mereka dari (membinasakan) kamu dan (menahan) tangan kamu dari (membinasakan) mereka di tengah kota Makkah setelah Allah memenangkan kamu atas mereka) ' (Qs. Al Fath: 24). Setelah kejadian itu, kami kembali pulang bersama-sama ke kota Madinah dengan membawa kemenangan. Namun sebelumnya, kami berhenti di suatu tempat. Sedangkan jarak kami dengan Bani Lihyan saat itu hanya dipisahkan oleh gunung, menurut informasi yang aku ketahui, kaum Bani Lihyan juga termasuk dari orang-orang Musyrik. Kemudian Rasulullah shallallahu 'alaihi wasallam menyatakan bahwa beliau akan mengampuni seseorang yang sanggup mendaki gunung tersebut pada malam hari. Memang, gunung yang ada di hadapan mereka itu seakan-akan sedang menantang Rasulullah shallallahu 'alaihi wasallam dan para sahabat yang hadir saat itu. Pada malam itu juga, aku berhasil mendaki gunung tersebut sebanyak dua atau tiga kali. Akhirnya kami tiba di kota Madinah. Lalu Rasulullah shallallahu 'alaihi wasallam mengutus Rabbah -pelayan beliau- untuk mengawal unta yang tengah membawa muatan yang cukup besar, lalu aku juga ikut menyertai Rabbah dengan menaiki kuda milik Thalhah. Keesokan harinya, aku mendengar informasi bahwa Abdurrahman Al Fazari hendak mencegat rombongan kami. Ternyata informasi itu benar, Abdurrahman dapat menawan unta Rasulullah shallallahu 'alaihi wasallam beserta muatannya. Bahkan kami dengar, dia berhasil membunuh orang yang mengendarai unta tersebut. Saat itu aku telah mengatakannya kepada Rabbah, 'Wahai Rabbah, ambillah kuda ini dan serahkanlah kepada Thalhah bin Ubaidullah, jangan sampai lupa, beritahukan kepada Rasulullah shallallahu 'alaihi wasallam bahwa orang-orang Musyrikin telah menawan rombongan unta yang beliau utus.' Setelah itu, aku naik ke atas bukit, sambil menghadap kota Madinah, aku berteriak dengan suara lantang, 'Wahai para penduduk! ' Sebanyak tiga kali berturut-turut. Kemudian aku turun dari atas bukit sambil terus melepaskan anak panah ke arah sasaran musuh, sementara itu untuk menghibur hati, aku bersenandung, 'Aku adalah putra Al Akwa', hari ini adalah hari kebinasaan! ' Dalam perjelanan mengejar musuh, aku bertemu seorang laki-laki dari kaum Musyrikin. Lalu aku mulai membidikkan anak panah ke arahnya. Tidak lama kemudian, aku berhasil menancapkan sebatang anak panah tepat mengenai bahunya, dari kejauhan aku katakan kepadanya, 'Rasakanlah anak panah itu, aku adalah putra Al Akwa', hari ini adalah hari kebinasaan'.\" Salamah berkata, \"Demi Allah, aku tetap terus melancarkan anak panah ke arah musuh. Tiba-tiba dari arah depan, aku melihat seorang musuh yang sedang menunggang kuda menuju ke arahku. Lalu aku bersembunyi di balik pohon yang rimbun. Begitu musuh yang menunggang kuda itu melintas, segera aku melepaskan anak panahku hingga berhasil melukainya. Tidak beberapa lama, datang lagi beberapa pasukan musuh. Namun seperti sebelumnya, aku langsung memanjat ke atas bukit. Dari atas bukit tersebut aku berupaya menahan laju mereka dengan cara melemparkan bebatuan ke arah mereka, dan ternyata cara tersebut berhasil. Mereka mundur secara teratur dan membiarkan aku terus mengejarnya. Karena merasa keberatan dengan beban yang mereka bawa, akhirnya mereka menjatuhkan sebagian besar perbekalan mereka dari unta Rasulullah shallallahu 'alaihi wasallam yang mereka ambil, agar lebih ringan dan dapat melarikan kendaraannya. Aku pun terus mengikuti laju mereka sambil melemparkan anak panah. Aku juga membuat jejak di jalan-jalan dengan bebatuan supaya dapat diketahui oleh Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya, dari apa yang telah aku lakukan terhadap musuh-musuh tersebut. Dengan berhimpit-himpitan, pasukan kaum Musyrikin berusaha turun dari bukit dengan melewati jalan sempit yang ada di bukit. Untungnya, Fulan bin Badri Al Fazari telah siap menanti di bawah untuk membantu mereka. Kemudian mereka duduk sambil beristirahat karena kelelahan, sementara aku duduk di atas bukit. Dari atas bukit, aku mendengar Al Fazari bertanya kepada teman-temannya yang baru saja turun dari bukit, 'Ada apa ini? Apa yang telah terjadi pada kalian? ' mereka menjawab, 'Kami telah mengalami kepayahan, demi Allah, tidaklah kami melalui akhir malam, melainkan kami selalu dihujani anak panah, sehingga kami membuang sebagian besar perbekalan kami.' Lalu Al Fazari memerintahkan empat orang dari mereka untuk menghadapiku, akhirnya keempat orang tersebut bergegas naik ke atas bukit untuk menghadapiku. Ketika jarak antara aku dengan mereka sudah semakin dekat, hingga memungkinkan mereka mendengar suara aku, maka aku berseru, \"Hai kalian berempat, apakah kalian mengenalku? ' mereka menjawab, 'Tidak, kami tidak mengenalmu, siapa sebenarnya kamu? ' aku menjawab, 'Aku adalah Salamah bin Al Akwa', demi dzat yang memuliakan wajah Muhammad, aku tidak akan membiarkan kalian hidup, mungkin begitu pula dengan kalian yang tidak mungkin membiarkan aku hidup.' Lalu aku mendengar salah seorang dari keempat orang tersebut menjawab seperti yang aku katakan. Belum sampai aku pindah tempat, tiba-tiba aku melihat beberapa orang sahabat Rasulullah shallallahu 'alaihi wasallam yang tengah mengendarai kuda keluar dari balik semak-semak pepohonan menuju arah tempat aku berada.\" Salamah berkata, \"Pertama kali yang aku lihat adalah Akhram Al Asadi, disusul oleh Abu Qatadah Al Anshari. Setelah itu, muncullah Miqdad bin Aswad Al Kindi.\" Salamah melanjutkan, \"Lalu aku memegang tali kekang kuda milik akhram, ternyata mereka bergegas hendak maju membantu aku, segera aku berkata, \"Wahai Akhram, hati-hatilah terhadap mereka, jangan sampai mereka melukai atau mencelakaimu, hingga datang bala bantuan dari Rasulullah shallallahu 'alaihi wasallam dan para sahabat yang lain.\" Dia menjawab, \"Wahai Salamah, jika kamu benar-benar beriman kepada Allah dan Allah dan hari Kiamat, serta kamu yakin bahwa surga dan neraka itu sesuatu yang benar, maka janganlah kamu menghalangiku untuk memperoleh syahid.\" Salamah berkata, \"Kemudian aku membiarkannya maju untuk bertempur satu lawan satu, lalu Abdurrahman maju ke hadapan menghadapi Akhram, pada awalnya dia dapat melukai kuda Abdurrahman, namun akhirnya Abdurrahman dapat menikam akhram hingga dia gugur. Abdurrahman lantas menaiki kudanya. Setelah itu, majulah Abu Qatadah -prajurit penunggang kuda Rasulullah shallallahu 'alaihi wasallam- menghadapi Abdurrahman. Lalu Abu Qatadah dapat menikam Abdurrahman dan membunuhnya, demi dzat yang memuliakan wajah Muhammad shallallahu 'alaihi wasallam, aku terus membuntuti mereka dengan berjalan kaki hingga tak kulihat satupun sahabat Muhammad shallallahu 'alaihi wasallam dan tidak juga debunya. Menjelang matahari terbenam, mereka menuju ke jalan di bukit yang terdapat mata airnya bernama Dzu Qard, untuk mereka minum karena kehausan.\" Salamah berkata, \"Kemudian mereka melihatku berlari membuntuti mereka, kuhalangi mereka dari telaga itu sehingga mereka tak bisa meneguk setetes air.\" Salamah berkata, \"Lantas mereka meninggalkan tempat tersebut dengan bersusah payah menyusuri lereng-lereng bukit.\" Salamah melanjutkan, \"Lalu aku berlari dan menjumpai seseorang dari mereka, lantas kutusuk dengan anak panah tepat mengenai ujung tulang bahu.\" Salamah melanjutkan, \"Lalu kukatakan dengan nada mengejek, 'Coba kau cabut anak panah yang kutusukkan, aku adalah putra Al Akwa', hari ini adalah hari kebinasaan.' Sang musuh berujar, 'Pagi yang sial, betulkah kamu Akwa'? ' Aku menjawab, 'Betul hai musuh Allah, akulah Akwa' yang pagi dini membawa kesialan bagimu.' Akwa' meneruskan, \"Musuh mencelakai dua ekor kudanya di lereng gunung. Kugiring keduanya kepada Rasulullah shallallahu 'alaihi wasallam. Amir menyusulku dengan membawa geriba kulit berkantung dua, satu berisi susu campuran, dan satunya berisi air murni. Aku berwudlu dan minum, lantas kutemui Rasulullah shallallahu 'alaihi wasallam yang beliau tengah berada di sumber air yang kuhalangi musuh meminumnya. Ternyata Rasulullah telah mengambil seluruh unta dan segala yang kuselamatkan dari pasukan musyrik, juga tombak dan kain burdah. Saat itu, Bilal telah menyembelih seekor unta dari beberapa unta yang aku selamatkan dari orang Musyrik, kemudian dia mengambil hatinya dan punuknya dan membakarnya, setelah itu ia mempersembahkannya kepada Rasulullah shallallahu 'alaihi wasallam.\" Salamah melanjutkan, 'Aku berkata, 'Wahai Rasulullah, biarkanlah aku memilih seratus orang dari pasukan musuh, kemudian aku mengikuti mereka hingga tidak ada lagi yang menginformasikan posisi kita melainkan aku tebas batang lehernya'.\" Salamah berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam tersenyum sehingga gigi geraham beliau terlihat jelas siang hari itu. Kemudian beliau bertanya: \"Wahai Salamah, apakah kamu telah siap dengan apa yang akan kamu lakukan itu?\" aku menjawab, \"Tentu, demi dzat yang telah memuliakan anda.\" Selanjutnya beliau bersabda: \"Ketahuilah wahai Salamah, sesungguhnya mereka sekarang sedang berada di wilayah kekuasaan orang-orang Ghathafan.\" Salamah berkata, \"Lalu datanglah seorang laki-laki dari Ghathafan seraya berkata, \"Si fulan telah menyembelih unta untuk mereka, ketika mereka menguliti hewan tersebut, tiba-tiba mereka melihat debu mengepul, hingga mereka lari terbirit-birit.\" Keesokan harinya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik prajurit penunggang kuda saat ini adalah Abu Qatadah, sedangkan sebaik-baik prajurit pejalan kaki adalah salamah.\" Salamah melanjutkan, \"Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan dua batang tombak kepadaku, yaitu; tombak untuk pasukan berkuda dan tombak untuk pejalan kaki, dan saat itu aku menggabungkan menjadi satu. Kemudian kami kembali ke Madinah dan aku membonceng di belakang Rasulullah shallallahu 'alaihi wasallam dengan menaiki Adzba`.\" Salamah berkata, \"Ketika kami berada di tengah jalan, -Salamah berkata- ada seorang sahabat Anshar yang mengajak kami untuk lomba lari cepat. Salamah berkata, \"Lalu sahabat Anshar itu berkata, 'Tidakkah ada orang yang mau berlomba lari menuju Madinah? ' dan ia mengulanginya sampai beberapa kali.\" Salamah melanjutkan, \"Setelah aku mendengar perkataannya, aku berkata, 'Apakah kamu hendak memuliakan orang yang mulia, ataukah hendak memperoleh wibawa di hadapan orang yang terpandang? ' dia menjawab, \"Tidak, namun untuk Rasulullah shallallahu 'alaihi wasallam.\" Salamah melanjutkan, \"Aku berkata, \"Wahai Rasulullah, demi ayah dan ibuku, biarkanlah aku melayani tantangan lomba lari laki-laki itu!\" Beliau menjawab: \"Silahkan jika kamu mau.\" Salamah berkata, \"Ayo mulai.\" Lalu aku berlari dengan kakiku, memang aku sengaja membiarkan dia hingga ia mendaki satu atau dua bukit, sebab aku khawatir akan kehabisan tenaga, kemudian aku berlari melewati jejaknya dan aku masih membiarkan dia mendaki satu atau dua bukit. Kemudian aku pacu lagi lariku sekencang-kencangnya sehingga aku dapat menjumpainya.\" Salamah berkata, \"Kemudian aku menepuk di antara pundaknya.\" Salamah melanjutkan, \"Aku berkata, 'Demi Allah, kamu telah didahului'.\" -Iyasy berkata; aku kira Salamah berkata- \"aku telah mendahuluinya ke Madinah.\" Salamah melanjutkan, \"Demi Allah, kami waktu i"},{"p":"Muslim","n":3140,"ar":"حَدَّثَنِي عَمْرُو بْنُ مُحَمَّدٍ النَّاقِدُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ ثَمَانِينَ رَجُلًا مِنْ أَهْلِ مَكَّةَ هَبَطُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ جَبَلِ التَّنْعِيمِ مُتَسَلِّحِينَ يُرِيدُونَ غِرَّةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابِهِ فَأَخَذَهُمْ سِلْمًا فَاسْتَحْيَاهُمْ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَهُوَ الَّذِي كَفَّ أَيْدِيَهُمْ عَنْكُمْ وَأَيْدِيَكُمْ عَنْهُمْ بِبَطْنِ مَكَّةَ مِنْ بَعْدِ أَنْ أَظْفَرَكُمْ عَلَيْهِمْ }","trj":"Telah menceritakan kepadaku [Amru bin Muhammad An Naqid] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas bin Malik], bahwa delapan puluh orang dari penduduk Makkah turun dari bukit Tan'im kepada Rasulullah shallallahu 'alaihi wasallam dengan persenjataan yang lengkap. Mereka hendak menyerang Nabi shallallahu 'alaihi wasallam dan para sahabatnya karena bentuk permusuhannya terhadap beliau. Namun akhirnya mereka menyerah dan beliau membiarkan mereka hidup, maka Allah Azza Wa Jalla menurunkan ayatnya: '(Dan Dialah yang menahan tangan mereka dari (membinasakan) kamu dan (menahan) tangan kamu dari (membinasakan) mereka di tengah kota Makkah sesudah Allah memenangkan kamu atas mereka) ' (Qs. Al Fath: 24)."},{"p":"Tirmidzi","n":1517,"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِفِي قَوْلِهِ تَعَالَى{ لَقَدْ رَضِيَ اللَّهُ عَنْ الْمُؤْمِنِينَ إِذْ يُبَايِعُونَكَ تَحْتَ الشَّجَرَةِ }قَالَ جَابِرٌ بَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَنْ لَا نَفِرَّ وَلَمْ نُبَايِعْهُ عَلَى الْمَوْتِقَالَ وَفِي الْبَاب عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ وَابْنِ عُمَرَ وَعُبَادَةَ وَجَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عِيسَى بْنِ يُونُسَ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ قَالَ جَابِرُ بْنُ عَبْدِ اللَّهِ وَلَمْ يُذْكَرْ فِيهِ أَبُو سَلَمَةَ","trj":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi] berkata, telah menceritakan kepada kami [Isa bin Yunus] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Jabir bin Abdullah] tentang firman Allah: '(Sesungguhnya Allah telah ridha terhadap orang-orang mu'min ketika mereka berjanji setia kepadamu di bawah pohon) ' -Qs. Al Fath: 18- Jabir berkata, \"Kami membaiat Rasulullah shallallahu 'alaihi wasallam untuk tidak lari (dari medan perang), bukan baiat untuk mati.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Salamah Ibnul Akwa', Ibnu Umar, Ubadah dan Jarir bin Abdullah.\" Abu Isa berkata, \"Hadits ini diriwayatkan dari Isa bin Yunus dari Al Auza'I, dari Yahya bin Abu Katsir berkata; Jabir bin Abdullah berkata. Dan dalam hadits tersebut tidak disebut nama Abu Salamah.\""},{"p":"Tirmidzi","n":3015,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَزَلَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لِيَغْفِرَ لَكَ اللَّهُ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ }مَرْجِعَهُ مِنْ الْحُدَيْبِيَةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ نَزَلَتْ عَلَيَّ آيَةٌ أَحَبُّ إِلَيَّ مِمَّا عَلَى الْأَرْضِ ثُمَّ قَرَأَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ فَقَالُوا هَنِيئًا مَرِيئًا يَا رَسُولَ اللَّهِ قَدْ بَيَّنَ اللَّهُ لَكَ مَاذَا يُفْعَلُ بِكَ فَمَاذَا يُفْعَلُ بِنَا فَنَزَلَتْ عَلَيْهِ{ لِيُدْخِلَ الْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ جَنَّاتٍ تَجْرِي مِنْ تَحْتِهَا الْأَنْهَارُ حَتَّى بَلَغَ فَوْزًا عَظِيمًا }قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِيهِ عَنْ مُجَمِّعِ بْنِ جَارِيَةَ","trj":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Qatadah] dari [Anas] radliallahu 'anhu berkata: Turun (ayat) kepada nabi Shallallahu 'alaihi wa Salam: \"Supaya Allah memberi ampunan kepadamu terhadap dosamu yang telah lalu dan yang akan datang.\" (Al Fath: 2) sepulangnya dari Hudaibiyah. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Telah turun ayat padaku yang lebih aku sukai daripada apa yang ada di atas bumi.\" Setelah itu nabi Shallallahu 'alaihi wa Salam membacakannya kepada mereka, mereka berkata: Bergembiralah wahai Rasulullah, Allah telah menjelaskan kepada baginda apa yang akan dilakukan terhadap baginda, lalu apa gerangan yang akan dilakukan terhadap kami? lalu turun ayat: \"Supaya dia memasukkan orang-orang mukmin laki-laki dan perempuan ke dalam surga yang mengalir di bawahnya sungai-sungai, \" sampai firmanNya: \"Keberuntungan yang besar.\" (QS. Alfath 5), Abu Isa berkata: Hadits ini hasan shahih. Dalam hal ini ada hadits serupa dari Mujamma' bin Jariyah."},{"p":"Tirmidzi","n":3114,"ar":"بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ شُعْبَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ عُمَرُ يَسْأَلُنِي مَعَ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ أَتَسْأَلُهُ وَلَنَا بَنُونَ مِثْلُهُ فَقَالَ لَهُ عُمَرُ إِنَّهُ مِنْ حَيْثُ تَعْلَمُ فَسَأَلَهُ عَنْ هَذِهِ الْآيَةِ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَقُلْتُ إِنَّمَا هُوَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ إِيَّاهُ وَقَرَأَ السُّورَةَ إِلَى آخِرِهَا فَقَالَ لَهُ عُمَرُ وَاللَّهِ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ إِلَّا أَنَّهُ قَالَ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ أَتَسْأَلُهُ وَلَنَا أَبْنَاءٌ مِثْلُهُ","trj":"Bismillahirrahmanirrahiim, telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Sulaiman bin Daud] dari [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas radliallahu 'anhuma], ia berkata; Umar bersama para sahabat Nabi shallallahu 'alaihi wasallam ia bertanya kepadaku kemudian Abdur Rahman bin 'Auf berkata; apakah engkau bertanya kepadanya, sementara kami memiliki anak-anak seperti dia? Kemudian Umar berkata kepadanya; sesungguhnya ia mempunyai kualitas tersendiri seperti yang engkau ketahui. Kemudian Umar bertanya kepadanya mengenai ayat ini: IDZAA JAA A NASHRULLAAHI WAL (Surat Al Fath) kemudian aku katakan; hal tersebut adalah ajal Rasulullah shallallahu 'alaihi wasallam yang telah Allah beritahukan kepadanya. Dan ia membaca surat tersebut hingga akhir, kemudian Umar berkata kepadanya; demi Allah tidaklah aku mengetahui dari ayat tersebut kecuali apa yang engkau ketahui. Abu Isa berkata; hadits ini adalah hadits hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dengan sanad ini seperti hadits tersebut, hanya saja ia berkata; kemudian Abdur Rahman bin 'Auf berkata kepadanya; apakah engkau bertanya kepadanya sementara kami memiliki anak-anak sepertinya? "}]};
